-- Poems batch 173
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('8eb83ed4-0a78-4bf9-b181-6c399fafb72a','句','王復','宋','宋诗','song-poetry','','[]','早秋蟬有信，多雨暑無權。',12,'全唐诗/poet.song.17000.json','["早秋蟬有信，多雨暑無權。"]'),
('17816f22-95c5-4a0d-aa69-2bced6fc423e','皇帝狩于近郊','張方平','宋','宋诗','song-poetry','','[]','講事時農隙，斿車引狩畋。',240,'全唐诗/poet.song.17000.json','["講事時農隙，斿車引狩畋。", "旌門開霽野，帳殿拂霜天。", "星斗隨華蓋，風雲逐寶鞭。", "翼開花浪急，圍合錦城圓。", "射狡無遺鏃，從奔必應弦。", "迹人輕過電，騎隊速回漩。", "鷙翮紛爭擊，材盧亦競先。", "亟來餘逸足，徑下不虛拳。", "勇氣凌金鼓，懽聲雜筦絃。", "抗緌分逆順，植表閱周旋。", "湯德逾三面，堯心豈兩豜。", "頒禽均近列，賜帛及高年。", "坐幄陳慈宴，停輿勞力田。", "鳴鐃迴綵仗，斜日下濛泉。", "寧校虞旗獲，聊供廟俎鮮。", "簡稽嚴卒乘，典制寓蹄筌。", "甫草深懷古，磻溪念得賢。", "威靈增震耀，夷虜懾腥羶。", "羽獵嘗箴漢，車攻昔美宣。", "詞臣茲紀詠，抑未愧前篇。"]'),
('499d7dfa-3b1d-490f-bc0e-590c4f892e05','大禮慶成','張方平','宋','宋诗','song-poetry','','[]','饗帝精禋舉，嚴親廣孝純。',120,'全唐诗/poet.song.17000.json','["饗帝精禋舉，嚴親廣孝純。", "禰宮增懿典，皇冊薦威神。", "寶殿齋居肅，琳房獻禮陳。", "慨瞻清廟几，穆奠紫壇茵。", "備樂嘉安曲，鴻儀顯相臣。", "玉從丹禁出，路儼繡旂新。", "瑞靄蒙天仗，祥風入帝宸。", "懽呼九州會，慶澤萬方均。", "有幸逢華旦，無謨翼至仁。", "但祈陪百禮，景扈越千春。"]'),
('91022473-13d6-4214-9205-3af54708f064','和題落筆峒  其一','許源','宋','宋诗','song-poetry','','[]','袖拂仙風上翠微，山禽窺我怪儒衣。',64,'全唐诗/poet.song.170000.json','["袖拂仙風上翠微，山禽窺我怪儒衣。", "巖編石室真奇趣，煙蓋雲幢似遠圍。", "彩筆不隨仙子去，青峰空伴野雲飛。", "我來續就承天賦，鐵笛一聲橫鶴歸。"]'),
('225ace86-2fa5-45ab-b551-efb8add5cfdd','和題落筆峒  其二','許源','宋','宋诗','song-poetry','','[]','落筆古仙峒，天開一段奇。',48,'全唐诗/poet.song.170000.json','["落筆古仙峒，天開一段奇。", "林深雲掛搭，石亂路委蛇。", "彷彿禪僧骨，糊塗墨客詩。", "何當了公事，相與問仙期。"]'),
('0714c202-ddb6-4a28-8418-ed718b7a9e81','汀州','宋思遠','宋','宋诗','song-poetry','','[]','全閩形勢數臨汀，贛嶺連疆似井陘。',32,'全唐诗/poet.song.170000.json','["全閩形勢數臨汀，贛嶺連疆似井陘。", "江匯里淵鎖地脈，山橫華蓋應天星。"]'),
('d42cc6f3-deb8-4039-a86a-2f856105edf8','定光南安巖  其一','宋思遠','宋','宋诗','song-poetry','','[]','石聳虛巖接太虛，百千年稱定光居。',64,'全唐诗/poet.song.170000.json','["石聳虛巖接太虛，百千年稱定光居。", "未知天上何方有，應是人間別地無。", "香風影裏迎新魄，梵唄聲中見落暉。", "自恨勞生名利役，不能來此共忘機。"]'),
('196b8f69-fe74-44b5-8579-a39a1ddc57a7','定光南安巖  其二','宋思遠','宋','宋诗','song-poetry','','[]','路入雲山幾萬層，豁然巖宇勢崢嶸。',32,'全唐诗/poet.song.170000.json','["路入雲山幾萬層，豁然巖宇勢崢嶸。", "地從物外囂塵斷，天到壺中日月長。"]'),
('de66c839-e74b-49c5-a1c6-4a37eac893c9','自題','胡綰','宋','宋诗','song-poetry','','[]','我爲平易政不苛，無復遣人奪農作。',32,'全唐诗/poet.song.170000.json','["我爲平易政不苛，無復遣人奪農作。", "看汝鼓腹樂太平，老瓦盆中盛酒酪。"]'),
('1dfb59c1-a70d-41e5-b938-8f1420a897b9','句','胡綰','宋','宋诗','song-poetry','','[]','楚王臺榭荆榛裏，屈指江山俎豆中。',16,'全唐诗/poet.song.170000.json','["楚王臺榭荆榛裏，屈指江山俎豆中。"]'),
('407f7400-eb1b-475f-b888-4bfd7f576831','咏郢州','劉三戒','宋','宋诗','song-poetry','','[]','百年宋玉石，三里莫愁鄉。',24,'全唐诗/poet.song.170000.json','["百年宋玉石，三里莫愁鄉。", "地接荆門近，煙迷漢水長。"]'),
('e01f02d6-805d-45a6-bd95-214ab85b5901','北樓','黄奕','宋','宋诗','song-poetry','','[]','百尺危樓四遠明，人從鰲背戲滄溟。',32,'全唐诗/poet.song.170000.json','["百尺危樓四遠明，人從鰲背戲滄溟。", "乾坤到處皆在目，山海何人更作經。"]'),
('8d15e027-010e-48c6-b8d5-f8a80ee5778f','贈桂琴隠先生','傅子雲','宋','宋诗','song-poetry','','[]','五載飛鷹迅，孤蹤病馬羈。',48,'全唐诗/poet.song.170000.json','["五載飛鷹迅，孤蹤病馬羈。", "望東嘗把酒，傾蓋便論詩。", "玉在山俱潤，泉寒練正垂。", "二雛方刷翼，行矣陟天池。"]'),
('7926bd53-3be4-4894-8c18-e9119334156e','山居歲暮','任璡','宋','宋诗','song-poetry','','[]','讀罷羲文先後天，蕭然一室裊寒煙。',32,'全唐诗/poet.song.170000.json','["讀罷羲文先後天，蕭然一室裊寒煙。", "山中歲月那知得，但見梅花又一年。"]'),
('214507a7-f5af-4955-a9f0-52aac4ebfa11','題洪陽洞石上','謝牧','宋','宋诗','song-poetry','','[]','特特携筇探洞房，中藏精氣凜寒芒。',32,'全唐诗/poet.song.170000.json','["特特携筇探洞房，中藏精氣凜寒芒。", "神仙久視知難學，乞取逍遥物外方。"]'),
('e0b8b9a4-393e-4999-abef-9fbb276a480b','沙岡','趙方','宋','宋诗','song-poetry','','[]','問予何酷愛沙岡，奇秀山光接水光。',32,'全唐诗/poet.song.170000.json','["問予何酷愛沙岡，奇秀山光接水光。", "槐樹綠陰剛似蓋，天風吹動蟄龍翔。"]'),
('6c1b6b09-59db-4658-bdf6-6591dca6c9eb','嶽亭','趙方','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南嶽高峰七十二，祝融峰直老人星。',32,'全唐诗/poet.song.170000.json','["南嶽高峰七十二，祝融峰直老人星。", "平生最有看山興，一上斯亭雙眼青。"]'),
('22637d0b-4beb-486b-aaa1-8a3e710b6a85','月池','趙方','宋','宋诗','song-poetry','','[]','道人院外一池橫，源水流來靜且清。',32,'全唐诗/poet.song.170000.json','["道人院外一池橫，源水流來靜且清。", "明月自能夜夜到，鏡光上下鑑虛盈。"]'),
('9cf12f34-cfd0-40e7-9606-e0a5b9238724','荷沼','趙方','宋','宋诗','song-poetry','','[]','露珠顆顆盪青荷，雲錦重重鋪碧波。',32,'全唐诗/poet.song.170000.json','["露珠顆顆盪青荷，雲錦重重鋪碧波。", "外直中通心獨苦，擬諸君子待如何。"]'),
('88a78242-a58f-4e84-abd1-71c603cf5381','水閣','趙方','宋','宋诗','song-poetry','','[]','四圍綠水繞重重，孤閣高撐渺渺中。',32,'全唐诗/poet.song.170000.json','["四圍綠水繞重重，孤閣高撐渺渺中。", "人在閣中憂思遠，應隨水到海涯東。"]'),
('718ac5dc-6d3e-4e4b-ba2c-382d4e1f215b','溪魚','趙方','宋','宋诗','song-poetry','','[]','溪流渺渺浄漣漪，魚躍魚潛樂自知。',32,'全唐诗/poet.song.170000.json','["溪流渺渺浄漣漪，魚躍魚潛樂自知。", "若逐桃花浪裏去，風雷相送入天池。"]'),
('555befc5-ae48-4c90-85c9-574687af1c11','龍潭','趙方','宋','宋诗','song-poetry','','[]','靜深空洞碧沉沉，鑑影分明照我心。',32,'全唐诗/poet.song.170000.json','["靜深空洞碧沉沉，鑑影分明照我心。", "照我心於何處是，潛龍時見普甘霖。"]'),
('6a37977b-675d-4790-959e-4bb47a9e6af0','石泉','趙方','宋','宋诗','song-poetry','','[]','石上泉流泉上石，泉之寒冽石堅貞。',32,'全唐诗/poet.song.170000.json','["石上泉流泉上石，泉之寒冽石堅貞。", "補天到海何須論，且慰往來行路人。"]'),
('fd8109b0-3b56-402f-9cd7-a1eeb691bf8d','幽谷','趙方','宋','宋诗','song-poetry','','[]','靜虛空闊深盤旋，松挂薜蘿籠紫烟。',32,'全唐诗/poet.song.170000.json','["靜虛空闊深盤旋，松挂薜蘿籠紫烟。", "嘗引我來尋詩料，和殘皎皎白駒篇。"]'),
('c70cd752-807e-4dff-860d-2cbfe2d4b0cd','東岑','趙方','宋','宋诗','song-poetry','','[]','讀書茅屋白雲岑，日月如流老欲侵。',32,'全唐诗/poet.song.170000.json','["讀書茅屋白雲岑，日月如流老欲侵。", "岑傍松杉栽萬樹，於茲十載已成林。"]'),
('200f1cc8-86e9-41a0-852e-d6ac5d027cbc','青衣泉','諸葛鑑','宋','宋诗','song-poetry','','[]','地脈流香出翠微，不關傳說是耶非。',64,'全唐诗/poet.song.170000.json','["地脈流香出翠微，不關傳說是耶非。", "寒風隠隠鳴松澗，急溜潺潺瀉石磯。", "此日無鸞飛碧落，當年有女著青衣。", "閑將陸羽茶經較，只載中泠一甕歸。"]'),
('815a55d8-27b0-4f7a-baec-dc4802523e2d','送翁誠之','徐照','宋','宋诗','song-poetry','','[]','又作巴陵縣，南州舊有聲。',48,'全唐诗/poet.song.170000.json','["又作巴陵縣，南州舊有聲。", "未憑湘水綠，能似長官清。", "笛冷君山月，帆輕夏浦晴。", "五言多好句，顔杜減詩名。"]'),
('a65e87eb-3f80-4277-9517-562e71907902','送徐璣','徐照','宋','宋诗','song-poetry','','[]','一舸寒江上，梅花共別離。',48,'全唐诗/poet.song.170000.json','["一舸寒江上，梅花共別離。", "不來相送處，愁有獨歸時。", "去夢千峰遠，爲官三歲期。", "思君難可見，新集見君詩。"]'),
('dbc27a22-4789-4873-be1f-af6fc452a533','舟中','徐照','宋','宋诗','song-poetry','','[]','秋氣清如水，推篷夜不眠。',48,'全唐诗/poet.song.170000.json','["秋氣清如水，推篷夜不眠。", "蘆花新有鴈，莎葉尚鳴蟬。", "心向征途老，詩憑物景全。", "漁童看月上，吹笛柁樓前。"]'),
('ba921295-fe5c-4381-b479-56189847685f','送陳郎中知嚴州','徐照','宋','宋诗','song-poetry','','[]','去作嚴光郡，前爲列宿官。',48,'全唐诗/poet.song.170000.json','["去作嚴光郡，前爲列宿官。", "水程趨闕近，豐歲得民安。", "公暇行隨鶴，宵寒卧聽灘。", "千峰臨舊榭，曾約野人看。"]'),
('ee2c57f3-a8e9-467e-a06d-7d64acbfd1c6','宿翁靈舒幽居期趙紫芝不至','徐照','宋','宋诗','song-poetry','','[]','江城過一雨，秋氣入宵濃。',48,'全唐诗/poet.song.170000.json','["江城過一雨，秋氣入宵濃。", "蛩響移砧石，螢光出瓦松。", "月遲將近曉，角盡即聞鍾。", "又起行庭際，思君恨幾重。"]'),
('3965935d-4d67-40a8-b3df-960b512da2c9','贈江心寺欽上人','徐照','宋','宋诗','song-poetry','','[]','客至啟幽戶，筍鞋行曲廊。',48,'全唐诗/poet.song.170000.json','["客至啟幽戶，筍鞋行曲廊。", "潮侵坐禪石，雨潤讀經香。", "古硯傳人遠，新篁過塔長。", "城中如火熱，此地獨清凉。"]'),
('7171a67f-24b1-48b3-a397-9c2af909a247','白下','徐照','宋','宋诗','song-poetry','','[]','白下嚴州近，崎嶇昔未經。',48,'全唐诗/poet.song.170000.json','["白下嚴州近，崎嶇昔未經。", "年豐山米賤，溪涸石苔腥。", "一月無新句，千岑役瘦形。", "人家今畏虎，未晚戶先扃。"]'),
('7089c986-923e-4afb-a1b4-8cc0cad89781','贈劉明遠','徐照','宋','宋诗','song-poetry','','[]','一生嫌世俗，不向市中居。',48,'全唐诗/poet.song.170000.json','["一生嫌世俗，不向市中居。", "既是未攀桂，却堪同釣魚。", "疾除禪老藥，詩答野人書。", "又說成丹鼎，吾生媿不如。"]'),
('f758a3c1-065c-45e9-ac73-898927427a7b','送塵老入廣化米開田','徐照','宋','宋诗','song-poetry','','[]','行李衝冰雪，途程半是船。',48,'全唐诗/poet.song.170000.json','["行李衝冰雪，途程半是船。", "去從人乞米，歸要海成田。", "遇景因開畫，思茶自掬泉。", "好風名舶趠，相候立江邊。"]'),
('a849b604-b1a5-4bc0-a63d-8c1ba58415e6','送朱嚴伯','徐照','宋','宋诗','song-poetry','','[]','好別無愁思，風霜一歲殘。',48,'全唐诗/poet.song.170000.json','["好別無愁思，風霜一歲殘。", "去因貧事迫，歸有暮年安。", "遠水維舟晚，青山遶舍寒。", "又誰憐靜者，得句不同看。"]'),
('b77566a1-5ebb-4048-a03c-c406a3b41365','寄趙紫芝','徐照','宋','宋诗','song-poetry','','[]','頻年遊闕下，近日喜言歸。',48,'全唐诗/poet.song.170000.json','["頻年遊闕下，近日喜言歸。", "及我成行役，與君還別離。", "夢長忘路遠，計拙任人非。", "楊柳塘何處，要看題壁詩。"]'),
('e70c7d9f-5a86-4970-8e4d-e8faebbbb212','途中','徐照','宋','宋诗','song-poetry','','[]','隻影微陽外，青山自鬰盤。',48,'全唐诗/poet.song.170000.json','["隻影微陽外，青山自鬰盤。", "未經千里遠，欲寄一書難。", "堠碣苔侵字，魚塘水過欄。", "西風吹樹葉，不問客衣單。"]'),
('8c726c91-5730-49ce-8982-be89387288c6','寄翁靈舒','徐照','宋','宋诗','song-poetry','','[]','游遠令人瘦，思君甚渴饑。',48,'全唐诗/poet.song.170000.json','["游遠令人瘦，思君甚渴饑。", "恨無如意事，懶乞送行詩。", "帝陌喧車馬，王門守鹿貔。", "何時借僧榻，切勿負幽期。"]'),
('35aed9ff-5c93-41d7-9f36-429ce83b7f68','贈潘德久','徐照','宋','宋诗','song-poetry','','[]','住近容成洞，歸來髮未霜。',48,'全唐诗/poet.song.170000.json','["住近容成洞，歸來髮未霜。", "出騎隨駕馬，晴曬入朝裳。", "收帖重開畫，煎茶即當觴。", "詩書難得力，戎力重清漳。"]'),
('1ebf0aae-67da-4ba3-afb9-6504e2526894','還舊山作','徐照','宋','宋诗','song-poetry','','[]','雲駁天初霽，携兒下短篷。',48,'全唐诗/poet.song.170000.json','["雲駁天初霽，携兒下短篷。", "數莖歸髮白，一袖俗塵空。", "日子差潮候，秋容在蓼叢。", "江神應念我，平穩不生風。"]'),
('54479e8a-79d6-4767-aa37-eecb1b38f551','山中','徐照','宋','宋诗','song-poetry','','[]','世事已無營，翛然物外形。',48,'全唐诗/poet.song.170000.json','["世事已無營，翛然物外形。", "野蔬僧飯潔，山葛道衣輕。", "掃葉燒茶鼎，標題記藥瓶。", "敲門舊賓客，稚子會相迎。"]'),
('8056b3d7-8202-42ed-9f4b-e190b25a8c7f','宿寺','徐照','宋','宋诗','song-poetry','','[]','古殿清燈冷，虛堂葉掃風。',48,'全唐诗/poet.song.170000.json','["古殿清燈冷，虛堂葉掃風。", "掩關人迹外，得句佛香中。", "鶴睡應無夢，僧談必悟空。", "坐驚窗欲曉，片月在林東。"]'),
('dbaa9bae-3ea7-4000-9c6e-466605d1836c','題釣臺','徐照','宋','宋诗','song-poetry','','[]','當時廊廟去，此地也成空。',48,'全唐诗/poet.song.170000.json','["當時廊廟去，此地也成空。", "草木多年換，兒孫近代窮。", "無言傷末俗，久立慕高風。", "梅福神僊者，新知是婦翁。"]'),
('61ea8c12-a89b-4d65-af9b-8897eb2f413a','題真娘墓','徐照','宋','宋诗','song-poetry','','[]','骨成泉下土，何物是遊魂。',48,'全唐诗/poet.song.170000.json','["骨成泉下土，何物是遊魂。", "一代顔容盡，千年名姓存。", "善緣依佛地，巧詠任人言。", "幾聽錢塘曲，風松靜似喧。"]'),
('4b8023d9-f49b-4c24-b509-94b01a05ec7e','題江心寺','徐照','宋','宋诗','song-poetry','','[]','兩寺今爲一，僧多外國人。',48,'全唐诗/poet.song.170000.json','["兩寺今爲一，僧多外國人。", "流來天際水，截斷世間塵。", "鴉宿腥林徑，龍歸損塔輪。", "却疑成片石，曾坐謝公身。"]'),
('119fa108-d40d-4f4f-94f2-02b11457a285','題羅隠故居','徐照','宋','宋诗','song-poetry','','[]','片水靜無塵，青山是四鄰。',48,'全唐诗/poet.song.170000.json','["片水靜無塵，青山是四鄰。", "上天如有意，此地著詩人。", "吟得物俱盡，罰令生世貧。", "因來尋古跡，只見石爲麟。"]'),
('ec2bce67-5190-4a20-89b4-aa0dbba61bf0','題陶貞白故居','徐照','宋','宋诗','song-poetry','','[]','徵君上天後，有屋在松根。',48,'全唐诗/poet.song.170000.json','["徵君上天後，有屋在松根。", "一片仙壇石，却當僧寺門。", "居山稱宰相，隔代絕兒孫。", "太傅新爲記，今來亦不存。"]'),
('0cc77e7c-5336-46b5-8295-e34ee3bf2d8f','題桃花夫人廟','徐照','宋','宋诗','song-poetry','','[]','一樹桃花發，桃花即是君。',48,'全唐诗/poet.song.170000.json','["一樹桃花發，桃花即是君。", "空祠臨野水，何處覓行雲。", "事迹樵人說，爐香過客焚。", "雨添碑上蘚，難讀古時文。"]'),
('d4326a5c-11a3-4d18-92b7-3f734452cfd1','謝徐璣惠茶','徐照','宋','宋诗','song-poetry','','[]','建山惟上貢，采擷極艱辛。',48,'全唐诗/poet.song.170000.json','["建山惟上貢，采擷極艱辛。", "不擬分奇品，遥將寄野人。", "角開秋月滿，香入井泉新。", "靜室無來客，碑黏陸羽真。"]'),
('c6c649d4-b537-472b-b85b-a5445615796b','愁','徐照','宋','宋诗','song-poetry','','[]','愁與詩相似，能令鬚髮新。',48,'全唐诗/poet.song.170000.json','["愁與詩相似，能令鬚髮新。", "意清塵不沒，道直事多屯。", "水石惟宜夏，田桑獨致貧。", "不除閑懶性，前世必僧身。"]'),
('c6f51f4b-87a7-46f6-a0f2-ac64f3da08eb','送李偉歸黄山','徐照','宋','宋诗','song-poetry','','[]','心和無白髮，長带一琴行。',48,'全唐诗/poet.song.170000.json','["心和無白髮，長带一琴行。", "幾路到君屋，數峰當郡城。", "妻兒貧自樂，丹藥歲燒成。", "未必聖明代，終令隠姓名。"]'),
('a2b0879d-c7d8-4dec-ace7-49946746b260','懷如順上人','徐照','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖湖上寺，一別二三年。',48,'全唐诗/poet.song.170000.json','["西湖湖上寺，一別二三年。", "舊住房長閉，新栽樹已圓。", "空多相憶夢，不得寄來篇。", "喜見鄰僧說，歸期是臘前。"]'),
('1de69043-eaa8-47fc-8bbc-c8c8a5bc9fbe','答徐璣','徐照','宋','宋诗','song-poetry','','[]','君有新詩題我石，我因吟賞每登亭。',64,'全唐诗/poet.song.170000.json','["君有新詩題我石，我因吟賞每登亭。", "塞門鴈到雲邊失，海口山來樹裏青。", "幾度寄書親入郭，有誰載酒更過汀。", "欲知生事全無長，買紙閑傳相鶴經。"]'),
('3eea2dee-cd93-4c9f-bfe5-d2bd182c14ca','題鮑史君林園','徐照','宋','宋诗','song-poetry','','[]','水波一带隔秋城，不許塵埃接地生。',64,'全唐诗/poet.song.170000.json','["水波一带隔秋城，不許塵埃接地生。", "濃露漸成紅蓼色，野風添作小松聲。", "客來喜自開樓鎖，病去逢人語藥名。", "閑意却多官意懶，旁人傳說似淵明。"]'),
('bfdaeec4-338f-441d-b7ab-bfd2a717ca4a','酬翁常之','徐照','宋','宋诗','song-poetry','','[]','半掩柴門一徑深，山中免見俗塵侵。',64,'全唐诗/poet.song.170000.json','["半掩柴門一徑深，山中免見俗塵侵。", "愁因有酒春生面，老不饒貧雪滿簪。", "舊井遠通幽谷水，翠藤新長小窗陰。", "扁舟莫負林間約，好把清詩慰此心。"]'),
('34914241-f3f2-4972-aa4a-e3724d08e768','贈從善上人','徐照','宋','宋诗','song-poetry','','[]','骨氣清泠無片塵，即應僧可是前身。',64,'全唐诗/poet.song.170000.json','["骨氣清泠無片塵，即應僧可是前身。", "詩因緣解堪呈佛，棋與禪通可悟人。", "掃地就涼松日少，煮茶消困石泉新。", "不能來住城中寺，去買青山約我鄰。"]'),
('bfa4656e-25c5-4e75-88d6-53f606bef2b0','訪趙紫芝','徐照','宋','宋诗','song-poetry','','[]','意欲尋君忘路遠，入城還又出城來。',64,'全唐诗/poet.song.170000.json','["意欲尋君忘路遠，入城還又出城來。", "菊明紫色天霜下，魚沒圓痕水垢開。", "新背古碑藏素篋，凍研山硯滴香醅。", "竹林好著君名姓，只恐君爲祿仕催。"]'),
('49d79441-6f10-4582-87e0-50ca109e7565','山中寄翁卷','徐照','宋','宋诗','song-poetry','','[]','忽看春至復春還，門外煙雲沒野間。',64,'全唐诗/poet.song.170000.json','["忽看春至復春還，門外煙雲沒野間。", "吟有好懷忘瘦苦，貧多難事壞清閑。", "柳花未散色全綠，杜宇乍啼聲更蠻。", "聞道掃松溪雨後，夢隨溪雨到巖關。"]'),
('94d3fa18-82e6-4e4b-a9e8-c82bcd2135a9','送塵老歸舊房','徐照','宋','宋诗','song-poetry','','[]','數間茅屋殘山外，片石崚嶒樹影交。',64,'全唐诗/poet.song.170000.json','["數間茅屋殘山外，片石崚嶒樹影交。", "給假兩旬秋易盡，相尋一舍地非遥。", "盆栽怪木緣能畫，池養嘉魚不入庖。", "聞道水松三百步，夢隨流水到溪橋。"]'),
('a0a43eca-e8ec-4fcf-9c42-b1bb27619ed5','猿皮','徐照','宋','宋诗','song-poetry','','[]','路逢巴客買猿皮，一片蒙茸似黑絲。',64,'全唐诗/poet.song.170000.json','["路逢巴客買猿皮，一片蒙茸似黑絲。", "常向小窗鋪坐處，却思空谷聽啼時。", "弩傷忍見痕猶在，笛響誰誇骨可吹。", "古樹團團行路曲，無人來作野賓詩。"]'),
('0081914d-7c63-4fe5-9877-82474ba31c3e','會飲鮑史君池臺','徐照','宋','宋诗','song-poetry','','[]','案上一琴書數卷，不須此地有笙歌。',64,'全唐诗/poet.song.170000.json','["案上一琴書數卷，不須此地有笙歌。", "厭居市井觀天小，喜到君家見月多。", "葉滿地飛隨步履，鶴於人熟聽吟哦。", "明朝也向山中去，手把松枝養太和。"]'),
('772fddfe-dff7-4b64-bb13-23aa9125b784','宿翁卷書齋','徐照','宋','宋诗','song-poetry','','[]','一山秋色同誰看，又復相尋出郭來。',64,'全唐诗/poet.song.170000.json','["一山秋色同誰看，又復相尋出郭來。", "鄰竹種成高礙月，井泉汲少近生苔。", "忽驚寒事砧初動，不辨晨光戶盡開。", "君愛苦吟吾喜聽，世人誰更重清才。"]'),
('10a8703f-3251-4f20-b8e2-336b0881da3d','漁者','徐照','宋','宋诗','song-poetry','','[]','瑟瑟風吹鬢髮飛，自將莎草補蓑衣。',32,'全唐诗/poet.song.170000.json','["瑟瑟風吹鬢髮飛，自將莎草補蓑衣。", "小船撐入蘆花去，家在溪邊多不歸。"]'),
('0809577d-44f9-4dfe-b4b9-b0faf8703976','觀所養鸂鶒','徐照','宋','宋诗','song-poetry','','[]','一身文采異常流，却使閑身不自由。',32,'全唐诗/poet.song.170000.json','["一身文采異常流，却使閑身不自由。", "永日翠籠相並睡，豈無魂夢到滄洲。"]'),
('1d1324f1-343c-4afc-a306-87ca8db06aea','柳下聞蟬','徐照','宋','宋诗','song-poetry','','[]','晚涼多處聽蟬聲，齊女當年變化成。',32,'全唐诗/poet.song.170000.json','["晚涼多處聽蟬聲，齊女當年變化成。", "不合著身楊柳上，也令千古動離情。"]'),
('77a8c929-5a84-4713-88a8-1193d468db1e','題趙運管吟篷','徐照','宋','宋诗','song-poetry','','[]','飛塵難到碧波中，波上煙雲盡不同。',32,'全唐诗/poet.song.170000.json','["飛塵難到碧波中，波上煙雲盡不同。", "吟斷不知驚鷺起，汀花一半在船篷。"]'),
('31e9c574-0554-45b8-a6c7-d09b2ead01d6','和翁常之','徐照','宋','宋诗','song-poetry','','[]','八尺蘄州桃竹簟，坐來疑是水侵裳。',32,'全唐诗/poet.song.170000.json','["八尺蘄州桃竹簟，坐來疑是水侵裳。", "垂楊葉下閑吟久，又與鳴蟬共晚凉。"]'),
('b935b1d3-b9c7-405f-b61e-aaad13a56f99','桃花嶺','徐照','宋','宋诗','song-poetry','','[]','諸嶺桃花嶺最高，冰枯泉脈草身高。',32,'全唐诗/poet.song.170000.json','["諸嶺桃花嶺最高，冰枯泉脈草身高。", "四山相並疑無日，若是南山雪不消。"]'),
('09bea80d-018a-4fb8-9f85-2a34b7d0722a','舟上','徐照','宋','宋诗','song-poetry','','[]','小船停槳逐潮還，四五人家住一灣。',32,'全唐诗/poet.song.170000.json','["小船停槳逐潮還，四五人家住一灣。", "貪看曉光侵月色，不知雲氣失前山。"]'),
('1895ad46-89ea-4036-ad30-0fdacbda5fd5','訪觀公不遇','徐照','宋','宋诗','song-poetry','','[]','卧犬聞人出，門當青櫟林。',48,'全唐诗/poet.song.170000.json','["卧犬聞人出，門當青櫟林。", "固知多不在，自欲遠相尋。", "宵短餘香印，林疎出磬音。", "昨來曾寄茗，應念苦吟心。"]'),
('7a93858b-5253-4ca0-b8b7-ae3b818d8792','中夕','徐照','宋','宋诗','song-poetry','','[]','中夕獨依依，閑行未掩扉。',48,'全唐诗/poet.song.170000.json','["中夕獨依依，閑行未掩扉。", "水邊山出月，松上雨沾衣。", "棹響初如近，螢光漸欲稀。", "不甘塵內事，長與此心違。"]'),
('095d4ee6-8b38-4e03-bac9-c6be9db123a9','會宿趙紫芝宅','徐照','宋','宋诗','song-poetry','','[]','殘燭照屏風，高堂暑氣空。',48,'全唐诗/poet.song.170000.json','["殘燭照屏風，高堂暑氣空。", "初旬長少月，半夜忽來鴻。", "舊集三年久，清吟四坐同。", "城樓殺更點，聲在雨聲中。"]'),
('40138f58-1336-442b-9cd4-2b41c6049873','題丁少瞻林園','徐照','宋','宋诗','song-poetry','','[]','州分低嶺外，來向此園行。',48,'全唐诗/poet.song.170000.json','["州分低嶺外，來向此園行。", "路改初栽樹，堂成未有名。", "藥苗如草長，巖溜入池清。", "欲識懷君意，時聞鶴一鳴。"]'),
('cb6782a7-9d0d-4ddb-b949-a2236b23c2cc','哭居塵禪師','徐照','宋','宋诗','song-poetry','','[]','今朝聞實信，一隻海船遥。',48,'全唐诗/poet.song.170000.json','["今朝聞實信，一隻海船遥。", "此世永相隔，何僧可與交。", "茶從秋後盡，門絕月中敲。", "昨夜山家夢，親曾到石橋。"]'),
('848a4bde-3401-4d72-8e60-127d478ff852','露','徐照','宋','宋诗','song-poetry','','[]','立久衣襟潤，空中氣結成。',48,'全唐诗/poet.song.170000.json','["立久衣襟潤，空中氣結成。", "光凝蘭葉膩，冷逼鶴陰清。", "又覺爲霜近，猶能向日明。", "惟知漢宮內，千尺有金莖。"]'),
('555ebfc3-b10a-41f5-926d-e5dca5e309d8','菊','徐照','宋','宋诗','song-poetry','','[]','氣受一歲足，千花極後芳。',48,'全唐诗/poet.song.170000.json','["氣受一歲足，千花極後芳。", "蕊浮茶鼎沸，色染道衣黄。", "天上虛星落，人間壽水香。", "鄧州兵革外，流種遍江鄉。"]'),
('d0604479-75a0-495d-a28c-ba8742ace78c','衰柳','徐照','宋','宋诗','song-poetry','','[]','風吹無一葉，不復翠成窠。',48,'全唐诗/poet.song.170000.json','["風吹無一葉，不復翠成窠。", "枝脆經霜氣，根空入水波。", "寒栖江鷺早，暗出野螢多。", "廢苑荒堤外，人嗟舊迹過。"]'),
('8953ff41-9bee-407d-ba3b-88180ab53d01','子規','徐照','宋','宋诗','song-poetry','','[]','羽類是遊魂，哀多屬曙昏。',48,'全唐诗/poet.song.170000.json','["羽類是遊魂，哀多屬曙昏。", "一時亡國恨，千古向人言。", "山竹已應裂，野花猶更繁。", "昔曾令杜甫，再拜憶君尊。"]'),
('fdda9f56-afad-4cda-99a2-ec4baed43dfb','鷺鷥','徐照','宋','宋诗','song-poetry','','[]','一點白如雪，頂黏絲數莖。',48,'全唐诗/poet.song.170000.json','["一點白如雪，頂黏絲數莖。", "沙邊行有跡，空外過無聲。", "高柳巢方穩，危灘立不驚。", "每看閑意思，漁父是前生。"]'),
('f8a95539-e4c0-491e-a477-43659a66115c','陳保之訪宿','徐照','宋','宋诗','song-poetry','','[]','不作王侯客，一身如散僊。',48,'全唐诗/poet.song.170000.json','["不作王侯客，一身如散僊。", "少聞人世事，多欠酒家錢。", "省語初如傲，高文舊已傳。", "去燈燒蠟炬，相對坐茫然。"]'),
('7e940e92-fa18-4538-971c-8e262ddabf4a','白巖僧舍','徐照','宋','宋诗','song-poetry','','[]','佳景多爲寺，一房當翠微。',48,'全唐诗/poet.song.170000.json','["佳景多爲寺，一房當翠微。", "爐香穿野靄，杉露滴僧衣。", "割蜜蜂喧牖，拋生鳥候扉。", "山深隨興味，斜日不須歸。"]'),
('8a35d528-4da7-4363-a07e-0917a5465b4a','登歙山寺','徐照','宋','宋诗','song-poetry','','[]','石徑半欹傾，山頭路始平。',48,'全唐诗/poet.song.170000.json','["石徑半欹傾，山頭路始平。", "步因花樹息，吟忘寺僧迎。", "一面門無水，東隅路入京。", "青峰三十六，霜曉見分明。"]'),
('16096fa6-819b-487e-b568-7dcb1f7a98ef','和潘德久喜徐文淵趙紫芝還里','徐照','宋','宋诗','song-poetry','','[]','故交南北去，誰復念幽人。',48,'全唐诗/poet.song.170000.json','["故交南北去，誰復念幽人。", "夕別驚初見，相知樂似新。", "竹聲當暑浄，茶味得泉珍。", "貧與詩相涉，詩清不怨貧。"]'),
('5e127c75-c10d-4b24-ac9c-69d0825fb480','塔山作','徐照','宋','宋诗','song-poetry','','[]','東岸沙新淤，西村半失田。',48,'全唐诗/poet.song.170000.json','["東岸沙新淤，西村半失田。", "夕陽明望外，寒鴈落愁邊。", "懶下遮風帽，誰添買酒錢。", "小坡人不渡，燈火壓潮船。"]'),
('b4091c28-863e-419e-906a-756275c6397e','挽王大夫','徐照','宋','宋诗','song-poetry','','[]','兩任身爲郡，里中如不知。',48,'全唐诗/poet.song.170000.json','["兩任身爲郡，里中如不知。", "民歸清浄化，家似困窮時。", "秦木淒秋韻，湘雲結暮姿。", "若無遺愛在，何得後人思。"]'),
('920006ef-acea-43cb-8af1-b10a545150f9','劉明遠會宿翁靈舒西齋','徐照','宋','宋诗','song-poetry','','[]','秋色侵肌骨，還將鬢色侵。',48,'全唐诗/poet.song.170000.json','["秋色侵肌骨，還將鬢色侵。", "自來難會宿，安得廢清吟。", "竹露滋叢菊，鄰鍾覺曙禽。", "城中同此月，不起故山心。"]'),
('f6d9e1bb-5f50-4ef5-9e2e-2360e2319636','歸來','徐照','宋','宋诗','song-poetry','','[]','歸來長獨坐，誰更伴吾行。',48,'全唐诗/poet.song.170000.json','["歸來長獨坐，誰更伴吾行。", "不念爲生拙，偏思得句清。", "園晴秋菜少，井涸夜泉生。", "愛聽燈前雨，松聲相雜鳴。"]'),
('b788e322-59dc-467a-933d-678b3aec5c15','贈溪上翁','徐照','宋','宋诗','song-poetry','','[]','生事付諸兒，日高眠起遲。',48,'全唐诗/poet.song.170000.json','["生事付諸兒，日高眠起遲。", "本無塵內事，亦有鬢邊絲。", "遠取泉烹茗，新移棘補籬。", "晚來持釣出，一犬自相隨。"]'),
('5834a839-3aa1-4d6d-b2e7-d4652d58612b','訪可公宿','徐照','宋','宋诗','song-poetry','','[]','枯株圍古寺，長覺莫寒增。',48,'全唐诗/poet.song.170000.json','["枯株圍古寺，長覺莫寒增。", "坐聽吹風雪，吟移照佛燈。", "試茶鐺則水，點筆硯生冰。", "門外營營者，誰人及似僧。"]'),
('2696ca4d-bc5b-49d3-a8fe-e5e309f2d9b1','贈實老','徐照','宋','宋诗','song-poetry','','[]','夏高頭半白，不肯住招提。',48,'全唐诗/poet.song.170000.json','["夏高頭半白，不肯住招提。", "汲井籬花落，掛衣巢鳥啼。", "林間曾有約，世上盡如迷。", "却把南華卷，從人論物齊。"]'),
('60812720-1690-4d51-ac53-ee968ebc85e8','漁家','徐照','宋','宋诗','song-poetry','','[]','阿翁年紀老，生計在綸絲。',48,'全唐诗/poet.song.170000.json','["阿翁年紀老，生計在綸絲。", "野水無人占，扁舟逐處移。", "數鱗新柳串，一笛小兒吹。", "有酒人家醉，公卿要識誰。"]'),
('26a1c6ae-465e-460a-bca4-0e60af4c62f0','山中即事','徐照','宋','宋诗','song-poetry','','[]','著履上崔嵬，呼兒注瓦杯。',48,'全唐诗/poet.song.170000.json','["著履上崔嵬，呼兒注瓦杯。", "千岑經雨後，一鴈带秋來。", "野艇乘潮發，山園逐主開。", "餘生落樵牧，開卷少塵埃。"]'),
('ec6a746a-c339-4565-a0f9-58539a9ac710','貧居','徐照','宋','宋诗','song-poetry','','[]','既與世不合，當令人事疎。',48,'全唐诗/poet.song.170000.json','["既與世不合，當令人事疎。", "引泉魚走石，掃徑葉平蔬。", "誰念交情淺，難如識面初。", "榮途多寵辱，未敢怨貧居。"]'),
('72e44c4d-1e2d-4489-9fb9-57204b7ccd00','訪僧居','徐照','宋','宋诗','song-poetry','','[]','客至無他事，房門不厭敲。',48,'全唐诗/poet.song.170000.json','["客至無他事，房門不厭敲。", "好山元带郭，損屋旋鋪茅。", "靜砌生靈藥，高林出遠郊。", "水禽冬不見，春暖漸營巢。"]'),
('085d3b9b-f4e3-41cd-a29c-1025fb6a9760','送翁誠之赴闕','徐照','宋','宋诗','song-poetry','','[]','我亦清湘去，何年可會君。',48,'全唐诗/poet.song.170000.json','["我亦清湘去，何年可會君。", "貧惟詩送別，愁覺酒難醺。", "郊祀隨天仗，臺占識瑞雲。", "定知分美郡，音問欲相聞。"]'),
('8e93fb4f-66bb-43fd-84ab-70848698f299','石門瀑布','徐照','宋','宋诗','song-poetry','','[]','一派從天落，曾經李白看。',48,'全唐诗/poet.song.170000.json','["一派從天落，曾經李白看。", "千年流不盡，六月地長寒。", "灑木噴微沫，衝崖激怒湍。", "人言深碧處，常有老龍蟠。"]'),
('2dbb881e-0a56-47f8-b849-df8c91ae2767','括溪和徐文淵','徐照','宋','宋诗','song-poetry','','[]','隔鄉山萬疊，前路見新年。',48,'全唐诗/poet.song.170000.json','["隔鄉山萬疊，前路見新年。", "雲霧寒疑雪，溪乾步當船。", "梅初開竹下，鴈不至沙邊。", "共向湘中去，詩將遠地傳。"]'),
('766e68da-e78c-4f99-a0d3-3bb5538f755e','溪行寄靈舒','徐照','宋','宋诗','song-poetry','','[]','灘惡過金水，波聲遠亦聞。',48,'全唐诗/poet.song.170000.json','["灘惡過金水，波聲遠亦聞。", "詩同家信發，燈向釣船分。", "數夜仍無月，看山半是雲。", "又須登岸宿，囘望却思君。"]'),
('048d3a9d-2e82-4efc-aeb3-3585890801d6','宿永康','徐照','宋','宋诗','song-poetry','','[]','路有三千里，春容若水濃。',48,'全唐诗/poet.song.170000.json','["路有三千里，春容若水濃。", "淺塘饑鷺下，晴靄市煙衝。", "孤望生遥思，頻過記昔蹤。", "宿程知近縣，聞打發燈鍾。"]'),
('8a86aae5-4cda-432a-bed7-cab7767755c2','途中寄趙紫芝','徐照','宋','宋诗','song-poetry','','[]','筠永州同路，人如異約何。',48,'全唐诗/poet.song.170000.json','["筠永州同路，人如異約何。", "雪風吟不廢，山水憶同過。", "仙去家長在，時平石可磨。", "夢知歸路遠，全覺夢君多。"]'),
('d603825e-cbf3-4f81-8ef7-ab5282282c2e','題衢州石壁寺','徐照','宋','宋诗','song-poetry','','[]','岸上橫生脈，平林一里溪。',48,'全唐诗/poet.song.170000.json','["岸上橫生脈，平林一里溪。", "衆船寒渡集，高寺遠山齊。", "殘磬吹風斷，眠禽壓竹低。", "自嫌昏黑至，難認壁間題。"]'),
('58f9b117-a656-4f27-9df8-ef315ce73858','信州水南','徐照','宋','宋诗','song-poetry','','[]','衆寺臨溪上，東西屋數間。',48,'全唐诗/poet.song.170000.json','["衆寺臨溪上，東西屋數間。", "詩傳叔倫句，真認貫休顔。", "柳過深潭碧，人隨白鳥還。", "斜陽三百里，高甚水晶山。"]'),
('70a9193e-ff46-4ba3-bf08-9180f779f8e2','題信州祥符寺','徐照','宋','宋诗','song-poetry','','[]','冰溪清絕地，誰擬此身來。',48,'全唐诗/poet.song.170000.json','["冰溪清絕地，誰擬此身來。", "寺古逢僧老，山高見水囘。", "巖菲寒未拆，風靄復難開。", "塔下看碑石，因尋跨鶴臺。"]'),
('5d28db80-df45-4718-8f5c-f93ae4b62a52','題李商叟半村壁','徐照','宋','宋诗','song-poetry','','[]','一徑蒼苔合，連年不出門。',48,'全唐诗/poet.song.170000.json','["一徑蒼苔合，連年不出門。", "風高松有韻，溪滿石無痕。", "不自知名重，令人覺道尊。", "更憂徵詔至，移室向深村。"]'),
('edc5973a-1f2b-4745-9a95-d2a4d1569d2a','題李半村曬蓑臺','徐照','宋','宋诗','song-poetry','','[]','松枝宿雨碎滴下，野鶴巢邊多水禽。',32,'全唐诗/poet.song.170000.json','["松枝宿雨碎滴下，野鶴巢邊多水禽。", "不見蓑衣臺上晒，來人自起釣魚心。"]'),
('eddb25f3-c4b2-40de-9f3d-b7aff28a8fc2','題信州趙昌甫林居','徐照','宋','宋诗','song-poetry','','[]','譜接江西派，聲名過浙間。',48,'全唐诗/poet.song.170000.json','["譜接江西派，聲名過浙間。", "棄官從早歲，買屋向深山。", "文集通僧借，漁舟載鶴還。", "待予歸舊里，又得到柴關。"]'),
('946445f6-0de1-45cf-bb4d-95cad40b484b','路逢楊嘉猷赴官嚴州','徐照','宋','宋诗','song-poetry','','[]','詩合誠齋意，難將片石鎸。',48,'全唐诗/poet.song.170000.json','["詩合誠齋意，難將片石鎸。", "相逢因在道，惜別未移船。", "野步僧同話，宵吟吏廢眠。", "思君還有夢，前到釣臺邊。"]'),
('b36fb781-af21-42a6-8578-a161122ed432','過鄱陽湖','徐照','宋','宋诗','song-poetry','','[]','港中分十字，蜀廣亦通連。',48,'全唐诗/poet.song.170000.json','["港中分十字，蜀廣亦通連。", "四望空無地，孤舟若在天。", "龍尊收巨浪，鷗少沒蒼煙。", "未渡皆驚畏，吾今已帖然。"]'),
('b079137e-5a12-4719-8a55-90ce0ca1e704','洪州城下作','徐照','宋','宋诗','song-poetry','','[]','野靄初收見遠汀，數株楊柳是官亭。',32,'全唐诗/poet.song.170000.json','["野靄初收見遠汀，數株楊柳是官亭。", "漁人向晚各歸去，一陣風來釣具腥。"]'),
('bb2f93e6-51ca-47d7-bee2-699cbbd9f445','題薌林','徐照','宋','宋诗','song-poetry','','[]','祇爲登山遠，當門疊石爲。',48,'全唐诗/poet.song.170000.json','["祇爲登山遠，當門疊石爲。", "人來嗟故跡，景勝入名詩。", "立鶴高過檻，欹花半在池。", "百年庭際木，新長挂冠枝。"]'),
('f81aadaa-346d-45b7-a9e9-d15c6ae906f9','宿吉州永慶寺','徐照','宋','宋诗','song-poetry','','[]','古邑溪邊寺，吟人愛寂寥。',48,'全唐诗/poet.song.170000.json','["古邑溪邊寺，吟人愛寂寥。", "少僧齋室廢，乞食釣鄉遥。", "鍾韻含霜氣，樓簷近斗杓。", "漢時銅鑄佛，瞻禮到今朝。"]'),
('6d477f72-806f-41f6-aca8-a1a93b5021ed','入湘二首  其一','徐照','宋','宋诗','song-poetry','','[]','入湘無濁水，天亦憫忠臣。',48,'全唐诗/poet.song.170000.json','["入湘無濁水，天亦憫忠臣。", "陰結魚龍氣，香聞蘭杜春。", "高吟方有思，靜望忽傷神。", "舟上多漁父，應無似昔人。"]'),
('0bcd4d95-4928-4f68-9f5e-96403f97d293','入湘二首  其二','徐照','宋','宋诗','song-poetry','','[]','土若丹砂顔色赤，山無高勢小成叢。',64,'全唐诗/poet.song.170000.json','["土若丹砂顔色赤，山無高勢小成叢。", "江船未慣行湘水，越客新能下楚風。", "蘭杜滿汀過綠草，鴛鴦近日別輕鴻。", "地塗先識永陵郡，曾看鄰翁畫軸中。"]'),
('577aaf50-b631-4118-9c26-f05421fe623c','湘中中秋','徐照','宋','宋诗','song-poetry','','[]','出望月輪小，不如臨海生。',48,'全唐诗/poet.song.170000.json','["出望月輪小，不如臨海生。", "又疑今夜看，難比故鄉明。", "立柏正無影，清猿偏有聲。", "數家弦管外，專此照離情。"]'),
('9e05293e-82d1-4d92-b72a-572e73567611','湘中寒夜','徐照','宋','宋诗','song-poetry','','[]','本自家於越，何期滯楚邦。',48,'全唐诗/poet.song.170000.json','["本自家於越，何期滯楚邦。", "吟多頭易白，歸切思難降。", "但聽風收竹，誰知雪滿江。", "叉魚中夜急，燒火照樓窗。"]'),
('51732f44-aadf-48e5-a32d-5d913e3ea080','題懷素臺','徐照','宋','宋诗','song-poetry','','[]','昔時懷素屋，臨郭少埃氛。',48,'全唐诗/poet.song.170000.json','["昔時懷素屋，臨郭少埃氛。", "草沒栽蕉地，雲藏瘞筆墳。", "年深碑不壞，名重世間聞。", "釵服吾能識，猶如已見君。"]'),
('5006ee9e-acea-4b03-8850-aa09d6519033','題愚溪堂','徐照','宋','宋诗','song-poetry','','[]','水流深見底，不是此溪愚。',48,'全唐诗/poet.song.170000.json','["水流深見底，不是此溪愚。", "謫宦休嗟命，鄉人爲讀書。", "文章傳海裔，屋室在州圖。", "儒者凡經此，須來看所居。"]'),
('46eaf3a6-b275-45e5-9d11-8156d9888504','題浯溪','徐照','宋','宋诗','song-poetry','','[]','知是漫郎宅，舟中聞寺鍾。',48,'全唐诗/poet.song.170000.json','["知是漫郎宅，舟中聞寺鍾。", "小溪通正港，高石疊群峰。", "綠木成春蔭，荒臺見古蹤。", "唐碑三十本，獨免野苔封。"]'),
('a17bb7bc-2ad4-42ef-a137-cbd35a6875e0','題淡巖','徐照','宋','宋诗','song-poetry','','[]','一石高千尺，惟留一面空。',48,'全唐诗/poet.song.170000.json','["一石高千尺，惟留一面空。", "寸窺橫嶂綠，圓透夕陽紅。", "僧定遺人世，猿藏畏雪風。", "却憐黄太史，不至雁山中。"]'),
('75e94cf9-817a-4a21-ad5d-90b4c8e1dc31','永州書懷','徐照','宋','宋诗','song-poetry','','[]','嗜茶疑是病，羸瘦見詩形。',48,'全唐诗/poet.song.170000.json','["嗜茶疑是病，羸瘦見詩形。", "天斷征鴻過，汀多香草青。", "興高貧不覺，身遠事皆經。", "歸路當游嶽，僧言極可聽。"]'),
('2a3cb15b-3298-448b-8542-00c6b69417c3','游瀟東和徐文淵','徐照','宋','宋诗','song-poetry','','[]','天吏今如隠，相隨步野坡。',48,'全唐诗/poet.song.170000.json','["天吏今如隠，相隨步野坡。", "山高臨古郡，天小入江波。", "香草春生遍，幽禽暮見多。", "更增游嶽思，昨有寺僧過。"]'),
('613462d9-45ff-47b1-affd-4854ae4bacbf','永州寄翁靈舒','徐照','宋','宋诗','song-poetry','','[]','古郡百蠻邊，蒼梧九點煙。',48,'全唐诗/poet.song.170000.json','["古郡百蠻邊，蒼梧九點煙。", "去家疑萬里，歸計在明年。", "風順眠聽角，樓高望見船。", "筠州當半道，長得秀詩篇。"]'),
('12758ce8-9986-4480-bee9-af9509b841df','寄劉孝若','徐照','宋','宋诗','song-poetry','','[]','難得劉夫子，生平極愛予。',48,'全唐诗/poet.song.170000.json','["難得劉夫子，生平極愛予。", "有時吟好句，特地到貧居。", "遠別寧無恨，平安莫問書。", "夢穿庭際菊，密葉過畦蔬。"]'),
('9c023c76-5d60-460d-9810-c2f5153afcbd','寄筠陽趙紫芝推官','徐照','宋','宋诗','song-poetry','','[]','府後巖巒衆，何時訪古僊。',48,'全唐诗/poet.song.170000.json','["府後巖巒衆，何時訪古僊。", "井甘鄰室共，鍾遠雪風傳。", "病去茶難廢，詩多石可鎸。", "蜀江春未動，猶得緩歸船。"]'),
('917a0661-a3fd-42cf-ae57-e11fbee399f7','同徐文淵登永州高山寺','徐照','宋','宋诗','song-poetry','','[]','畫圖舊識高山寺，今在高山寺裏行。',64,'全唐诗/poet.song.170000.json','["畫圖舊識高山寺，今在高山寺裏行。", "千古嶮峰長自直，一春瀟水未曾清。", "孤城吹角寒猿應，破屋尋碑野鼠驚。", "天遣二人來遠地，要將新景就詩名。"]'),
('a5107678-5209-431e-8f6a-46692fe2ba56','湘口','徐照','宋','宋诗','song-poetry','','[]','廟前物景非人世，獨獨來看路逕遥。',64,'全唐诗/poet.song.170000.json','["廟前物景非人世，獨獨來看路逕遥。", "船板鷺行乾有迹，菊花鹿踐曲生苗。", "合流水急聲難盡，過片雲輕色易銷。", "黄葉未成傷遠思，西風先向客衣飄。"]'),
('cb1bc42e-1f76-48cc-a707-87b9639195df','贈鄧都監','徐照','宋','宋诗','song-poetry','','[]','能吟能畫俱精到，多得聲名在世間。',64,'全唐诗/poet.song.170000.json','["能吟能畫俱精到，多得聲名在世間。", "少病高年惟髮白，爲官遠地却身閑。", "深林有寺唐碑在，古廟無人楚竹斑。", "物景可吟兼可畫，乞君篇幅未應慳。"]'),
('cfa6761a-dcc0-4a9f-acab-9d99bafa667b','高山寺晚望','徐照','宋','宋诗','song-poetry','','[]','石路近門方不險，刺桐疎處見僧歸。',64,'全唐诗/poet.song.170000.json','["石路近門方不險，刺桐疎處見僧歸。", "小坡重疊無平屋，四月陰寒尚裌衣。", "山到道州高莫比，水分湘口綠相圍。", "暮雲不隔東南望，一片遥兼白鳥飛。"]'),
('bf98b4b8-6929-4331-a076-6634e1b06085','題永州唐德明竹園','徐照','宋','宋诗','song-poetry','','[]','渭川千畝空聞說，得似君家亦是難。',64,'全唐诗/poet.song.170000.json','["渭川千畝空聞說，得似君家亦是難。", "畦僕不知生鳳實，野翁祇欲乞魚竿。", "忽驚殘粉飄蒼雪，最喜幽聲勝遠灘。", "六月火雲飛不盡，誰知此處獨清寒。"]'),
('18c80c8a-9b9e-494c-81e0-9bcc595300b7','聞水','徐照','宋','宋诗','song-poetry','','[]','燈光難照客懷開，忽聽寒聲響似雷。',32,'全唐诗/poet.song.170000.json','["燈光難照客懷開，忽聽寒聲響似雷。", "天氣無風樹無葉，道州半夜水流來。"]'),
('56b54d79-6317-401e-8ac0-ac51577700c9','寄家書作','徐照','宋','宋诗','song-poetry','','[]','屋頭桑葉大如錢，知是吳蠶第一眠。',32,'全唐诗/poet.song.170000.json','["屋頭桑葉大如錢，知是吳蠶第一眠。", "遠水忽來瀟岸沒，家書却寄道州船。"]'),
('fe00b08c-771e-4dd8-bbf6-1abc366cda09','題何仙姑舊居','徐照','宋','宋诗','song-poetry','','[]','身居何處洞，瀟岸看雲行。',48,'全唐诗/poet.song.170000.json','["身居何處洞，瀟岸看雲行。", "既已通仙籍，奚煩贈道名。", "幌紅花日影，香斷寺鍾聲。", "題句君應識，君詩亦自清。"]'),
('831f4321-52c1-47f0-a443-b8e3c9eb114b','訪瀟岸黄仲立','徐照','宋','宋诗','song-poetry','','[]','長似在船裏，松聲如水聲。',48,'全唐诗/poet.song.170000.json','["長似在船裏，松聲如水聲。", "門當崗路掩，雲向井欄生。", "道進漁樵客，家空世俗輕。", "階前桐葉響，云是白鷳行。"]'),
('54f69b5d-76db-4668-993b-20ce576575f4','夜聽黄仲立彈廣陵','徐照','宋','宋诗','song-poetry','','[]','月色照君琴，移床出木陰。',48,'全唐诗/poet.song.170000.json','["月色照君琴，移床出木陰。", "數聲廣陵水，一片古人心。", "投劍功無補，衝冠怒亦深。", "蹤能清客耳，還是亂時音。"]'),
('7b9357f3-6ae4-4a6a-b6ae-1cddc44f6fd3','求鄧叔珍畫','徐照','宋','宋诗','song-poetry','','[]','畫要天機到，常人學不成。',48,'全唐诗/poet.song.170000.json','["畫要天機到，常人學不成。", "胸中無世事，筆下有詩情。", "斷岸孤村接，高林遠岫平。", "不能求片幅，空自識先生。"]'),
('143e0832-4d20-4857-b24b-5c92c17c79d6','鴈','徐照','宋','宋诗','song-poetry','','[]','今春北歸鴈，秋至又南征。',48,'全唐诗/poet.song.170000.json','["今春北歸鴈，秋至又南征。", "冷避燕關雪，暖逢湘水晴。", "連行衝燒斷，並食雜鷗行。", "沙上無繒弋，相呼一夜鳴。"]'),
('c9f29219-f758-490e-ab86-c1339985b11b','蟬','徐照','宋','宋诗','song-poetry','','[]','葉落無蟬在，又隨林葉生。',48,'全唐诗/poet.song.170000.json','["葉落無蟬在，又隨林葉生。", "不離荒苑處，偏感異鄉情。", "幽韻松風合，枵腸竹露清。", "無端溪鳥逐，飛落地中行。"]'),
('b77cf902-bfc6-410d-80fb-5ea90f886d7c','相中別鄧該','徐照','宋','宋诗','song-poetry','','[]','隔水鷓鴣鳴，一汀香草生。',48,'全唐诗/poet.song.170000.json','["隔水鷓鴣鳴，一汀香草生。", "自憐爲客久，誰忍送君行。", "後會期何日，歸途喜乍晴。", "它春科甲上，必欲見題名。"]'),
('8c2bfa02-eb6a-4106-b373-70d5cb817b2b','題單丙文畫像','徐照','宋','宋诗','song-poetry','','[]','幾年無字學，宋代出王鍾。',192,'全唐诗/poet.song.170000.json','["幾年無字學，宋代出王鍾。", "鈎鎖全遺力，錐沙不露鋒。", "神明還舊觀，時輩獲稀逢。", "點曳連煙霧，崩騰動鳳龍。", "勢成期險峻，意造絕纖穠。", "八法因知永，三分可問蹤。", "豐多尋聖病，求務廢眠饔。", "若匪蒙提耳，終難免擊胸。", "道玄令自悟，恩大報無從。", "新硯傳沅石，寒煤掃嶽松。", "缺碑年號在，古器土泥重。", "注分元非淺，舒情似獨隆。", "租人脂曉轄，離館聽秋蛩。", "賈島銅爲像，平原繡作容。", "簡編流越海，魂夢歷蠻峰。", "先喜趨朝日，應須領戟僮。"]'),
('f280793b-cafb-4c55-937e-f965e2e57775','遊衡山','徐照','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','衡山七十二，高是祝融峰。',96,'全唐诗/poet.song.170000.json','["衡山七十二，高是祝融峰。", "下界蠻方近，中天嶽勢崇。", "四維皆佛占，絕頂正秋濃。", "翼宿平垂地，雷池暗起龍。", "簡書曾禹授，燔祭自周封。", "拜廟巡陰石，看橋入古松。", "雪深居板屋，日轉動厨鍾。", "片水清如鏡，洞庭微見蹤。"]'),
('c53c5998-2fc8-4cad-82c9-426a02a5631f','題嶽僧房','徐照','宋','宋诗','song-poetry','','[]','夏臘高於衆，音容亦未衰。',48,'全唐诗/poet.song.170000.json','["夏臘高於衆，音容亦未衰。", "終經迎客晚，煮藥任僮饑。", "苔上拋生石，猿驚掛衲枝。", "山高九千丈，百事不曾知。"]'),
('5572cd2c-6620-4beb-9323-549bf29067c6','上封寺','徐照','宋','宋诗','song-poetry','','[]','步經千萬歇，兩日至山平。',48,'全唐诗/poet.song.170000.json','["步經千萬歇，兩日至山平。", "磬逐爐香盡，猿摇樹雪傾。", "昔曾因畫見，誰擬得吟行。", "又出穹林閣，終宵看日生。"]'),
('0d080c07-02e1-41b9-8425-a528d971c405','南嶽萬年松','徐照','宋','宋诗','song-poetry','','["\u8861\u5c71"]','所高無二丈，盤折數枝懸。',48,'全唐诗/poet.song.170000.json','["所高無二丈，盤折數枝懸。", "兩樹死一樹，多年言萬年。", "節堅全化石，根蠹半盛泉。", "便可招琴悟，相同把筆傳。"]'),
('0b8b082e-d286-46fd-94a1-21f522810145','登祝融峰','徐照','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','祝融高莫比，身到勝傳聞。',48,'全唐诗/poet.song.170000.json','["祝融高莫比，身到勝傳聞。", "日動洞庭水，風開衡嶽雲。", "老僧冬離寺，群脩夜歸墳。", "後洞連方廣，山頭路即分。"]'),
('4fd23d91-7bbb-4ae7-97e3-7bbdd460f7c8','光武廟','徐照','宋','宋诗','song-poetry','','[]','帳閉爐煙聚，山龍帝者衣。',48,'全唐诗/poet.song.170000.json','["帳閉爐煙聚，山龍帝者衣。", "真人元有道，社鬼忽無威。", "畫剝金猶在，碑平字半非。", "鼓鳴村犬吠，祭罷數翁歸。"]'),
('4572ceec-458a-4794-9015-bfb4b031d869','杜甫墳','徐照','宋','宋诗','song-poetry','','[]','耒陽知縣非知己，救厄無蹤豈忍聞。',32,'全唐诗/poet.song.170000.json','["耒陽知縣非知己，救厄無蹤豈忍聞。", "若更聲名可埋沒，行人定不吊空墳。"]'),
('5ba70d03-6202-492a-a679-525fecf6185b','桂陽道中','徐照','宋','宋诗','song-poetry','','[]','官樹標牌號，遮陰種已成。',48,'全唐诗/poet.song.170000.json','["官樹標牌號，遮陰種已成。", "井乾人立久，蘆密獸行鳴。", "接洞多空地，居城半是兵。", "未能忘好古，缺石認題名。"]'),
('9e9188e4-3c87-4457-82d7-e0942880a16f','郴州蘇仙人宅','徐照','宋','宋诗','song-poetry','','[]','一石升天處，分明孝得仙。',48,'全唐诗/poet.song.170000.json','["一石升天處，分明孝得仙。", "今人脩母冢，古宅抵官田。", "雲似飛來鶴，丹隨汲上泉。", "吾家數十里，回望忽凄然。"]'),
('501243fd-f7f2-4fea-89a1-8d5a58119776','石家洞口','徐照','宋','宋诗','song-poetry','','[]','數朶山如削，青煙起墓墟。',48,'全唐诗/poet.song.170000.json','["數朶山如削，青煙起墓墟。", "聖朝惟大度，蠻黨亦安居。", "練卒來呈箭，生兒遣讀書。", "更須看榜示，一與省人如。"]'),
('14ca69e3-9668-4a13-b6a3-ad5d4987ad4b','筠州送趙判院歸九江','徐照','宋','宋诗','song-poetry','','[]','相逢今半月，夜雨厭同聞。',48,'全唐诗/poet.song.170000.json','["相逢今半月，夜雨厭同聞。", "遠地長爲客，還家極羨君。", "詩低勞盡寫，茶美許重分。", "一馬衝寒去，廬峰正雪雲。"]'),
('22aa18c8-ed26-4845-b4ba-7c2c038d3d8d','題筠州趙縣丞寒谷','徐照','宋','宋诗','song-poetry','','[]','栽梅一百樹，有屋二三間。',48,'全唐诗/poet.song.170000.json','["栽梅一百樹，有屋二三間。", "此地長宜隠，爲官却未閑。", "路移存古井，城逼失前山。", "喜共紅蕖客，來吟至夕還。"]'),
('87db2ecb-111c-4e32-b2e6-16825fb4e218','筠州贈鄧漢卿','徐照','宋','宋诗','song-poetry','','[]','客路相逢欣道合，未嘗一日不相隨。',64,'全唐诗/poet.song.170000.json','["客路相逢欣道合，未嘗一日不相隨。", "僊壇觀水天晴後，古苑尋梅雪落時。", "不娶自然忘世累，雲山何苦動歸思。", "行年未老頭全白，只我知君爲作詩。"]'),
('954173c7-02ac-4139-b051-192af4e345fa','筠州同陳主簿遊園','徐照','宋','宋诗','song-poetry','','[]','一見情先熟，相同野外行。',48,'全唐诗/poet.song.170000.json','["一見情先熟，相同野外行。", "林園仙士守，筆硯小童擎。", "鳥上階除近，冰懸石竇明。", "知君吟易就，清思逼寒生。"]'),
('296c805c-02d2-4719-baff-40df7a6a08d8','移家雁池','徐照','宋','宋诗','song-poetry','','[]','不向山中住，城中住此身。',48,'全唐诗/poet.song.170000.json','["不向山中住，城中住此身。", "家貧兒廢學，寺近佛爲鄰。", "雪長官河水，鴻驚釣渚春。", "夜來游嶽夢，重見日東人。"]'),
('c1d2e13f-5c6d-4f29-81c9-c4a3b7325481','哭翁誠之  其一','徐照','宋','宋诗','song-poetry','','[]','因識詩情性，爲官亦是清。',48,'全唐诗/poet.song.170000.json','["因識詩情性，爲官亦是清。", "吉人天不祐，直道世難行。", "寄諷曾稱菊，思歸或上城。", "贈余詩一軸，追和隔今生。"]'),
('b3d238eb-648f-42aa-86cc-e7a8ec8921c4','哭翁誠之  其二','徐照','宋','宋诗','song-poetry','','[]','高義似君稀，思量淚滴衣。',48,'全唐诗/poet.song.170000.json','["高義似君稀，思量淚滴衣。", "公餘長對坐，路遠未容歸。", "橘井嘗甘冷，蘭亭辨是非。", "誰憐窮賈島，臨老失棲依。"]'),
('a6f0e4ec-3d5d-4ea9-abab-a296905c5d72','送翁靈舒遊邊','徐照','宋','宋诗','song-poetry','','[]','孤劍色磨青，深謀祕鬼靈。',48,'全唐诗/poet.song.170000.json','["孤劍色磨青，深謀祕鬼靈。", "離山春值雪，憂國夜觀星。", "奏凱邊人悅，翻營戰地腥。", "期君歸幕下，何石可書名。"]'),
('8d8b78ae-958b-484e-af01-5932ac2248bf','贈朱道士','徐照','宋','宋诗','song-poetry','','[]','新營一間屋，種柳是前春。',48,'全唐诗/poet.song.170000.json','["新營一間屋，種柳是前春。", "此地已逃俗，何時可卜鄰。", "吟詩能愈疾，得酒自忘貧。", "九十頭無雪，多應笑野人。"]'),
('3196a463-73af-4ec5-8def-488a826d22e6','送徐文淵赴省試','徐照','宋','宋诗','song-poetry','','[]','永州官滿後，借屋靜中居。',48,'全唐诗/poet.song.170000.json','["永州官滿後，借屋靜中居。", "兩歲不參部，一心惟讀書。", "孤經期榜首，行日離春初。", "即有杏花宴，題詩衆弗如。"]'),
('2b62bf39-6dcf-48bb-a13d-cf9e1dd5da97','憶趙紫芝','徐照','宋','宋诗','song-poetry','','[]','一別一百日，無書直至今。',48,'全唐诗/poet.song.170000.json','["一別一百日，無書直至今。", "幾回成夜夢，猶自廢秋吟。", "小雪衣猶綌，荒年米似金。", "知音人亦有，誰若爾知心。"]'),
('dd50d795-3c68-46a3-97e8-94168acbb790','謝薛總幹惠茶盞','徐照','宋','宋诗','song-poetry','','[]','色變天星照，姿貞蜀土成。',96,'全唐诗/poet.song.170000.json','["色變天星照，姿貞蜀土成。", "視形全覺巨，到手却如輕。", "盛水蟾輪漾，澆茶雪片傾。", "價令金帛賤，聲擊水冰清。", "拂拭忘衣袖，留藏有竹籝。", "入經思陸羽，聯句待彌明。", "貪動丹僧見，從來相府榮。", "感情當愛物，隨坐更隨行。"]'),
('ba901504-73ec-41e3-b077-9237620ed678','送陳池州十二韻','徐照','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','急詔下林間，天教公未閑。',144,'全唐诗/poet.song.170000.json','["急詔下林間，天教公未閑。", "虎符重領郡，鴛序暫離班。", "道直言皆壯，心和鬢不斑。", "紫騮曾識駕，白羽可平姦。", "邊地塵初靜，鄰邦化匪艱。", "前途從吏接，後乘約僧還。", "旗影明寒水，梅花動曉關。", "下車逢日吉，滌印破春慳。", "惠政流人至，清吟俗事刪。", "條依蕭守跡，仙認竇君顔。", "千古同歌袴，期年即賜環。", "敢云能下榻，同看九華山。"]'),
('619d270c-ddc4-4f52-85c4-cd1743266851','哭潘德久','徐照','宋','宋诗','song-poetry','','[]','不得身爲郡，歸來兩鬢青。',48,'全唐诗/poet.song.170000.json','["不得身爲郡，歸來兩鬢青。", "方言營隠地，豈擬落文星。", "字有佳人學，琴無野鶴聽。", "傷心共吟處，殘墨在窗櫺。"]'),
('87af5d31-71fe-4861-bf35-a279569c6a0c','贈九華李丹士','徐照','宋','宋诗','song-poetry','','[]','長記零陵郡，共看江上峰。',48,'全唐诗/poet.song.170000.json','["長記零陵郡，共看江上峰。", "平生輕世事，幾度認仙蹤。", "轉式驅雷電，封泥伏虎龍。", "三千三百里，今日又相逢。"]'),
('a225bc52-8a6b-4b9c-8386-db73aadfeb00','贈不食姑','徐照','宋','宋诗','song-poetry','','[]','衣以青爲色，謂如天骨青。',48,'全唐诗/poet.song.170000.json','["衣以青爲色，謂如天骨青。", "近年全不食，飲水自通靈。", "心信生狂語，清羸改俗形。", "半空仙樂奏，曾向靜中聽。"]'),
('0a104856-ce26-4545-981e-8034bda5ef80','酬贈徐璣','徐照','宋','宋诗','song-poetry','','[]','每到齋門敲始應，池禽雙戲動清波。',64,'全唐诗/poet.song.170000.json','["每到齋門敲始應，池禽雙戲動清波。", "愛閑却道無官好，住僻如嫌有客多。", "字學晉碑終日寫，詩成唐體要人磨。", "山民百事今全懶，祇合煙江著短莎。"]'),
('77012e5d-3f95-4d15-9d56-0435f47ae923','同劉孝若野步','徐照','宋','宋诗','song-poetry','','[]','杖屨相隨步野田，坐臨階石和詩篇。',64,'全唐诗/poet.song.170000.json','["杖屨相隨步野田，坐臨階石和詩篇。", "要看隔水人家菊，試借繫門漁父船。", "且緩歸情知有月，不生酒興爲無錢。", "寒來莫問家中事，纔得身閑即是仙。"]'),
('d88ba873-edc5-4e7e-aae9-a355b57865d4','哭鮑清卿  其一','徐照','宋','宋诗','song-poetry','','[]','立性全夷淡，移家避俗氛。',48,'全唐诗/poet.song.170000.json','["立性全夷淡，移家避俗氛。", "酒醺馿倒載，吟苦鶴曾聞。", "連任虛分竹，長年祇愛雲。", "傷心見兒輩，猶讀舊時文。"]'),
('a79626de-d476-435a-a350-398606979280','哭鮑清卿  其二','徐照','宋','宋诗','song-poetry','','[]','一病居閑久，恩榮自及孫。',48,'全唐诗/poet.song.170000.json','["一病居閑久，恩榮自及孫。", "真傳未老貌，禪贊在山言。", "沙鳥巢庭樹，漁舟泊水門。", "重來舊游處，空有竹輿存。"]'),
('b3ec6735-76ed-44bc-a69e-b8d454921665','挽陳西老母','徐照','宋','宋诗','song-poetry','','[]','夫人年八十，頭髮未如銀。',48,'全唐诗/poet.song.170000.json','["夫人年八十，頭髮未如銀。", "有子緣能孝，居家不似貧。", "案頭經尚在，箱內藥初陳。", "至日西門外，無非送葬人。"]'),
('499b510d-1a33-47ab-ba6c-345cdffd9184','挽陳益謙','徐照','宋','宋诗','song-poetry','','[]','先生胡不仕，高卧在林泉。',48,'全唐诗/poet.song.170000.json','["先生胡不仕，高卧在林泉。", "憂國能先見，無人肯薦賢。", "月明新冢上，橘熟舊廬前。", "所著書成篋，多應後世傳。"]'),
('c3d6b40d-a1f1-4e3e-b132-958e7b5e6994','喜蔣德瞻還里','徐照','宋','宋诗','song-poetry','','[]','長作湯村夢，今來免所思。',48,'全唐诗/poet.song.170000.json','["長作湯村夢，今來免所思。", "丹靈年命永，琴裂壁風吹。", "開戶秋花發，終經午飯遲。", "岳陽何日去，後集要君詩。"]'),
('47f9a803-a907-46a6-b301-5a824bcf8593','病起呈靈舒紫芝寄文淵','徐照','宋','宋诗','song-poetry','','[]','唐世吟詩侶，一時生在今。',48,'全唐诗/poet.song.170000.json','["唐世吟詩侶，一時生在今。", "不因吾疾重，誰識爾情深。", "解願衣賒酒，更醫藥費金。", "天教殘息在，安敢廢清吟。"]'),
('0700eedc-a047-4333-9008-59eaf0c0f1c3','送潘才叔倅新安','徐照','宋','宋诗','song-poetry','','[]','大臣曾列薦，聲譽有人聞。',48,'全唐诗/poet.song.170000.json','["大臣曾列薦，聲譽有人聞。", "古郡知臨水，黄山望似雲。", "道情因病長，公務被吟分。", "天上除書近，時危必用君。"]'),
('1380d476-50ff-4bd9-847b-c43e78ae4332','送薛子舒福州省覲','徐照','宋','宋诗','song-poetry','','[]','一馬背西風，斑衣與古同。',48,'全唐诗/poet.song.170000.json','["一馬背西風，斑衣與古同。", "暫時離膝下，鄰郡是閩中。", "到日殘秋兔，還期早塞鴻。", "即須同邑里，來迓黑頭公。"]'),
('23c8c116-c845-426a-bfd8-cc285445f7f0','送奭上人化緣','徐照','宋','宋诗','song-poetry','','[]','專志事皆成，期師此一行。',48,'全唐诗/poet.song.170000.json','["專志事皆成，期師此一行。", "閣盛靈佛像，碑載施人名。", "江闊風催渡，村深雪廢程。", "暫勞曾共說，終可遂閑情。"]'),
('75e5b31b-dfe2-4d7f-b675-a825044ed34f','同趙紫芝宿翁靈舒所居','徐照','宋','宋诗','song-poetry','','[]','不期欣會面，如即失炎蒸。',48,'全唐诗/poet.song.170000.json','["不期欣會面，如即失炎蒸。", "廢寢看遲月，同吟憶遠僧。", "過旬河復見，無雨露多凝。", "得句爭書寫，蛾飛撲滅燈。"]'),
('e63e0d21-be9d-4b0a-9382-db194488f3d9','題陳待制湖樓','徐照','宋','宋诗','song-poetry','','[]','天游觀妙化，人世事皆輕。',216,'全唐诗/poet.song.170000.json','["天游觀妙化，人世事皆輕。", "沆瀣藏仙境，津涯截海城。", "一身凌汗漫，品類仰高明。", "有道行藏小，無心視聽精。", "上疑靈蜃吐，下覺巨鼇擎。", "雨氣西簾入，月華東檻生。", "山臨左輔近，湖自會昌成。", "風起僧鍾直，村回野艇橫。", "蓮枯收繡段，松靜發琴聲。", "濠濮觀魚鳥，瀟湘欠藥蘅。", "一層休更上，百尺有誰評。", "昏日寒峰淡，殘星遠笛鳴。", "醉如元亮興，歸引仲宣情。", "閬苑瓊爲貴，黄州竹過清。", "郡圖添聖跡，畫軸記新營。", "奏樂漁人聽，投車坐客盈。", "八篇移古詠，四字立嘉名。", "未必終成隠，清朝待秉衡。"]'),
('8a1a04d9-cac8-4591-82e8-04dedf44170a','寄徐文淵','徐照','宋','宋诗','song-poetry','','[]','別君一百一十日，喜聽人傳八句詩。',64,'全唐诗/poet.song.170000.json','["別君一百一十日，喜聽人傳八句詩。", "只在鄰州難得見，却思前任遠相隨。", "分名丹荔畫成軸，出處子魚糟過時。", "近日有誰論字法，似聞檢法是同師。"]'),
('025bb993-c585-4144-80f8-5c24a98bbbbd','不寐','徐照','宋','宋诗','song-poetry','','[]','擁衾多不寐，吟思被愁分。',48,'全唐诗/poet.song.170000.json','["擁衾多不寐，吟思被愁分。", "雪氣衝簾入，鴻聲带雨聞。", "兒饑因廢學，親沒未營墳。", "何致貧如此，肝腸痛莫云。"]'),
('162f3999-3d5d-43b9-bfab-986029ec1f87','贈大羅山李秀才','徐照','宋','宋诗','song-poetry','','[]','大羅山上客，後主是宗親。',48,'全唐诗/poet.song.170000.json','["大羅山上客，後主是宗親。", "莫是爲詩苦，却令生世貧。", "荒年家口衆，少日鬢毛新。", "近又重遭禍，虛星必照身。"]'),
('ec6c07d2-9900-4706-8387-6fa619db1d67','白石巖','徐照','宋','宋诗','song-poetry','','[]','一石入遥天，千峰疊在前。',48,'全唐诗/poet.song.170000.json','["一石入遥天，千峰疊在前。", "人行不到處，仙去未多年。", "竇暗雲生像，簷斜日照泉。", "皇朝宣賜物，弟子尚相傳。"]'),
('8e98c109-e4d2-4eca-8df4-5d792c487dba','題薛景石瓜廬','徐照','宋','宋诗','song-poetry','','[]','何地有瓜廬，平湖四畝餘。',48,'全唐诗/poet.song.170000.json','["何地有瓜廬，平湖四畝餘。", "自鋤畦上草，不放手中書。", "人遠來求字，童閑去釣魚。", "山民山上住，却羨水邊居。"]'),
('febc437b-440e-4bd9-a54f-e9eaa6ec9dff','浄光山四詠呈水心先生 宿覺庵','徐照','宋','宋诗','song-poetry','','[]','公說曹溪事，經今六百年。',48,'全唐诗/poet.song.170000.json','["公說曹溪事，經今六百年。", "庵基平地築，碑記遠人傳。", "種竹初遮日，疏巖只欠泉。", "自當居鼎鼐，豈在學修禪。"]'),
('3b33722c-c3e4-4004-9166-e0d032c90727','浄光山四詠呈水心先生 絕境亭','徐照','宋','宋诗','song-poetry','','[]','高頂宜登望，吾州見地形。',48,'全唐诗/poet.song.170000.json','["高頂宜登望，吾州見地形。", "水通蠻國遠，山出海門青。", "蘚徑僧行跡，風枝鶴退翎。", "公能同衆樂，私帑建官亭。"]'),
('a17decd2-cd3b-4f96-b3a6-1f13af4fbb77','浄光山四詠呈水心先生 會景軒','徐照','宋','宋诗','song-poetry','','[]','不見日東上，西原雨一晴。',48,'全唐诗/poet.song.170000.json','["不見日東上，西原雨一晴。", "逐時看景異，風物入詩清。", "立久飛雲滅，身高去鳥平。", "石峰何處是，歸思忽然生。"]'),
('12e3e11e-4b99-47e6-b5da-53674a6c84ab','浄光山四詠呈水心先生 茶山堂','徐照','宋','宋诗','song-poetry','','[]','片山唐國賜，茶有數根留。',48,'全唐诗/poet.song.170000.json','["片山唐國賜，茶有數根留。", "幾番見人說，今朝還獨遊。", "遠波分段白，宿靄向晴收。", "却有覺庵主，猶能學道州。"]'),
('6f8a81ea-7e0c-4660-a3fa-ee46ee396ce5','游雁蕩山 壽昌道中','徐照','宋','宋诗','song-poetry','','[]','碣字芙蓉驛，喜行行不難。',48,'全唐诗/poet.song.170000.json','["碣字芙蓉驛，喜行行不難。", "路侵滄海過，人得異山看。", "圓石蠔黏滿，平塗鷺立寒。", "一遊期一月，回日必冬殘。"]'),
('5b637a69-bb4f-434d-9fe3-52f98c4918d4','游雁蕩山 能仁寺','徐照','宋','宋诗','song-poetry','','[]','寺置有碑傳，觀音巖石前。',48,'全唐诗/poet.song.170000.json','["寺置有碑傳，觀音巖石前。", "殿高燈焰短，山合磬聲圓。", "窗靜吹寒雪，舂鳴落夜泉。", "清遊人豈識，謂不似秋天。"]'),
('6a213ccf-7bf4-4646-9855-20252dc4f8b6','游雁蕩山 大龍湫瀑布','徐照','宋','宋诗','song-poetry','','[]','飛下數千尺，全然無定形。',48,'全唐诗/poet.song.170000.json','["飛下數千尺，全然無定形。", "電橫天日射，龍出石雲腥。", "壯勢春曾看，寒聲佛共聽。", "昔人云此水，洗目最能靈。"]'),
('aae3ed9e-a544-4d92-a538-335a9f6e0e6e','游雁蕩山 靈巖','徐照','宋','宋诗','song-poetry','','[]','雁蕩最奇處，衆巖生此間。',48,'全唐诗/poet.song.170000.json','["雁蕩最奇處，衆巖生此間。", "問名僧盡識，得句客方閑。", "洞峻獼猴入，天晴瀑布慳。", "古時山未顯，謝守只空還。"]'),
('facbf04a-0f84-43b7-b059-a48d820ae6f4','游雁蕩山 靈峰','徐照','宋','宋诗','song-poetry','','[]','我來無一語，閑認昔遊蹤。',48,'全唐诗/poet.song.170000.json','["我來無一語，閑認昔遊蹤。", "誰種路傍樹，却遮山上峰。", "潭乾沉石露，人立去禽衝。", "樵說仙橋險，因思在上封。"]'),
('c933c898-5147-4b1b-9406-1211dfeb22c4','游雁蕩山 石門庵','徐照','宋','宋诗','song-poetry','','[]','庵是何年立，其中有一僧。',48,'全唐诗/poet.song.170000.json','["庵是何年立，其中有一僧。", "蒼崖從古險，白日少人登。", "衆物清相映，吾生隠未能。", "夜來新過虎，抓折樹根藤。"]'),
('3d0e4e51-8474-4812-a34f-bb8a85d00f82','游雁蕩山 寶冠寺','徐照','宋','宋诗','song-poetry','','[]','寺基低且狹，半被石巖分。',48,'全唐诗/poet.song.170000.json','["寺基低且狹，半被石巖分。", "水響常如雨，林寒忽聚雲。", "空房人暫宿，半夜雁初聞。", "此處能通蕩，僧家却不云。"]'),
('bfec9237-1a16-44f4-a919-d25060afd43e','游雁蕩山 贈東庵約公','徐照','宋','宋诗','song-poetry','','[]','白髮白髭鬚，僧年八十餘。',48,'全唐诗/poet.song.170000.json','["白髮白髭鬚，僧年八十餘。", "已成重閣在，別置一庵居。", "客喜逢煎茗，童寒免灌蔬。", "小師南北去，近日各無書。"]'),
('1489dda4-84f6-4d6d-aa7b-b42fdecfa005','題夏景清湘中閣','徐照','宋','宋诗','song-poetry','','[]','湘中山似水，自古有人云。',48,'全唐诗/poet.song.170000.json','["湘中山似水，自古有人云。", "此是曾遊地，今來盡屬君。", "殘風吹岸草，空廟入江雲。", "却憶還鄉夢，清猿半夜聞。"]'),
('6eca9cc8-ee03-4be3-9c0a-c2cb71570aec','題翁卷山居  其一','徐照','宋','宋诗','song-poetry','','[]','十年前有約，今却在城居。',48,'全唐诗/poet.song.170000.json','["十年前有約，今却在城居。", "羨爾能携子，深山自結廬。", "引泉移岸石，栽藥就園蔬。", "見說高林外，樵人聽誦書。"]'),
('c1d3043d-63c0-499f-a85a-77773b474a06','題翁卷山居  其二','徐照','宋','宋诗','song-poetry','','[]','空山無一人，君此寄閑身。',48,'全唐诗/poet.song.170000.json','["空山無一人，君此寄閑身。", "水上花來遠，風中樹動頻。", "蟲行黏壁字，茶煮落巢薪。", "若有高人至，何妨不裹巾。"]'),
('8821d24d-33b9-46d5-a97d-a398e9b9e861','題趙明叔新居','徐照','宋','宋诗','song-poetry','','[]','社壇側近地圖寬，所作園池亦在間。',32,'全唐诗/poet.song.170000.json','["社壇側近地圖寬，所作園池亦在間。", "十萬人家城裏住，少聞人有對門山。"]'),
('f38836f3-5abf-41aa-b062-b2864de26e2b','題張提舉西墅','徐照','宋','宋诗','song-poetry','','[]','渡頭風景如前日，誰種桃花在兩邊。',32,'全唐诗/poet.song.170000.json','["渡頭風景如前日，誰種桃花在兩邊。", "未晚人家門戶閉，鷺鷥閑立釣魚船。"]'),
('ece95e02-6ab5-4ef3-9c51-355bc168211a','登宿覺庵','徐照','宋','宋诗','song-poetry','','[]','雨過山庵樹色鮮，江城四月尚衣綿。',32,'全唐诗/poet.song.170000.json','["雨過山庵樹色鮮，江城四月尚衣綿。", "本來行飯嘗新茗，又得憑欄看插田。"]'),
('3f59a654-bd9b-4475-9bcb-9a19b57b124e','懷趙紫芝翁靈舒','徐照','宋','宋诗','song-poetry','','[]','紫芝別我天台去，翁十深山自結茅。',32,'全唐诗/poet.song.170000.json','["紫芝別我天台去，翁十深山自結茅。", "但見春愁隨日長，不知庭葉蔽禽巢。"]'),
('1ff45f35-d9a4-4d03-9225-77c491e082b6','重題翁卷山居','徐照','宋','宋诗','song-poetry','','[]','山中白日無塵跡，只有啼禽在樹頭。',64,'全唐诗/poet.song.170000.json','["山中白日無塵跡，只有啼禽在樹頭。", "土蟻上鞋行徑葉，楝花黏手掬溪流。", "高吟未許常人學，清福多應積世修。", "新茗一瓶蒙見惠，家童言是社前收。"]'),
('e6e7e848-8905-4ea4-9555-24be400f017f','送張真翁赴舉','徐照','宋','宋诗','song-poetry','','[]','端修修德在，門族盛如初。',48,'全唐诗/poet.song.170000.json','["端修修德在，門族盛如初。", "常有人登第，今稱爾讀書。", "南風舟去疾，西墅客來疎。", "所著青衫舊，前官擬別除。"]'),
('c2a4bdce-7af0-405e-bc02-b358313026b0','送木宗院','徐照','宋','宋诗','song-poetry','','[]','此職司天派，員分南與西。',48,'全唐诗/poet.song.170000.json','["此職司天派，員分南與西。", "事稀從吏懶，詩好笑人低。", "丹荔開屏畫，青榕蓋鶴栖。", "必思隨侍日，曾有舊留題。"]'),
('62436165-7afc-4022-b170-58aa5551e80a','陳待制五月十四日生朝','徐照','宋','宋诗','song-poetry','','[]','羲轡遲中夏，生賢國世寧。',120,'全唐诗/poet.song.170000.json','["羲轡遲中夏，生賢國世寧。", "隔宵蟾欲滿，經溽雨初停。", "分派來溈水，儲神應德星。", "高樓參造物，健筆倒滄冥。", "幾郡流威惠，今人識典刑。", "隨行惟一鶴，堆案有群經。", "道直言皆壯，心和鬢益青。", "即須調鼎鉉，未許在林坰。", "斸石逢雲母，栽松長茯苓。", "龜巢蓮葉上，公見却千齡。"]'),
('19665826-f4bc-4444-bc51-0bd9baaaf15a','寄贈葛朴翁','徐照','宋','宋诗','song-poetry','','["\u897f\u6e56"]','頭上一方巾，西湖住宅新。',48,'全唐诗/poet.song.170000.json','["頭上一方巾，西湖住宅新。", "古今稱句法，島賀是僧身。", "買馬因添口，將錢或施貧。", "有軒名數竹，還復屬何人。"]'),
('b307b78c-e986-4a80-afaf-6ef96960ea37','挽陳夫人','徐照','宋','宋诗','song-poetry','','[]','平陽林給事，有女識經書。',48,'全唐诗/poet.song.170000.json','["平陽林給事，有女識經書。", "爲婦極能孝，今人皆不如。", "得年非餌藥，了葬自餐蔬。", "閩嶠嗟埋骨，新碑到野廬。"]'),
('33021874-c051-409c-8c6b-8da35fa9ace6','挽徐一之','徐照','宋','宋诗','song-poetry','','[]','生平空獻賦，不得似相如。',48,'全唐诗/poet.song.170000.json','["生平空獻賦，不得似相如。", "聖代無遺逸，深溪自隠居。", "僧傳詩藁遠，鳥宿墓林虛。", "有弟情還切，碑將諫筆書。"]'),
('2ea23688-8a21-4995-bf00-d099bb1fe6b0','病中作','徐照','宋','宋诗','song-poetry','','[]','一行三步歇，屋漏坐頻移。',48,'全唐诗/poet.song.170000.json','["一行三步歇，屋漏坐頻移。", "妻欲藏茶鼎，僧能施藥資。", "鄰園梅盡發，河岸草生遲。", "天解憐貧病，難令不作詩。"]'),
('7de5f20a-7d24-4900-a0af-80a569412eeb','和翁靈舒冬日書事  其一','徐照','宋','宋诗','song-poetry','','[]','石縫敲冰水，凌寒自煮茶。',48,'全唐诗/poet.song.170000.json','["石縫敲冰水，凌寒自煮茶。", "梅遲思閏月，楓遠誤春花。", "貧喜田新長，吟令鬢已華。", "城中尋小屋，歲晚欲移家。"]'),
('d3c325ed-ad21-40e7-9690-d1911180b8db','和翁靈舒冬日書事  其二','徐照','宋','宋诗','song-poetry','','[]','秀句出寒餓，從人笑過清。',48,'全唐诗/poet.song.170000.json','["秀句出寒餓，從人笑過清。", "步溪波逐影，吟竹鳥譍聲。", "酒裏安天運，春邊見物情。", "耕桑猶罄樂，何事可營生。"]'),
('0165edce-e7fe-498b-ab7a-8d3b1ff463a2','和翁靈舒冬日書事  其三','徐照','宋','宋诗','song-poetry','','[]','十日南山雪，今朝又北風。',48,'全唐诗/poet.song.170000.json','["十日南山雪，今朝又北風。", "燒衝崖石斷，梅映野堂空。", "難語傷時事，無成愧野翁。", "一生吟思味，獨喜與君同。"]'),
('a1b20392-2918-40fd-921c-8c2a1aafce58','道書記房老梅','徐照','宋','宋诗','song-poetry','','[]','香有竹風知，無塵雜野姿。',48,'全唐诗/poet.song.170000.json','["香有竹風知，無塵雜野姿。", "爲憐新白髮，重記舊題詩。", "蘚带龍鱗剝，蜂沾蠹屑垂。", "不來三十載，半樹是孫枝。"]'),
('5967552b-5bf1-4a8e-8f43-b4a66b8bca03','訪奭公宿和其韻','徐照','宋','宋诗','song-poetry','','[]','枯株圍古寺，長覺夜寒增。',48,'全唐诗/poet.song.170000.json','["枯株圍古寺，長覺夜寒增。", "坐聽風吹雪，吟移佛照燈。", "灰沉麟骨碎，茶沸蟹涎凝。", "何計從師老，生涯若履冰。"]'),
('878f7a10-5e58-45b2-ad24-da907d5b4396','送侯寧','徐照','宋','宋诗','song-poetry','','[]','芳蘭雜蕭艾，獨鶴隨雞群。',48,'全唐诗/poet.song.170000.json','["芳蘭雜蕭艾，獨鶴隨雞群。", "男兒暫困厄，困厄誰憐君。", "或云深林間，其馥人自聞。", "何如鼓雙翼，軒昂九霄雲。"]'),
('b0dd3e1b-923a-4a7c-a792-33cb002825e8','種菊  其一','徐照','宋','宋诗','song-poetry','','[]','屈平發悲吟，采之療饑腹。',48,'全唐诗/poet.song.170000.json','["屈平發悲吟，采之療饑腹。", "人貌歲不同，興嘆有荀昱。", "遠人陶淵明，釀酒不等熟。", "醉把菊花枝，醅濁巾可漉。"]'),
('42693b63-f820-4c93-8193-38ced7277323','種菊  其二','徐照','宋','宋诗','song-poetry','','[]','一花八十品，秋風巧於春。',48,'全唐诗/poet.song.170000.json','["一花八十品，秋風巧於春。", "不與群物競，靜性如幽人。", "濕燥欲及宜，□□養性真。", "誰授服餌法，應能壽吾身。"]'),
('c3ad6d63-6b53-4e7d-97c3-dc5b311922cd','低飛雀','徐照','宋','宋诗','song-poetry','','[]','雀飛不高丈，啾啾聚榛菅。',48,'全唐诗/poet.song.170000.json','["雀飛不高丈，啾啾聚榛菅。", "太倉有腐粟，安得悅爾顔。", "弋人四驚逐，飛投網羅間。", "巢中衆雛鳴，望其母來還。"]'),
('a520e351-68b5-4c89-9d20-96943a35d5e3','憫交','徐照','宋','宋诗','song-poetry','','[]','天道轉末劫，氣序多差殽。',60,'全唐诗/poet.song.170000.json','["天道轉末劫，氣序多差殽。", "山河破瓦色，産物無豐饒。", "土薄黍無力，膠粘難久牢。", "中間靈者人，亦復多輕澆。", "憫今不逮古，空思管鮑交。"]'),
('87868640-2423-4e98-a49e-c624289735da','翫月','徐照','宋','宋诗','song-poetry','','[]','初生如金鈎，將滿如玉盤。',72,'全唐诗/poet.song.170000.json','["初生如金鈎，將滿如玉盤。", "古人愛明月，月色疑可餐。", "賈島倚長杉，精魂化蟾間。", "李白捉皓色，狂不如波瀾。", "何爲梅山翁，見月長興嘆。", "月多照予愁，未久先掩關。"]'),
('6fb26fa3-89f5-4fcd-af3c-2df4c071c2ff','登東寶山僧舍','徐照','宋','宋诗','song-poetry','','[]','捫蘿上纔絕，移舟泊前灘。',132,'全唐诗/poet.song.170000.json','["捫蘿上纔絕，移舟泊前灘。", "火雲滿行路，剝啄敲柴關。", "脫裳掛木杪，喘汗如漿翻。", "主人喜客來，笑話生春溫。", "袒裼不我責，我息方己安。", "自拾落地薪，煮茗當盃盤。", "卧石平如床，上有樹影繁。", "清風吹骨毛，執熱鄙炎官。", "佳禽不自匿，靜處故相喧。", "竟日忘渴饑，山水秀堪餐。", "換却世上心，世上多憂煩。"]'),
('077e4fc7-34c3-4bd0-b1d1-58d7cf84210b','喜翁卷至','徐照','宋','宋诗','song-poetry','','[]','開裳坐巖石，靜僻勝塵區。',96,'全唐诗/poet.song.170000.json','["開裳坐巖石，靜僻勝塵區。", "禽落閑庭果，荷侵濕岸蒲。", "高情天外遠，暑氣竹間無。", "淺井瓦瓶汲，低床桃簟鋪。", "江聲空檻樹，燒影照巢烏。", "困睡拋書冊，悲吟缺玉壺。", "浮生如夢幻，世事任鳬盧。", "但得過從樂，無嫌此地迂。"]'),
('25414e1e-af3e-4874-9354-d73178c64a28','林中奉酬翁卷','徐照','宋','宋诗','song-poetry','','[]','已畢林中事，雲煙隔暮城。',96,'全唐诗/poet.song.170000.json','["已畢林中事，雲煙隔暮城。", "古松知鶴老，沙水見魚行。", "孤坐形生影，窮吟谷應聲。", "嗜茶因識譜，尋藥忽遺名。", "日吉期蜂分，山晴放犢耕。", "喜幽從地僻，不學負時清。", "緣薺同家食，披藤發野情。", "松廬極鄰並，歸計幾時成。"]'),
('ac91f3a2-9f7e-48de-8a03-f254cb2da51b','贈張將領十六韻','徐照','宋','宋诗','song-poetry','','[]','一載鄞江上，波平塵不飛。',168,'全唐诗/poet.song.170000.json','["一載鄞江上，波平塵不飛。", "屢成橫槊句，密運若神機。", "弓影盈秋月，劍光摇夕暉。", "起身黄石地，成夢黑山薇。", "府帥曾前席，君王擬解衣。", "蓴鱸休在念，草木亦知威。", "骨相封侯貴，家鄉衣錦歸。", "柳高戎壁峻，花近宅堂煇。", "二妓吟霜竹，千金買寶鞿。", "好文佳士致，起舞麗人圍。", "庭果丹顋潤，官醪蠟脚肥。", "胡琴音屈律，香篆氣紛霏。", "輔漢終成績，逢劉亦有依。", "兒男當富貴，得意似君稀。"]'),
('f2a22f04-c26e-4f4c-9230-fc1370bd282f','覓班竹作床','徐照','宋','宋诗','song-poetry','','[]','翠節老苔濕，湘妃泪遺蹤。',60,'全唐诗/poet.song.170000.json','["翠節老苔濕，湘妃泪遺蹤。", "莫顧鬼物護，斤斧誅籜龍。", "不數漢水邊，棄賊如草蓬。", "殺青色玳瑁，六尺光照空。", "俾我卧讀書，魂夢來槐宮。"]'),
('42a1af89-11bf-494c-9973-aebaf40cb023','黄公濟','徐照','宋','宋诗','song-poetry','','[]','石色丹砂文，林木翠相合。',84,'全唐诗/poet.song.170000.json','["石色丹砂文，林木翠相合。", "靈源一派長，近與銀漢接。", "老眼掛千仞，吟步遶百匝。", "雲遮忽有無，路坳見重疊。", "風響聞笙竽，龍靈化蛙蛤。", "再掬清泠波，一洗□滯匼。", "但願高高流，勿以衆流雜。"]'),
('83c42ec8-3962-4cdf-833e-51e371fcd2a2','畏虎','徐照','宋','宋诗','song-poetry','','[]','侯門無羆虎，進者何趑趄。',108,'全唐诗/poet.song.170000.json','["侯門無羆虎，進者何趑趄。", "主人畏客來，有甚虎與羆。", "彼此情不安，逢迎反憂悲。", "我愛田上翁，面有無求姿。", "不怨春作苦，聯以歲晚期。", "藜藿如羊棗，豆粟兼晨炊。", "西風作霜晴，曉寒起呼兒。", "大兒收橡實，小兒拾松枝。", "無求當自求，勿用他人爲。"]'),
('f40ed86f-3fd8-4564-8540-543627a79ce5','題侯侶之九歌圖','徐照','宋','宋诗','song-poetry','','[]','君家九歌圖，元是龍眠畫。',144,'全唐诗/poet.song.170000.json','["君家九歌圖，元是龍眠畫。", "冰毫動天機，意與象俱化。", "坡仙以一馬，千金莫酬價。", "昏眼喜忽明，老絹塵欲亞。", "𥦷窠有靈鬼，天馬夾龍駕。", "鱗幢借金節，隠隠出虛罅。", "箎駕迎飛響，陳具咸所禡。", "湘天水波立，綠紅渺高下。", "漠漠楚客魂，萬古入悲話。", "頹簷饑禽啄，長陀瘦鮫跨。", "八篇竹枝詞，命君共吟些。", "愁聲還入市，乞酒從嘲駡。"]'),
('21a1343f-ccae-4cfc-a55d-9c9e4c55b9e4','渡錢塘江','徐照','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','怒潮出海門，巨浪貼天白。',192,'全唐诗/poet.song.170000.json','["怒潮出海門，巨浪貼天白。", "阿香擊鼓喧，地軸忽崩坼。", "大令虬與龍，讋畏改窟宅。", "千艘未敢前，長年面憂色。", "水程八十里，動有千里隔。", "飛櫓更無常，身世難可測。", "縛纜廟山脚，炊煙岸連碧。", "天無砲車雲，風響稍自激。", "低回兀小篷，滉漾任所適。", "青瑶沐金蟾，四向山絕跡。", "仰面觀斗柄，意可曉南北。", "吳橋淮楚棹，盡爲聲利役。", "天公憫我憂，江水平如席。", "何年變平陸，險危免經歷。", "遥遥星火紅，知近人家側。", "驚喜愧老奴，夢遠鼻吹息。"]'),
('1b8a04c7-315a-40ab-b364-d59689b02fa6','朱可翁陳西老徐靈淵携酒餞別飲罷以周興嗣千字文中語爲韻曰謂語助者且名爲江上行云分得語字','徐照','宋','宋诗','song-poetry','','[]','歲晚風霧寒，用事有青女。',156,'全唐诗/poet.song.170000.json','["歲晚風霧寒，用事有青女。", "滕六更無頼，冰花鬭欲舞。", "狹坐夜生稜，叉袖手難距。", "百草盡晦寂，蟲虺亦蟄戶。", "于何梅山翁，遥遥作行旅。", "耳熱呼盧仝，此意何自語。", "淵明古達者，饑逐亦無處。", "詩老知我憂，相暖且樽俎。", "鼎足吟清詩，龍蛇動盈楮。", "參昴掛屋角，呼兒更撚炬。", "古來回并難，發明各何許。", "飛雁度荒塞，新梅耿平楚。", "相思續君詩，亦足慰心緒。"]'),
('b81063a5-e609-49a8-84fe-d50789b1df6a','江上翁','徐照','宋','宋诗','song-poetry','','[]','江頭老翁不爲貧，自織笭箵張素鱗。',32,'全唐诗/poet.song.170000.json','["江頭老翁不爲貧，自織笭箵張素鱗。", "明月江頭春水漲，小船撐岸拾流薪。"]'),
('12823812-cc6f-480b-8d21-a14e5f04370d','分題得漁村晚照','徐照','宋','宋诗','song-poetry','','[]','漁師得魚繞溪賣，小船橫繫柴門外。',64,'全唐诗/poet.song.170000.json','["漁師得魚繞溪賣，小船橫繫柴門外。", "出門老嫗喚雞犬，收歛蓑衣屋頭曬。", "賣魚得酒又得錢，歸來醉倒地上眠。", "小兒啾啾問煮米，白鷗飛去蘆花煙。"]'),
('3fe73455-a3d3-461c-a889-bc28a44df9be','陌上柳','徐照','宋','宋诗','song-poetry','','[]','千葉萬葉翠色鮮，春風吹盡枝上綿。',64,'全唐诗/poet.song.170000.json','["千葉萬葉翠色鮮，春風吹盡枝上綿。", "五里長亭更短亭，古人今人千萬情。", "中閨美人念離別，羅衾曉寒夢分絕。", "陌上楊柳春生枝，陌上行人春不歸。"]'),
('db25e9b2-61b3-4066-a9c7-43933d52fa9e','題歸雁圖','徐照','宋','宋诗','song-poetry','','[]','浙水平天浄如掃，客雁飛來秋事早。',64,'全唐诗/poet.song.170000.json','["浙水平天浄如掃，客雁飛來秋事早。", "短篷吹雪荻花風，影落深叢山欲曉。", "汀蕪無綠鮮飆香，一宵聲影空瀟湘。", "有人展卷苦思歸，夢隨翎翅飛滄茫。"]'),
('64771698-3a45-48bc-8eda-1ec0bf4980f0','題慧二梅圖','徐照','宋','宋诗','song-poetry','','[]','水波上頭竹枝下，隙月斜穿雪輕灑。',64,'全唐诗/poet.song.170000.json','["水波上頭竹枝下，隙月斜穿雪輕灑。", "東君祇付一家春，俗眼自分宮與野。", "從來詩子多好奇，寒暖又別南北枝。", "山翁酒醉不復語，窮馿破帽松風吹。"]'),
('67c6a870-d712-4235-9b33-ed79168fceed','瑞安道房觀陳友雲古柏命予作詩','徐照','宋','宋诗','song-poetry','','[]','西陵西陵高插天，武侯廟前寒潑煙。',64,'全唐诗/poet.song.170000.json','["西陵西陵高插天，武侯廟前寒潑煙。", "誰知陳侯筆有力，遠遠移來向君壁。", "老翁眼見驚愕眙，醉摇屈筆來吟詩。", "霹靂燒空雲劈地，一夜蒼虬忽飛去。"]'),
('eff3c9ba-f524-4458-8435-b96fa55ee06f','石屏歌爲潘隠父作','徐照','宋','宋诗','song-poetry','','[]','浯溪片石天來長，顔家字畫元文章。',252,'全唐诗/poet.song.170000.json','["浯溪片石天來長，顔家字畫元文章。", "淡巖明秀甲天下，萬古石鼓留岐陽。", "大工踏天割雲骨，盡出湘沅山水窟。", "六尺四面起稜角，顔色萇洪血塗抹。", "何年老手擘巨靈，赤雲白日聯青星。", "湘娥罷瑟老魚舞，瘦鶴叫下蘆花汀。", "潘侯得之如升僊，可惜只賣四萬錢。", "梅山山翁覷天巧，笑渦旋頰流詩涎。", "君不見元祐年間狄引進，雪林千里春水潤。", "大蘇黄九來賦詩，百盃醉倒金釵陣。", "潘侯石屏真絕奇，更多酒肉如澠池。", "蘇黄已矣不復來，政須我輩來吟之。", "又不見當年玉川子，拾得玉碑極歡喜。", "半路忽遭窮相馿，十步九蹶扶不起。", "至堅易折古所傷，願人好置高人堂，謝客巖頭生夜光。"]'),
('e55dd4c8-b069-4e98-a02f-0ca8fe62275c','上木詹事生日十月十五','徐照','宋','宋诗','song-poetry','','[]','客花十月開湘桃，蓬天春淺霞煙高。',128,'全唐诗/poet.song.170000.json','["客花十月開湘桃，蓬天春淺霞煙高。", "僊郎玩世跨鵬海，紅龍紫仗青童翿。", "星斗心胸□□□，筆端衮衮驚滄濤。", "天皇庚申開鳳曆，百八十歲生夔臯。", "彤庭射策鬼斗□，虎符分寄梁懸刀。", "承華出入漢長吏，畫圖周室諸侯朝。", "綾綺連錢蔽華屋，神奎秘畫黄金標。", "鶴嘴瓶深貯沆瀣，西峰倒碧翻蒲萄。"]'),
('a338cfed-2867-47e7-a204-6f19397b9471','未廻車','徐照','宋','宋诗','song-poetry','','[]','山川匪遥遠，行人未迴車。',48,'全唐诗/poet.song.170000.json','["山川匪遥遠，行人未迴車。", "欲語昨宵夢，忽接今朝書。", "啼烏在屋上，綠草生庭除。", "仰看日月光，照知子衿裾。"]'),
('88140592-0f2a-40fe-be59-470eadf5b5d7','采蘭曲','徐照','宋','宋诗','song-poetry','','[]','門前春水青如羅，采蘭船小長經過。',32,'全唐诗/poet.song.170000.json','["門前春水青如羅，采蘭船小長經過。", "未須折蘭喜相贈，見此自令憂思多。"]'),
('b40af4d1-dac0-44e9-b421-b85fcf98e40b','自君之出矣  其一','徐照','宋','宋诗','song-poetry','','[]','自君之出矣，心意遠相隨。',24,'全唐诗/poet.song.170000.json','["自君之出矣，心意遠相隨。", "拆破唐人絹，經經是雙絲。"]'),
('4fbb2c52-26a4-4843-9ce8-689f82b7056a','自君之出矣  其二','徐照','宋','宋诗','song-poetry','','[]','自君之出矣，玉鑑生塵垢。',24,'全唐诗/poet.song.170000.json','["自君之出矣，玉鑑生塵垢。", "蓮子種成荷，曷時可成藕。"]'),
('6d1a53a5-eceb-427b-a911-76dcfa46a4de','自君之出矣  其三','徐照','宋','宋诗','song-poetry','','[]','自君之出矣，懶粧眉黛濃。',24,'全唐诗/poet.song.170000.json','["自君之出矣，懶粧眉黛濃。", "愁心如屋漏，點點不移床。"]'),
('5a19894a-770f-4afb-9cea-0de37968e5d4','春日曲','徐照','宋','宋诗','song-poetry','','[]','中婦掃蠶蟻，挈籃桑樹間。',24,'全唐诗/poet.song.170000.json','["中婦掃蠶蟻，挈籃桑樹間。", "小姑摘新茶，日斜下前山。"]'),
('40323ed8-09f5-4525-9ff2-aa7233a661a3','路上花','徐照','宋','宋诗','song-poetry','','[]','富女易生驕，貧女難保節。',24,'全唐诗/poet.song.170000.json','["富女易生驕，貧女難保節。", "慇懃路上花，行人意先折。"]'),
('41caeab2-5dd1-4e98-89ae-99d7f9851035','鼕鼕鼓','徐照','宋','宋诗','song-poetry','','[]','前鼓鼕鼕後鼓鼕鼕聲一同。',30,'全唐诗/poet.song.170000.json','["前鼓鼕鼕後鼓鼕鼕聲一同。", "忽然聲近忽聲遠，又是東風西風南北風。"]'),
('064b5888-c4c6-42e3-b27d-07a13648569b','湘江曲','徐照','宋','宋诗','song-poetry','','[]','湘江無潮水，日夜一向流。',24,'全唐诗/poet.song.170000.json','["湘江無潮水，日夜一向流。", "別心無彼此，兩處各悠悠。"]'),
('4ce00f3f-0be8-4b2b-96fc-9903e2fbf0d4','古怨曲','徐照','宋','宋诗','song-poetry','','[]','易得君知音，難得君知心。',48,'全唐诗/poet.song.170000.json','["易得君知音，難得君知心。", "縱然恩意短，寧使言語深。", "渴飲貪泉水，倦息惡木陰。", "儻涉不美名，曷可銷煩襟。"]'),
('cdf6498c-9994-4d39-9389-2f683d8c67d2','山中吟','徐照','宋','宋诗','song-poetry','','[]','小豎驅牛羊，日照山下道。',24,'全唐诗/poet.song.170000.json','["小豎驅牛羊，日照山下道。", "山翁家業貧，青松不得老。"]'),
('cd6308ac-fb77-408d-957d-74a53c33c1fa','各遠禍','徐照','宋','宋诗','song-poetry','','[]','拙鳩營巢杉刺棚，曙出昏入俱不鳴。',48,'全唐诗/poet.song.170000.json','["拙鳩營巢杉刺棚，曙出昏入俱不鳴。", "雙雛脫殻羽翅生，母來哺餵雛無聲。", "鳩能默默各遠禍，一日高飛啄庭果。"]'),
('019dfd93-798e-4dca-86b5-a0ae71516813','繰絲曲','徐照','宋','宋诗','song-poetry','','[]','荻箔爭收繭，瓢輪鬭卷絲。',24,'全唐诗/poet.song.170000.json','["荻箔爭收繭，瓢輪鬭卷絲。", "未充身上著，先賣給朝饑。"]'),
('cde96fe7-6408-4547-b435-04ef26ff4617','灉湖作','徐照','宋','宋诗','song-poetry','','[]','灉湖春來水拍天，秋來水涸成乾田。',32,'全唐诗/poet.song.170000.json','["灉湖春來水拍天，秋來水涸成乾田。", "天地盈虛不可保，富貴於人豈長好。"]'),
('69b5c872-f7b7-475e-8a90-5f5369f51284','青鳩詞','徐照','宋','宋诗','song-poetry','','[]','勞勞復勞勞，生人半行客。',64,'全唐诗/poet.song.170000.json','["勞勞復勞勞，生人半行客。", "今人行古道，古道有行役。", "相逢莫等閑，相離易疎隔。", "慇懃紅杏花，徹宵對芳席。", "明年花開人東西，青鳩食花舊處啼。"]'),
('10ce7bd5-2f7a-4a79-aab3-fee83d51f344','練波曲','徐照','宋','宋诗','song-poetry','','[]','素練平鋪吹不起，夜來垂下天孫機。',32,'全唐诗/poet.song.170000.json','["素練平鋪吹不起，夜來垂下天孫機。", "愁看百尺千尺長，不作遊子寒時衣。"]'),
('0fa60a09-fa2b-41e7-80c5-2f515654272b','商人婦','徐照','宋','宋诗','song-poetry','','[]','百尺檣竿過酒樓，竹標雉尾信風頭。',32,'全唐诗/poet.song.170000.json','["百尺檣竿過酒樓，竹標雉尾信風頭。", "高鬟粉項商人婦，不識人間離別愁。"]'),
('853a044a-9d5e-4ef5-a9bf-8cabe82933dc','黄哺歌','徐照','宋','宋诗','song-poetry','','[]','唐翁釣魚至黄哺，不得魚兒得魚母。',84,'全唐诗/poet.song.170000.json','["唐翁釣魚至黄哺，不得魚兒得魚母。", "廿里返家急烹煮，魚能脫命刀與砧。", "掉入碧潯千尺深，半無鱗鬣眼血侵。", "黄哺黄哺又有一漁父，魚兮魚兮復遭禍。", "爲魚猶或爲兒苦，死兮生兮不離兒處所。"]'),
('ab5a0842-ae04-4dac-953f-995578b33fda','同地歌','徐照','宋','宋诗','song-poetry','','[]','堂前種黄葵，百結種葵畔。',24,'全唐诗/poet.song.170000.json','["堂前種黄葵，百結種葵畔。", "同地不同心，徒令永相見。"]'),
('c1d6cad4-c4af-4163-8ca3-27a17004b690','猛虎行','徐照','宋','宋诗','song-poetry','','[]','猛虎出林行，咆哮取人食。',48,'全唐诗/poet.song.170000.json','["猛虎出林行，咆哮取人食。", "居人慮虎至，荆棘挂牆壁。", "虎乃愛其身，驚遁不近側。", "人兮不如虎，甘心墮荆棘。"]'),
('bee96aa2-c01c-43f0-a485-b649b710c1e7','昭君詞','徐照','宋','宋诗','song-poetry','','[]','琵琶彈得是胡音，上馬低蛾淚滴襟。',32,'全唐诗/poet.song.170000.json','["琵琶彈得是胡音，上馬低蛾淚滴襟。", "畫匠枉教延壽死，相如作賦得黄金。"]'),
('b06bf47b-91f2-4da2-839a-822a9dcbe65a','勸魚吟','徐照','宋','宋诗','song-poetry','','[]','一寒遊鱼不可見，春暖遊鱼初見面。',32,'全唐诗/poet.song.170000.json','["一寒遊鱼不可見，春暖遊鱼初見面。", "淵清人稀魚可遊，勸魚切勿親金鈎。"]'),
('aa14160f-859a-4a46-babe-66fa217e4a36','江南曲','徐照','宋','宋诗','song-poetry','','[]','絡緯催寒斷夢頭，不眠雙淚枕邊流。',32,'全唐诗/poet.song.170000.json','["絡緯催寒斷夢頭，不眠雙淚枕邊流。", "屏風莫展江南畫，寸地能生千里愁。"]'),
('442e6658-f940-404e-a26a-84cb47e1c976','采蓮曲  其一','徐照','宋','宋诗','song-poetry','','[]','行遍塘邊不肯歸，鴛鴦打起看雙飛。',32,'全唐诗/poet.song.170000.json','["行遍塘邊不肯歸，鴛鴦打起看雙飛。", "荷花近岸難攀折，蒲葦叢深露濕衣。"]'),
('cbfe5cb2-23b1-46e2-bc7c-26564c56a785','采蓮曲  其二','徐照','宋','宋诗','song-poetry','','[]','羅蓋初收晚日陰，野鳬飛起小魚沉。',32,'全唐诗/poet.song.170000.json','["羅蓋初收晚日陰，野鳬飛起小魚沉。", "蓮蓬摘下留空柄，把向船前探水深。"]'),
('f446d121-dd65-423a-9b54-a8be0365194f','李溪曲別鄭遇','徐照','宋','宋诗','song-poetry','','[]','七十二灘聲共聞，一朝路向李溪分。',32,'全唐诗/poet.song.170000.json','["七十二灘聲共聞，一朝路向李溪分。", "梅花無情動春夢，未好憶家先憶君。"]'),
('bea478e0-acda-4496-b2c3-63bc2bcf2d69','柳葉詞','徐照','宋','宋诗','song-poetry','','[]','嫩葉吹風不自持，淺黄微綠映清池。',32,'全唐诗/poet.song.170000.json','["嫩葉吹風不自持，淺黄微綠映清池。", "玉人未識分離恨，折向堂前學畫眉。"]'),
('34e68d52-7da6-4ace-9dc7-a73ddd608322','宮詞  其一','徐照','宋','宋诗','song-poetry','','[]','睡眼蒙茸带宿酲，起來階下探春晴。',32,'全唐诗/poet.song.170000.json','["睡眼蒙茸带宿酲，起來階下探春晴。", "滿身花露聽鶑久，禁鼓重新打六更。"]'),
('1f788904-c133-4a73-9d4a-3f9b95a7e516','宮詞  其二','徐照','宋','宋诗','song-poetry','','[]','懶臨粧架索朱綿，上得高臺失寶鈿。',32,'全唐诗/poet.song.170000.json','["懶臨粧架索朱綿，上得高臺失寶鈿。", "內屋深屏多畫杏，有誰獨喜畫雙蓮。"]'),
('f49b5615-0cc5-423f-a42b-9fa093ee364a','妾薄命','徐照','宋','宋诗','song-poetry','','[]','初與君相知，便欲腸肺傾。',48,'全唐诗/poet.song.170000.json','["初與君相知，便欲腸肺傾。", "只擬君肺腸，與妾相似生。", "徘徊幾言笑，始悟非真情。", "妾情不可收，悔思淚盈盈。"]'),
('19b95df1-af64-4002-97e7-b4d28ed0c53e','越魚吟','徐照','宋','宋诗','song-poetry','','[]','越魚生水中，專食水上禽。',40,'全唐诗/poet.song.170000.json','["越魚生水中，專食水上禽。", "禽又安知魚，魚自生機心。", "越魚早來人釣得，人却放之反不食。"]'),
('253e0d69-a5b8-43b6-91ab-739c1acba7ec','三閣詞  其一','徐照','宋','宋诗','song-poetry','','[]','龔孔與麗華，迷昏竟宵晝。',24,'全唐诗/poet.song.170000.json','["龔孔與麗華，迷昏竟宵晝。", "只知歡似前，豈知禍萌後。"]'),
('1a0ef0bf-6d22-4171-b9cb-e36e699b7c20','三閣詞  其二','徐照','宋','宋诗','song-poetry','','[]','三閣變瓦礫，歡樂一時休。',24,'全唐诗/poet.song.170000.json','["三閣變瓦礫，歡樂一時休。", "草沒石井欄，草亦爲汝羞。"]'),
('0e541d8b-6a5f-4456-a26a-7b0d7ded170f','美人睡起曲','徐照','宋','宋诗','song-poetry','','[]','睡起胡蜂已退衙，袖中猶带鬰金牙。',32,'全唐诗/poet.song.170000.json','["睡起胡蜂已退衙，袖中猶带鬰金牙。", "懶拈青扇遮微雨，鬭摘庭前紫笑花。"]'),
('7694ea2c-6ec4-49e8-bcb9-68860c82c2f5','宮怨','徐照','宋','宋诗','song-poetry','','[]','楊柳枝疎見月痕，夜香燒了鎖宮門。',32,'全唐诗/poet.song.170000.json','["楊柳枝疎見月痕，夜香燒了鎖宮門。", "琵琶不有愁人聽，誰識聲中是怨言。"]'),
('944ffd20-a28a-45e7-a79c-8c0fe133f5e8','促促詞','徐照','宋','宋诗','song-poetry','','[]','促促復促促，東家歡欲歌，西家悲欲哭。',82,'全唐诗/poet.song.170000.json','["促促復促促，東家歡欲歌，西家悲欲哭。", "丈夫力耕長忍饑，老婦勤織長無衣。", "東家鋪兵不出戶，父爲節級兒抄簿。", "一年兩度請官衣，每月請米一石五。", "小兒作軍送文字，旬日一輪怨辛苦。"]'),
('241794a6-8209-4c52-981e-2aa2e5393135','征婦思','徐照','宋','宋诗','song-poetry','','[]','年半爲郎婦，郎去戍采石。',76,'全唐诗/poet.song.170000.json','["年半爲郎婦，郎去戍采石。", "又云戍濠梁，不得真消息。", "半年無信歸，獨自守羅幃。", "西風吹妾寒，倩誰寄郎衣。", "姑老子在腹，憶郎損心目。", "願郎征戰早有功，生子有蔭姑有封。"]'),
('56bff8a6-09da-407a-8c98-1598c1703665','蝗飛高','徐照','宋','宋诗','song-poetry','','[]','戰士屍上蟲，蟲老生翅翼。',120,'全唐诗/poet.song.170000.json','["戰士屍上蟲，蟲老生翅翼。", "目怒體甲硬，豈非怨飛激。", "櫛櫛北方來，橫遮遍天黑。", "戍婦聞我言，色變氣咽逆。", "良人近戰死，屍骸委砂礫。", "昨夜魂夢歸，白騎曉無迹。", "因知天中蝗，乃是屍上物。", "仰面久迎視，低頭淚雙滴。", "呼兒勿殺害，解繫從所適。", "蝗乎若有知，飛入妾心臆。"]'),
('274e57bc-6d42-4506-8e6f-da0507fe1229','廢居行','徐照','宋','宋诗','song-poetry','','[]','北風蕭蕭胡馬鳴，邊人走盡空戶庭。',128,'全唐诗/poet.song.170000.json','["北風蕭蕭胡馬鳴，邊人走盡空戶庭。", "黄金埋藏禾米棄，路上逐日空饑行。", "子西父南弗相守，仰面看日啼無聲。", "生身不合屬中土，自昔無時無戰爭。", "家桑椹熟生野蛾，兔跳席箕田成坡。", "一路幾州皆荒廢，處處戰骨平草多。", "傳報將軍殺胡虜，取得山河歸漢主。", "殘生只願還本鄉，且免後裔有兵禍。"]'),
('1bc01e05-3e9e-4624-ad0a-4a5e2b0b7858','釜下吟','徐照','宋','宋诗','song-poetry','','[]','阿對泉頭舂黑菰，萁然豆煮蟲泣鍋。',139,'全唐诗/poet.song.170000.json','["阿對泉頭舂黑菰，萁然豆煮蟲泣鍋。", "蜀姜作芼吳鹽和，琥珀香爛雲子烏。", "不數肉甕誇安胡，老妻熱貯兒怒呼。", "饑雷欲轉藜腸枯，政須一飽百不圖。", "君不見牛觳觫，烏畢逋，蟹躁擾，魚喁嚅。", "玉脂泣鼎扤血餬，萬錢方丈胡爲乎。", "莫笑庾郎一事無食鮭，長有二十七種園中蔬。", "催兒掛豆更栽芋，坡老自謂我亦識字耕田夫。"]'),
('fef78d27-d4d9-47b5-b819-add9133cc0d3','放魚歌','徐照','宋','宋诗','song-poetry','','[]','笭箵下北灣，罣䍡上西浦。',96,'全唐诗/poet.song.170000.json','["笭箵下北灣，罣䍡上西浦。", "漁師惡取真少恩，游鱗潛身更何所。", "未死神已泣，口沫自吹吐。", "相失滄波俄頃間，斫雪飛花落盤俎。", "山翁忍見不惜青銅錢，盡買鰣鰅魴鯽鱮。", "我聞清淵之水千尺長，魚乎魚乎慎勿輕行復遭禍。"]'),
('3762b126-899b-4161-bff7-a204b7b6636e','愛梅歌','徐照','宋','宋诗','song-poetry','','["\u897f\u6e56"]','紫琳聯坳蘸黟漆，破帽籠頭醉拈筆。',185,'全唐诗/poet.song.170000.json','["紫琳聯坳蘸黟漆，破帽籠頭醉拈筆。", "解返冰魂化墨僊，青皇盡把韶華失。", "巧分六出騃滕六，迅折千葩怯殷七。", "笑笑先生懶學畫，花光仁老毛欲栗。", "可笑梅山翁，一夜吟詩便來乞。", "無聲與有聲，畫妙詩騷兩清逸。", "見說鵝溪出好絹，誰能爲買三百疋。", "長條短棘椒藟萌，折榦稀枝瘦虬屈。", "畫取西湖三兩朶，摘索映空花不密。", "更畫庾嶺三十本，雪月風煙意非一。", "君不見翰林走旁訪消息，寒城日日騎馿出。", "又不見杜老當年酒不。"]'),
('28d14d9d-14f3-4536-a46d-38d8ccaa21c0','莫愁曲','徐照','宋','宋诗','song-poetry','','[]','莫愁石城住，今來無莫愁。',24,'全唐诗/poet.song.170000.json','["莫愁石城住，今來無莫愁。", "只重石城水，曾汎莫愁舟。"]'),
('275b2cca-695c-4033-830a-b8af1debfd27','三峽吟','徐照','宋','宋诗','song-poetry','','[]','山水七百里，上有青楓林。',24,'全唐诗/poet.song.170000.json','["山水七百里，上有青楓林。", "啼猿不自愁，愁落行人心。"]'),
('402cae89-be0e-40ac-a00a-66420c3145cd','李夫人','徐照','宋','宋诗','song-poetry','','[]','延年有妹顔如花，十四選入君王家。',80,'全唐诗/poet.song.170000.json','["延年有妹顔如花，十四選入君王家。", "翡翠結簾玉鏤牀，君王一時無暫忘。", "朝朝出入芙蓉殿，莫道妾身出微賤。", "妾生未久身入泉，上天何不與妾年。", "君王愛妾言不死，逐夜宮中喚方士。"]'),
('12444da3-969a-4211-88d4-8f80667dc01e','青溪閣','徐照','宋','宋诗','song-poetry','','[]','葉脫林梢處處秋，壯懷易感更登樓。',64,'全唐诗/poet.song.170000.json','["葉脫林梢處處秋，壯懷易感更登樓。", "日斜鍾阜煙凝碧，霜落秦淮水漫流。", "人似仲宣思故國，詩如杜老到夔州。", "十年前作金陵夢，重撫闌干說舊遊。"]'),
('cdc5b71f-98c4-4cf9-9d44-1098b3e4ee77','拔蒲曲','徐照','宋','宋诗','song-poetry','','[]','拔蒲心，葉再抽。',16,'全唐诗/poet.song.170000.json','["拔蒲心，葉再抽。", "拔蒲根，種不留。"]'),
('c998efc1-7275-4ecb-8cb9-b2dfad354969','步虛詞','翁卷','宋','宋诗','song-poetry','','[]','玄根布靈葉，妙化無常人。',72,'全唐诗/poet.song.170000.json','["玄根布靈葉，妙化無常人。", "結茲清陽氣，挺我空洞神。", "煉度得長生，列籍齊衆真。", "登賓玉皇家，執侍羅星嬪。", "欻往宴十洲，飛客成相親。", "茫茫塵中區，荒穢何足鄰。"]'),
('0bc70cb3-f4e3-487a-b1b9-84bf393f7c6b','游仙篇','翁卷','宋','宋诗','song-poetry','','[]','旭日升太虛，流光到萌芽。',84,'全唐诗/poet.song.170000.json','["旭日升太虛，流光到萌芽。", "旁有五雲氣，煥爛含精華。", "所願服食之，躋身眇長霞。", "带我清泠佩，飛我欻忽車。", "寧爲世間游，世道紛以拏。", "三山不足期，千齡詎云賒。", "悟彼勞生人，無異芳春花。"]'),
('9afc62e9-c1cd-4a3b-b6b5-714e43cdb03d','思遠客','翁卷','宋','宋诗','song-poetry','','[]','涉夏思已深，感秋念愈迫。',120,'全唐诗/poet.song.170000.json','["涉夏思已深，感秋念愈迫。", "思念皆爲誰，爲彼遠行客。", "客行曷辰休，悵望朝復夕。", "出門虛有待，命駕焉所適。", "邈邈阻前歡，悠悠抱今戚。", "中庭一株橘，嘉實轉金碧。", "爰意花開時，花邊語離析。", "惜此不忍餐，留之候君摘。", "擬君君未來，囘腸更如折。", "何當乘夢時，儻遂徽容覿。"]'),
('c9a67eb7-ec11-40a8-9aa5-23d44d7b7709','登飛霞山作','翁卷','宋','宋诗','song-poetry','','[]','局居厭紛叢，蕩志尋嶇嶔。',144,'全唐诗/poet.song.170000.json','["局居厭紛叢，蕩志尋嶇嶔。", "拂衣出城隅，杖策循湖陰。", "何年彼真仙，遺宮寄幽岑。", "連樹窈蒙密，靈洞疑虛沈。", "攀條承蘚飆，立石弄澄深。", "眺睞增殊歡，超忽涓煩襟。", "美人逝云遠，青草疇與吟。", "感昔興重嗟，會意良在今。", "山公悅崇資，嵇氏陶清音。", "保真道無違，逐欲情易淫。", "顧乏安期資，華鬢能不侵。", "雖非尚子賢，儻遂畢娶心。"]'),
('262b4ac0-97f3-4515-b053-483fad432fe5','古道','翁卷','宋','宋诗','song-poetry','','[]','古道今不見，今交非古情。',84,'全唐诗/poet.song.170000.json','["古道今不見，今交非古情。", "交情亦何難，難逢雙目明。", "青松生青山，真節莫與并。", "植之廛郭旁，流俗多所輕。", "遠道豈易行，出門悔吝生。", "君看天上雲，何心更營營。", "勿言貧未安，安貧存令名。"]'),
('b1b70991-9239-453c-9b04-70fe7b340a19','和陳待制秋日湖樓宴集篇','翁卷','宋','宋诗','song-poetry','','[]','一夕鳴雨來，秋容變俄頃。',96,'全唐诗/poet.song.170000.json','["一夕鳴雨來，秋容變俄頃。", "湖山屬初霽，風煙带微冷。", "侍臣設芳筵，開樓翫澄景。", "懷我林下人，招携共觀省。", "碧草鋪近洲，白雲冒遥嶺。", "依稀蘭杜香，髣髴瀟湘浄。", "撫化篇忽成，達生累全屏。", "即是造物游，何必神仙境。"]'),
('883c8101-794d-4d15-a192-e07576bfc649','送葉任道','翁卷','宋','宋诗','song-poetry','','["\u8861\u5c71"]','英英橋門彥，聲動翰墨場。',156,'全唐诗/poet.song.170000.json','["英英橋門彥，聲動翰墨場。", "已就沖天翼，如何復低翔。", "茲辰首征途，言尋八桂鄉。", "遠士望模式，會府欽才良。", "莫以瓊樹姿，怨彼霜霰妨。", "委順要達識，沮挫知堅剛。", "改序逢清和，飛花點行裝。", "登涉山川異，經從道路長。", "聽猿過南嶽，採芷沿三湘。", "應懷古騷人，搦筆爲篇章。", "行藏義在需，通塞時靡常。", "大器且自惜，晚成亦何傷。", "蓬瀛幾仙伴，佇子歸班行。"]'),
('c6d4e380-3856-47c0-8da5-0008259a4bad','送戴漢老','翁卷','宋','宋诗','song-poetry','','[]','三洞聳奇秀，雙溪瀉澄鮮。',156,'全唐诗/poet.song.170000.json','["三洞聳奇秀，雙溪瀉澄鮮。", "上有婺女光，照耀無窮年。", "儲靈復産異，人物相比肩。", "君雖生後來，識與先輩連。", "如筠挺脩直，似玉抱貞堅。", "策名甲科上，初仕甌海邊。", "孰云簿領閑，文案方滿前。", "敏手信無敵，虛懷常坦然。", "駕言指歸期，通邑皆拳拳。", "乃知爲政者，何苦用心偏。", "良才世所稀，華職當驟遷。", "願君養盛業，益使芳譽傳。", "明晨潮信來，挂席從中川。"]'),
('9343caaf-b3a5-4438-8fa1-75677fc42ce4','送劉幾道','翁卷','宋','宋诗','song-poetry','','[]','束髮同執經，交分人莫如。',132,'全唐诗/poet.song.170000.json','["束髮同執經，交分人莫如。", "我愚百無成，蹭蹬空林居。", "君文最奇崛，二十魁薦書。", "青衫何太晚，警捕殊區區。", "是月蟬始鳴，秀色連郊墟。", "俶裝趨海邑，指期當憩車。", "老大戀親友，暫別猶欷歔。", "況此一分手，歸期三載餘。", "積雨山川晦，新晴氛霧除。", "殷勤送客吟，摻執行子裾。", "願言乘高風，矯翮凌太虛。"]'),
('e12b66bb-4859-40fc-9aad-ac69400067c5','山中採藥','翁卷','宋','宋诗','song-poetry','','[]','巖崖産靈藥，等閒人顧稀。',108,'全唐诗/poet.song.170000.json','["巖崖産靈藥，等閒人顧稀。", "採掇獲所願，躋登倦忘歸。", "沃葉带露滋，深根涵土肌。", "妍光媚幽笈，芳氣盈我衣。", "濯以清澗泉，曝之太陽暉。", "製治擬如法，服食從所宜。", "除疴養天和，仙方豈吾欺。", "協彼古修意，庶用延將衰。", "將衰儻得延，萬事焉足爲。"]'),
('ab5b85e9-a9cc-42c2-b608-635b3a288404','酬友人','翁卷','宋','宋诗','song-poetry','','[]','常憂別時數，每苦歡事疎。',156,'全唐诗/poet.song.170000.json','["常憂別時數，每苦歡事疎。", "矧茲同心人，契闊三月餘。", "昨日携瘦藤，往訪林間廬。", "差池不一見，出門恨何如。", "今晨蒼童來，贈言委璠璵。", "吟翫弗忍釋，絢彩摇襟裾。", "子有供世才，胡爲未展舒。", "我無資身策，合守貧賤居。", "積疴困疲薾，焉得愁悶除。", "慇懃荷久要，尚肯念到予。", "南枝早梅白，古澗寒流虛。", "明當復相尋，行游带琴書。", "嚼花飲芳泉，哦詩更躊躇。"]'),
('d24cbf85-e4de-4657-bebe-e272e2305ff3','題林遂之真意亭','翁卷','宋','宋诗','song-poetry','','[]','結亭納虛豁，崔嵬進南山。',72,'全唐诗/poet.song.170000.json','["結亭納虛豁，崔嵬進南山。", "南山有佳致，白雲多往還。", "繁英粲秋籬，幽芳復相關。", "濁醪對之飲，超此神慮閑。", "至樂豈外求，妙象非言間。", "妙哉靖節風，千載君能攀。"]'),
('fafa87c9-6de4-4116-89c2-ef878359a77b','呈余伯皋','翁卷','宋','宋诗','song-poetry','','[]','木犀香殘菊花拆，多少秋風吹隴陌。',64,'全唐诗/poet.song.170000.json','["木犀香殘菊花拆，多少秋風吹隴陌。", "我行欲遍江西州，最後方作筠陽客。", "筠陽之州水中隔，古來稱是神仙宅。", "今君住此將二年，應識神仙李八伯。"]'),
('dc69558b-3efc-4aef-9d96-16f7bb61e2bf','寄衣詞','翁卷','宋','宋诗','song-poetry','','[]','手織白紵纖且長，生著宜熱熟宜涼。',64,'全唐诗/poet.song.170000.json','["手織白紵纖且長，生著宜熱熟宜涼。", "以比妾心齊素潔，製成遊子遠衣裳。", "君心相厚未相薄，衣來還得稱君目。", "願君服之無棄捐，映君顔貌長如玉。"]'),
('a8ad2aae-beb0-46a0-928d-262b6f238596','白紵詞','翁卷','宋','宋诗','song-poetry','','[]','翩翩長袖光閃銀，繡羅帳密流香塵。',64,'全唐诗/poet.song.170000.json','["翩翩長袖光閃銀，繡羅帳密流香塵。", "歌分四時舞一色，淥觴傳處馳金輪。", "急竹繁絲互催逼，吳娘嬌濃玉無力。", "呵星喚月留夜長，十二圍屏暖山色。"]'),
('5c096cbd-0d83-46c9-b144-e0ed8c83052a','送陳郎中棅知嚴州','翁卷','宋','宋诗','song-poetry','','[]','頻年經虎害，人望使君來。',48,'全唐诗/poet.song.170000.json','["頻年經虎害，人望使君來。", "地重分旄節，州清管釣臺。", "涼天星象動，吉日印符開。", "帝擢平津策，曾知有用才。"]'),
('3bd28bdd-c01b-4bba-9d2a-96b266b47c86','寄趙靈秀','翁卷','宋','宋诗','song-poetry','','[]','千山落葉深，高樹不藏禽。',48,'全唐诗/poet.song.170000.json','["千山落葉深，高樹不藏禽。", "游子在何處，故人勞此心。", "閑燈妨遠夢，寒雨亂愁吟。", "僧奭曾相約，花時共一尋。"]'),
('a925ca45-e1cb-4b40-992a-e3534d08c419','送人赴沅州任','翁卷','宋','宋诗','song-poetry','','[]','舊貢包茅地，中存古意長。',48,'全唐诗/poet.song.170000.json','["舊貢包茅地，中存古意長。", "去程逢嶽雪，上事带春陽。", "霧結硃砂氣，波流白芷香。", "大夫祠寂寞，煩與奠椒漿。"]'),
('1cd9accb-0652-42ef-a168-8aec5343170c','悼雪菴禪師','翁卷','宋','宋诗','song-poetry','','[]','悟了無生妙，歸空若故鄉。',48,'全唐诗/poet.song.170000.json','["悟了無生妙，歸空若故鄉。", "竹房三尺像，石榻一爐香。", "壞衲猶懸樹，新松忽過牆。", "僧中留不得，幾日爲淒涼。"]'),
('f83bf690-9313-4fb7-934f-c9ee3e92efd4','寄沈洞主','翁卷','宋','宋诗','song-poetry','','[]','想當清夜醮，带月叩仙鐘。',48,'全唐诗/poet.song.170000.json','["想當清夜醮，带月叩仙鐘。", "指上雷霆訣，菴前虎豹蹤。", "藥收陽地草，薪採故枝松。", "擬即尋師去，茅峰疊幾重。"]'),
('04bdb3c5-0322-47d2-a377-7f34f1489229','晚秋送徐璣赴龍溪丞因過泉南舊里','翁卷','宋','宋诗','song-poetry','','[]','卷中風雅句，名匠亦難如。',48,'全唐诗/poet.song.170000.json','["卷中風雅句，名匠亦難如。", "遠邑親微祿，他鄉過舊廬。", "程途多見菊，行李半擔書。", "未信文明代，無人薦子虛。"]'),
('05570349-ec0b-4d67-ad30-8dc00c64c4aa','即事言懷','翁卷','宋','宋诗','song-poetry','','[]','賦得拙疎性，合令縱跡賒。',48,'全唐诗/poet.song.170000.json','["賦得拙疎性，合令縱跡賒。", "相親惟野客，所論是詩家。", "聽雨眠僧屋，看雲立釣槎。", "秋來有新句，多半爲黄花。"]'),
('4245a44f-85eb-4e0e-a167-fa1571a4f013','寄遠人','翁卷','宋','宋诗','song-poetry','','[]','秋氣日淒清，秋衣紉未成。',48,'全唐诗/poet.song.170000.json','["秋氣日淒清，秋衣紉未成。", "在家猶不樂，行路若爲情。", "幾處好山色，暮天羣雁聲。", "分明相憶夢，夜夜出江城。"]'),
('dd7649db-791d-42de-be81-35dcb454d757','太平山讀書奉寄城間諸友','翁卷','宋','宋诗','song-poetry','','[]','寥寥鐘磬音，永日在空林。',48,'全唐诗/poet.song.170000.json','["寥寥鐘磬音，永日在空林。", "多見僧家事，深便靜者心。", "虛亭雲片泊，側徑石根侵。", "此去城間遠，君應嬾出尋。"]'),
('dd99f0d4-347c-416e-90df-f65ecc56cf85','冬日過道上人舊房','翁卷','宋','宋诗','song-poetry','','[]','已知超衆相，假質任成灰。',48,'全唐诗/poet.song.170000.json','["已知超衆相，假質任成灰。", "房是他僧住，門無舊客來。", "冰乾半池水，花落一根梅。", "猶是疑行脚，何年見却囘。"]'),
('839c484c-05cb-4334-9a3b-4ac25af67850','送趙紫芝爲江東從事','翁卷','宋','宋诗','song-poetry','','[]','非惟篇翰奇，吏道更深知。',48,'全唐诗/poet.song.170000.json','["非惟篇翰奇，吏道更深知。", "山水六朝地，登臨三考時。", "泥沙多舊物，風日少全碑。", "正屬黄花發，愁聞有別離。"]'),
('a90724ab-9669-4118-b510-b18c24690849','春日和劉明遠','翁卷','宋','宋诗','song-poetry','','[]','不奈滴簷聲，風囘昨夜晴。',48,'全唐诗/poet.song.170000.json','["不奈滴簷聲，風囘昨夜晴。", "一階春草碧，幾片落花輕。", "知分貧堪樂，無營夢亦清。", "看君話幽隠，如我願逃名。"]'),
('af374886-7e58-4430-ac17-e968165948d5','送薛子舒赴華亭船官','翁卷','宋','宋诗','song-poetry','','[]','君到雲間日，應分二陸名。',48,'全唐诗/poet.song.170000.json','["君到雲間日，應分二陸名。", "縣圖山色少，井味海潮并。", "剡局三年印，春風半月程。", "野人因買鶴，曾向此中行。"]'),
('60cb8fd1-8976-48a0-9c9a-bfa5146bbfc0','送包釋可撫機','翁卷','宋','宋诗','song-poetry','','[]','州带福星明，君今指去程。',48,'全唐诗/poet.song.170000.json','["州带福星明，君今指去程。", "亂山秋雨後，一路野蟬鳴。", "時靜軍書少，人閒官況清。", "歸來話風土，盡識荔枝名。"]'),
('2d259849-ace3-4dd1-8573-6ed9220e27b5','喜蔣德瞻還里','翁卷','宋','宋诗','song-poetry','','[]','爲官三載餘，所得是清虛。',48,'全唐诗/poet.song.170000.json','["爲官三載餘，所得是清虛。", "學就金丹法，修成玉檢書。", "乍歸人客滿，久出竹林疎。", "怪我吟髭白，相歡相見初。"]'),
('972dfaf4-e7b1-448c-b2aa-f3adcddf994f','送趙嗣勳','翁卷','宋','宋诗','song-poetry','','["\u592a\u6e56"]','休思孤嶼峰，且往看吳中。',48,'全唐诗/poet.song.170000.json','["休思孤嶼峰，且往看吳中。", "一片太湖色，遠涵秋氣空。", "藕塘南北棹，蘆港去來鴻。", "入幕多僚屬，惟君事不同。"]'),
('1dde53c7-cfa4-421b-8de5-8fe4cd5b972c','過太湖','翁卷','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','水跨三州地，蘇州水最多。',48,'全唐诗/poet.song.170000.json','["水跨三州地，蘇州水最多。", "昔年僧爲說，今日自經過。", "亡國豈無恨，漁人休更歌。", "洞庭山一抹，翠靄白雲和。"]'),
('74ba9764-b14e-43b1-a144-977f1c0add5e','信州草衣寺','翁卷','宋','宋诗','song-poetry','','[]','簷多山鳥啼，山外玉爲溪。',48,'全唐诗/poet.song.170000.json','["簷多山鳥啼，山外玉爲溪。", "林樹若又長，塔峰應更低。", "數僧歸似客，一佛壞方泥。", "宴坐當時事，廊碑具刻題。"]'),
('fbfd52c9-57bb-4532-9cd7-78ae02c349ab','宿鄔子寨下','翁卷','宋','宋诗','song-poetry','','[]','已謁龍君廟，明朝早過湖。',48,'全唐诗/poet.song.170000.json','["已謁龍君廟，明朝早過湖。", "傍沙船盡泊，經火地多枯。", "秋至昏星易，空長楚月孤。", "蕭條村戍內，更點有如無。"]'),
('9835f812-3785-4ccf-b4d9-38b9d254bf34','同趙靈芝杜子野游豫章總持寺','翁卷','宋','宋诗','song-poetry','','[]','滿寺是秋風，吹開黄菊叢。',48,'全唐诗/poet.song.170000.json','["滿寺是秋風，吹開黄菊叢。", "重林無日到，此地若山中。", "罷磬孤僧出，看碑兩客同。", "相傳化龍事，神怪理難通。"]'),
('99bddd5f-b3e0-4358-86fd-1da9cc6aa904','酬杜子野','翁卷','宋','宋诗','song-poetry','','[]','千葩開欲休，獨客思悠悠。',48,'全唐诗/poet.song.170000.json','["千葩開欲休，獨客思悠悠。", "江水能相隔，春風不共遊。", "數篇詩未答，一幅信重收。", "多少懷君意，鶑聲高樹頭。"]'),
('c3a78db7-ed86-4458-85e0-d80b78e05bc2','贈張亦','翁卷','宋','宋诗','song-poetry','','[]','興兵又罷兵，策士恥無名。',48,'全唐诗/poet.song.170000.json','["興兵又罷兵，策士恥無名。", "閑見秋風起，猶生萬里情。", "借窗臨水歇，沽酒對花傾。", "示我新詩卷，如編衆玉成。"]'),
('68f40178-f78b-4444-9d45-868b7d883cf6','寄葛天民','翁卷','宋','宋诗','song-poetry','','[]','常日已清癯，那兼疾未除。',48,'全唐诗/poet.song.170000.json','["常日已清癯，那兼疾未除。", "傳來五字好，吟了半年餘。", "鐵柱仙人觀，梅花處士廬。", "江湖正相隔，歲晚更愁予。"]'),
('a18014c6-6f6c-46fd-9403-5902acee1615','送盧主簿歸吳','翁卷','宋','宋诗','song-poetry','','[]','湖波長浩蕩，苑綠遍幽奇。',48,'全唐诗/poet.song.170000.json','["湖波長浩蕩，苑綠遍幽奇。", "皆是全吳地，今非昔代時。", "鴟夷無舊舸，泰伯有新祠。", "吟苦曾遊客，因君動遠思。"]'),
('7f4649ba-a0bc-4d3a-8fbb-86b4d0d0b57b','題竹','翁卷','宋','宋诗','song-poetry','','[]','偶種得成陰，翛翛過別林。',48,'全唐诗/poet.song.170000.json','["偶種得成陰，翛翛過別林。", "月寒雙鴿睡，風靜一蟬吟。", "映地添苔碧，臨池覺水深。", "貧居來客少，頼爾慰人心。"]'),
('3d4c126c-1bbb-479c-9e26-debc7aef69eb','曉對','翁卷','宋','宋诗','song-poetry','','[]','獨對曉來晴，天寒景物清。',48,'全唐诗/poet.song.170000.json','["獨對曉來晴，天寒景物清。", "梅花分地落，井氣隔簾生。", "曾是吟招隠，何時遂耦耕。", "蕭疎頭上髮，已白二三莖。"]'),
('81952362-18b2-440f-ac5a-440e4284a1d9','暮春病歸','翁卷','宋','宋诗','song-poetry','','[]','朝朝風景添，吾病亦開簾。',48,'全唐诗/poet.song.170000.json','["朝朝風景添，吾病亦開簾。", "洗藥花前曬，傳方壁上黏。", "力微還省語，身老更看髯。", "昨日林僧至，茶杯始一拈。"]'),
('4d40add4-31c5-41f2-ba4a-28ab88735c99','送徐靈淵永州司理','翁卷','宋','宋诗','song-poetry','','[]','君向零陵日，分携又雪天。',48,'全唐诗/poet.song.170000.json','["君向零陵日，分携又雪天。", "地遥行幾郡，官小度三年。", "蘭芷芳條潔，瀟湘翠色連。", "從來苦吟思，歸賦若多篇。"]'),
('84717ce7-e609-4f85-9db8-afe5eed66641','中秋步月','翁卷','宋','宋诗','song-poetry','','[]','幽興苦相引，水邊行復行。',48,'全唐诗/poet.song.170000.json','["幽興苦相引，水邊行復行。", "不知今夜月，曾動幾人情。", "光逼流螢斷，寒侵宿鳥驚。", "欲歸猶未忍，清露滴三更。"]'),
('7dc4b453-0d46-46ee-b98a-e613d603acbc','道上人房老梅','翁卷','宋','宋诗','song-poetry','','[]','孤高不受埃，老怪昔誰栽。',48,'全唐诗/poet.song.170000.json','["孤高不受埃，老怪昔誰栽。", "仙魄乘槎去，龍身带雪來。", "數枝寒照水，一點浄沾苔。", "頭白狂詩客，花時屢往囘。"]'),
('a766b83b-5a13-4ecf-a1ab-72304bca7228','寄永州徐三掾曹','翁卷','宋','宋诗','song-poetry','','[]','聞說居官處，千峰近九疑。',48,'全唐诗/poet.song.170000.json','["聞說居官處，千峰近九疑。", "合流皆楚水，高石半唐碑。", "香草寒猶綠，清猿夜更悲。", "其中多隠者，君去得逢誰。"]'),
('bb4696b7-ec40-4268-87be-f6ff41ba7ed2','書隠者所居','翁卷','宋','宋诗','song-poetry','','[]','百事已無機，空林不掩扉。',48,'全唐诗/poet.song.170000.json','["百事已無機，空林不掩扉。", "蜂沾朝露出，鶴带晚雲歸。", "石老苔爲貌，松寒薜作衣。", "山翁與漁父，相過轉依依。"]'),
('44ea7975-e691-4ef8-b3f3-b4f154f9f4a6','贈不食姑','翁卷','宋','宋诗','song-poetry','','[]','嫁時衣尚著，忽自欲通仙。',48,'全唐诗/poet.song.170000.json','["嫁時衣尚著，忽自欲通仙。", "終日常持呪，經年只飲泉。", "瘦形非是病，怪語却如顛。", "金母還知爾，招邀歸洞天。"]'),
('6b512aed-44a3-4ce9-8770-88dcdf66c0d8','送奭公抄化','翁卷','宋','宋诗','song-poetry','','[]','一錫出林去，風霜前路寒。',48,'全唐诗/poet.song.170000.json','["一錫出林去，風霜前路寒。", "自言緣事了，方得此身安。", "飄葉隨禪步，饑禽傍野餐。", "舊房惟有佛，開著任人看。"]'),
('51be7396-4adf-4dc2-a568-057dadbde3f0','能仁寺','翁卷','宋','宋诗','song-poetry','','[]','芙蓉峰入天，寺與此峰連。',48,'全唐诗/poet.song.170000.json','["芙蓉峰入天，寺與此峰連。", "得見是冬月，要來從昔年。", "寒潭盛塔影，古木带厨煙。", "偶值高僧出，禪牀坐默然。"]'),
('1f54a87e-0d9a-46e0-a890-b40c8138065d','贈東庵約公','翁卷','宋','宋诗','song-poetry','','[]','問今年八十，退院久清閑。',48,'全唐诗/poet.song.170000.json','["問今年八十，退院久清閑。", "白雪髭慵剃，青松戶早關。", "取泉來煮茗，與客話遊山。", "弟子何僧是，緇衣多往還。"]'),
('d3c16ab1-aab8-4e65-a182-cb55952e71fa','石門菴','翁卷','宋','宋诗','song-poetry','','[]','山到極深處，石門爲地嵐蒸空寺壞，雪壓小庵清。',46,'全唐诗/poet.song.170000.json','["山到極深處，石門爲地嵐蒸空寺壞，雪壓小庵清。", "果落羣猿拾，林昏獨虎行。", "一僧何所得，高坐若無情。"]'),
('727f0cc0-d8d1-4439-b431-95b2e0ebc3bb','寶冠寺','翁卷','宋','宋诗','song-poetry','','[]','山多猿鳥羣，永日絕囂氛。',48,'全唐诗/poet.song.170000.json','["山多猿鳥羣，永日絕囂氛。", "一澗水流出，幾房僧共聞。", "拄筇黏落葉，拂石動寒雲。", "誰昔來營此，尋碑看記文。"]'),
('eb0d2112-74ae-423e-bed4-2cdcb76c23f5','寄山友徐靈暉','翁卷','宋','宋诗','song-poetry','','[]','若非殊俗好，那肯愛幽居。',48,'全唐诗/poet.song.170000.json','["若非殊俗好，那肯愛幽居。", "深徑無來客，空山自讀書。", "樹蟬經雨少，門柳望秋疎。", "相憶何時去，閑園共爾鋤。"]'),
('7b9dcde1-cf37-41b2-b0fa-1d1df85b6a86','陳西老母氏挽詞','翁卷','宋','宋诗','song-poetry','','[]','八十餘年壽，孀居備苦辛。',48,'全唐诗/poet.song.170000.json','["八十餘年壽，孀居備苦辛。", "成家無別物，有子作詩人。", "遠客移書弔，新墳得佛鄰。", "秋堂挂遺像，癯若在時身。"]'),
('2436b94d-6f0f-4421-9fd5-b6468b87cd9a','題常州獨孤檜','翁卷','宋','宋诗','song-poetry','','[]','此檜何時種，相傳是獨孤。',48,'全唐诗/poet.song.170000.json','["此檜何時種，相傳是獨孤。", "年深成古物，名重入州圖。", "老節堅難蠹，皴皮裂似枯。", "託根列帝廟，應不慮樵夫。"]'),
('682ce653-2b9d-4c6e-be2e-5fa0af7876d0','哭徐山民','翁卷','宋','宋诗','song-poetry','','[]','已是窮侵骨，何期早喪身。',48,'全唐诗/poet.song.170000.json','["已是窮侵骨，何期早喪身。", "分明上天意，磨折苦吟人。", "花色連晴晝，鶑聲在近鄰。", "誰憐三尺像，猶带瘦精神。"]'),
('423bd662-6ae8-4af1-af32-0db751b660ad','秋日閑居呈趙端行','翁卷','宋','宋诗','song-poetry','','[]','閑居觀物化，幾葉又飛東。',48,'全唐诗/poet.song.170000.json','["閑居觀物化，幾葉又飛東。", "清氣全歸月，寒聲半是風。", "病多憐骨瘦，吟苦笑身窮。", "折得鄰家菊，還思靖節翁。"]'),
('adc29b0e-c8c2-4c74-9ddf-ab627397db33','送姚主簿歸龍溪','翁卷','宋','宋诗','song-poetry','','[]','三考今批足，應無愧此心。',48,'全唐诗/poet.song.170000.json','["三考今批足，應無愧此心。", "只將零月俸，買得一張琴。", "歸處路猶遠，到時冬必深。", "邑丞詩極好，閑暇可相尋。"]'),
('7f364f57-0415-4e6f-a691-32e988e2aaae','送蔣德瞻節推','翁卷','宋','宋诗','song-poetry','','[]','八百里重湖，長涵太古波。',48,'全唐诗/poet.song.170000.json','["八百里重湖，長涵太古波。", "君山雲出少，夢澤雨來多。", "才子今方去，名樓必屢過。", "楚辭休要學，易得怨傷和。"]'),
('b14236aa-6ba8-4d0b-8721-160b47515cc0','贈滕處士','翁卷','宋','宋诗','song-poetry','','[]','識君戎馬際，今叉十年餘。',48,'全唐诗/poet.song.170000.json','["識君戎馬際，今叉十年餘。", "環海纔安息，先生便隠居。", "清風三畝宅，白日一牀書。", "長是閒門掩，鄰僧亦不如。"]'),
('a5b90404-4796-4855-8a5a-6f85f5260d59','送趙明叔明府','翁卷','宋','宋诗','song-poetry','','[]','隨行惟一琴，前路足幽尋。',48,'全唐诗/poet.song.170000.json','["隨行惟一琴，前路足幽尋。", "今夜維舟處，何村隔樹林。", "鴻聲秋浦冷，雨氣海山深。", "若問三年政，知君盡此心。"]'),
('20e0f450-7a07-44f9-aa68-edf1a657b6bf','初晴道中','翁卷','宋','宋诗','song-poetry','','[]','初晴殘濕在，衆樹碧光鮮。',48,'全唐诗/poet.song.170000.json','["初晴殘濕在，衆樹碧光鮮。", "幽鷺窺泉立，閑童跨犢眠。", "依山知有寺，過水恨無船。", "石路是誰作，姓名巖上鎸。"]'),
('b2d9ac83-007e-4fb5-8882-1057bb1cb43c','福州黄檗寺','翁卷','宋','宋诗','song-poetry','','[]','天下兩黄檗，此中山是真。',48,'全唐诗/poet.song.170000.json','["天下兩黄檗，此中山是真。", "碑看前代刻，僧值故鄉人。", "一宿禪房雨，經時客路塵。", "將行更瞻禮，十二祖師身。"]'),
('8b54d389-bb48-4c9e-b612-1803f675302b','送翁應叟','翁卷','宋','宋诗','song-poetry','','[]','逢君亦姓翁，莫即是吾宗。',48,'全唐诗/poet.song.170000.json','["逢君亦姓翁，莫即是吾宗。", "遠自刺桐里，來看孤嶼峰。", "雖云相識晚，宛若故情濃。", "囘首秋風路，閩山復幾重。"]'),
('b1c6b8da-ea4c-46cb-96bf-18bb29111dd9','處州蒼嶺','翁卷','宋','宋诗','song-poetry','','[]','步步躡飛雲，初疑夢裏身。',48,'全唐诗/poet.song.170000.json','["步步躡飛雲，初疑夢裏身。", "村雞數聲遠，山舍幾家鄰。", "不雨溪長急，非春樹亦新。", "自從開此嶺，便有客行人。"]'),
('04f5e669-792e-4b11-aeb6-1a61dc5f39f9','題武義趙提幹林亭','翁卷','宋','宋诗','song-poetry','','[]','武陵諸勝狀，如列在簷前。',48,'全唐诗/poet.song.170000.json','["武陵諸勝狀，如列在簷前。", "一郭樓臺日，數村桑柘煙。", "鳥啼春滿谷，秧綠水平田。", "中有漁樵影，吾詩詠不全。"]'),
('12e93ca4-b86a-4775-b10b-f92fa0f0dfa8','春雪','翁卷','宋','宋诗','song-poetry','','[]','疑是梨花發，滿園驚乍看。',48,'全唐诗/poet.song.170000.json','["疑是梨花發，滿園驚乍看。", "不能爲臘瑞，空自作春寒。", "遠遁營巢鵲，深埋吐葉蘭。", "從教豔陽曬，流去作波瀾。"]'),
('96fb276d-fd32-4c4b-a5e2-688658578ab3','即事','翁卷','宋','宋诗','song-poetry','','[]','省飲不成醉，牢愁將奈何。',48,'全唐诗/poet.song.170000.json','["省飲不成醉，牢愁將奈何。", "晚煙雲半雜，春雪雨相和。", "巷濕人行少，空寒雁叫多。", "凭欄思無極，懷古謾悲歌。"]'),
('8046a6f8-800b-4eb2-81ab-bf6aa676c568','題王法師房','翁卷','宋','宋诗','song-poetry','','[]','應有列仙至，觀當靈洞安。',48,'全唐诗/poet.song.170000.json','["應有列仙至，觀當靈洞安。", "月蘿春長蔓，風竹暮生寒。", "印下鬼神役，鼎交龍虎歡。", "尋常應緣外，多把異書看。"]'),
('398ac528-fd06-4b5c-895d-5e12e7c54a9f','贈鮑居士','翁卷','宋','宋诗','song-poetry','','[]','日日湖波畔，羣鷗相共閑。',48,'全唐诗/poet.song.170000.json','["日日湖波畔，羣鷗相共閑。", "全家皆好佛，獨坐或看山。", "曬藥嫌雲在，留僧带月還。", "有時乘小艇，忽入到城間。"]'),
('0bc7057d-fb38-407a-8908-d8919f40ce3c','哭徐璣','翁卷','宋','宋诗','song-poetry','','[]','前時官上歸，感愴失靈暉。',48,'全唐诗/poet.song.170000.json','["前時官上歸，感愴失靈暉。", "不料三年後，俱隨萬化非。", "塔峰長入座，池色自臨扉。", "無復乘閑屐，觀棋訪衲衣。"]'),
('d84ad83f-a2be-41c1-8201-cff18b6867b2','贈孫季蕃','翁卷','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','立談飛絮中，相遇在吳宮。',48,'全唐诗/poet.song.170000.json','["立談飛絮中，相遇在吳宮。", "以我爲生拙，憐君失計同。", "醉酣花落月，吟苦竹摇風。", "自作廬山記，幽奇欲遍窮。"]'),
('a30c01bc-f2eb-4fe3-b3ff-d2d93e48679d','周南仲挽詞','翁卷','宋','宋诗','song-poetry','','[]','志以古人期，今人焉得知。',48,'全唐诗/poet.song.170000.json','["志以古人期，今人焉得知。", "學非無用處，命自不逢時。", "華省官如夢，閑居謗亦隨。", "喪君於此日，師友最相悲。"]'),
('e7b62934-1787-4ead-8007-3eba772757f5','寄張直翁','翁卷','宋','宋诗','song-poetry','','[]','若向筠州去，惟消一日寬。',48,'全唐诗/poet.song.170000.json','["若向筠州去，惟消一日寬。", "又無他事阻，自欲訪君難。", "露下秋山潔，鴻飛楚水寒。", "近詩凡幾首，專待寫來看。"]'),
('0d996b40-d2d3-44ee-b1af-dda43a946452','贈劉高士','翁卷','宋','宋诗','song-poetry','','[]','靈境康廬上，師曾此處家。',48,'全唐诗/poet.song.170000.json','["靈境康廬上，師曾此處家。", "今遊在京國，誰爲管煙霞。", "覓句行逢鶴，持經坐對花。", "笑予非酒戶，相勸滿甌茶。"]'),
('de5e1fd4-cd37-4bb6-b7b7-aa0ecf0fe665','送曹西士宰建昌','翁卷','宋','宋诗','song-poetry','','[]','買得秋風棹，江行不問程。',48,'全唐诗/poet.song.170000.json','["買得秋風棹，江行不問程。", "誰知書判筆，中有惠慈情。", "舊治川僧說，新銜楚吏迎。", "名山皆在望，應費好詩評。"]'),
('b6afbd91-940c-4746-b990-9b785e37ac21','送劉成道','翁卷','宋','宋诗','song-poetry','','[]','客中仍送客，羸病若爲心。',48,'全唐诗/poet.song.170000.json','["客中仍送客，羸病若爲心。", "沿路萬千景，費君多少吟。", "出門梅雨滑，浮棹浙河深。", "莫放旅愁起，聞蟬思舊林。"]'),
('9d37bd76-8bed-48a5-be62-10af3f80837a','舟行寄趙端行','翁卷','宋','宋诗','song-poetry','','[]','離亭一分手，便送釣船行。',48,'全唐诗/poet.song.170000.json','["離亭一分手，便送釣船行。", "雖是暫相別，那能忘此情。", "花飛春已老，雲散晚方晴。", "詩句空吟得，無人可共評。"]'),
('271b0a49-39ba-474d-8969-8dc248b3fcd6','送人遊天台','翁卷','宋','宋诗','song-poetry','','[]','暫遊行李少，幾日到天台。',48,'全唐诗/poet.song.170000.json','["暫遊行李少，幾日到天台。", "船带落潮發，月從前浦來。", "花源香不斷，藥地綠成堆。", "莫學他劉阮，經年忘却囘。"]'),
('b5dc0f07-9033-4b68-a175-6851efa406a9','送徐評事赴省試','翁卷','宋','宋诗','song-poetry','','[]','早年通法後，已是立朝身。',48,'全唐诗/poet.song.170000.json','["早年通法後，已是立朝身。", "更道明經好，須爲擢第人。", "馬寒村驛暮，燈暖帝城春。", "花氣多時節，高門有賀賓。"]'),
('28d0f168-796e-484a-9348-f6ff08e76348','友人林居','翁卷','宋','宋诗','song-poetry','','[]','花石與林廬，皆非俗者居。',48,'全唐诗/poet.song.170000.json','["花石與林廬，皆非俗者居。", "鋪沙爲徑軟，因竹夾籬疎。", "留客同家食，教兒誦古書。", "常言治生意，只欲似樵漁。"]'),
('23c03df7-d403-43ee-98dc-eb524592c166','送吉水包長官','翁卷','宋','宋诗','song-poetry','','[]','不恥身爲令，惟存濟物心。',48,'全唐诗/poet.song.170000.json','["不恥身爲令，惟存濟物心。", "離家春雨足，入境夏苗深。", "吉字水初識，洞巖仙可尋。", "知君修浄化，白日只彈琴。"]'),
('77d471a8-a0f8-497a-aadc-1f62a30c42b5','送趙嗣勳簽書昭慶軍幕','翁卷','宋','宋诗','song-poetry','','[]','當時一萬言，親擢自臨軒。',48,'全唐诗/poet.song.170000.json','["當時一萬言，親擢自臨軒。", "況有從前例，難辭不次恩。", "下峰雲带寺，震澤水浮村。", "多少聞名者，爭來識狀元。"]'),
('f897740c-7c1c-47d9-a318-8671bdf52683','送周子靜桂陽教官','翁卷','宋','宋诗','song-poetry','','[]','魁名人共說，直節世間聞。',48,'全唐诗/poet.song.170000.json','["魁名人共說，直節世間聞。", "遠地今崇學，諸生久待君。", "三湘鴻不到，五嶺路初分。", "閑日登臨作，應題贈屈文。"]'),
('66961997-e5f6-4070-966d-b2b0e8526b3f','京口即事','翁卷','宋','宋诗','song-poetry','','[]','長流當下流，鐵甕此爲州。',48,'全唐诗/poet.song.170000.json','["長流當下流，鐵甕此爲州。", "前代多名迹，閑人欲遍遊。", "夕陽波上寺，明月戍邊樓。", "一曲漁家笛，生予無限愁。"]'),
('c43b6ecf-c020-4339-817e-7e40fcc591b8','贈熊鍊師','翁卷','宋','宋诗','song-poetry','','[]','松邊自掩扉，賣藥罷方歸。',48,'全唐诗/poet.song.170000.json','["松邊自掩扉，賣藥罷方歸。", "教客認仙草，笑人求紫衣。", "惜琴眠處放，玩易語時稀。", "見說沅砂賤，閑身去欲飛。"]'),
('451647dd-55e4-44a1-af45-104f0259c88e','宿寺','翁卷','宋','宋诗','song-poetry','','[]','一宿此禪宮，身同落髮翁。',48,'全唐诗/poet.song.170000.json','["一宿此禪宮，身同落髮翁。", "深窗難得月，老屋易生風。", "燈冷紗光淡，香殘印篆空。", "獨憐吟思苦，妨却夢西東。"]'),
('7438d5d8-59f0-4f30-aed3-daa820ac84c5','留別吳中諸士友','翁卷','宋','宋诗','song-poetry','','[]','羈遊雖不閑，幽思亦相關。',48,'全唐诗/poet.song.170000.json','["羈遊雖不閑，幽思亦相關。", "今日經行處，他宵夢寐間。", "松江雲在水，茂苑樹成山。", "況復多吟客，令人懶欲還。"]'),
('22d58b14-7455-4b65-ac9b-c38343fc87ea','南澗尋韓仲止不遇','翁卷','宋','宋诗','song-poetry','','[]','樹樹有佳陰，山蟬不住吟。',48,'全唐诗/poet.song.170000.json','["樹樹有佳陰，山蟬不住吟。", "掬來南澗水，清若主人心。", "屋上雲飛冷，籬根蘚積深。", "留詩在巖壁，明日更相尋。"]'),
('5219a51a-200c-4f8d-a8e6-00175b4d7905','送于君錫節推','翁卷','宋','宋诗','song-poetry','','[]','歷歷渡遥程，仙山向赤城。',48,'全唐诗/poet.song.170000.json','["歷歷渡遥程，仙山向赤城。", "同爲憶家者，豈不羨君行。", "歲晚梅花白，天寒楚塞清。", "野人詩一首，相送莫言輕。"]'),
('5db35e24-672b-4055-b4e6-df723f942511','贈張韓伯','翁卷','宋','宋诗','song-poetry','','[]','暫得共論文，依然蹤跡分。',48,'全唐诗/poet.song.170000.json','["暫得共論文，依然蹤跡分。", "春來若爲況，避遠不相聞。", "一路水兼石，萬重山隔雲。", "何由比明月，到處可逢君。"]'),
('dd6c7e48-9d32-4393-a2fe-9c91cc249d88','秋居寄西里君','翁卷','宋','宋诗','song-poetry','','[]','每日看山山上立，滿山風日又秋來。',64,'全唐诗/poet.song.170000.json','["每日看山山上立，滿山風日又秋來。", "貧家歲計惟收菊，幽徑時常不掃苔。", "新得酒方思欲試，舊存吟軸見還開。", "涼天在處清如水，能賦慙無宋玉才。"]'),
('d6fe4bc9-8952-46f9-be47-efd72aefab0e','鮑使君閑居','翁卷','宋','宋诗','song-poetry','','[]','吟樓影在湖波上，吟景長從望處生。',64,'全唐诗/poet.song.170000.json','["吟樓影在湖波上，吟景長從望處生。", "疊石擬成幽嶂色，種松移得遠灘聲。", "多諳藥品曾因病，却著荷衣欲避名。", "聞說近來心更靜，案頭惟有一琴橫。"]'),
('c5b03b39-b49c-4f67-aad5-c72978189e72','山中','翁卷','宋','宋诗','song-poetry','','[]','山中凡事幸相宜，第一紅塵免上衣。',64,'全唐诗/poet.song.170000.json','["山中凡事幸相宜，第一紅塵免上衣。", "尋藥每同丹客去，拾薪多趁牧兒歸。", "鳴泉潄石寒蒲潔，宿霧蒸泥早蕨肥。", "不奈鄰峰學禪伴，時時來此叩巖扉。"]'),
('d6a05e89-247d-4a77-8e27-4c50be73e584','行藥作','翁卷','宋','宋诗','song-poetry','','[]','病倦令人懶欲吟，偶因行藥過牆陰。',64,'全唐诗/poet.song.170000.json','["病倦令人懶欲吟，偶因行藥過牆陰。", "煙生園柳暮鴉集，水涸池塘秋草侵。", "有口不須談世事，無機惟合卧山林。", "西風颯颯吹毛骨，且看滿園花似金。"]'),
('1a71686d-94c8-4aee-937a-35a5925f2426','寓南昌僧舍','翁卷','宋','宋诗','song-poetry','','[]','突兀禪宮何代餘，閑同衲客聽鐘魚。',64,'全唐诗/poet.song.170000.json','["突兀禪宮何代餘，閑同衲客聽鐘魚。", "身如野鶴棲無定，愁似頑藤挽不除。", "舊隠定多新長竹，遠交全乏近來書。", "爐香椀茗晴窗下，數軸楞伽屢展舒。"]'),
('d0da47e6-9e35-4751-a119-19547bf86848','留別南昌諸友','翁卷','宋','宋诗','song-poetry','','[]','衰顔怕被青銅見，病骨堪同瘦鶴羣。',64,'全唐诗/poet.song.170000.json','["衰顔怕被青銅見，病骨堪同瘦鶴羣。", "出久併荒幽徑菊，未歸長憶滿山雲。", "春風豈識吟人恨，夜雨頻於客舍聞。", "萬柳百花好時節，別君愁緒亂紛紛。"]'),
('7e801b48-795d-4342-94fd-4a8244a20943','送陳嘉父爲彭澤主簿','翁卷','宋','宋诗','song-poetry','','[]','昔時陶令彈琴縣，今日君爲主簿官。',64,'全唐诗/poet.song.170000.json','["昔時陶令彈琴縣，今日君爲主簿官。", "地勝不嫌清俸薄，政公還得衆人歡。", "江分九派潮常到，嶽沓千峰夏亦寒。", "閑客欲遊遊未得，畫成圖軸乞予看。"]'),
('bdcc849e-2d9d-42aa-87fe-de5b3555efe7','次韻葛天民','翁卷','宋','宋诗','song-poetry','','[]','接得詩來勝接書，憶君情思豁然舒。',64,'全唐诗/poet.song.170000.json','["接得詩來勝接書，憶君情思豁然舒。", "却看城裏誰家竹，又鎖湖邊舊住廬。", "曾有退之憐賈島，豈無得意薦相如。", "欲知別後予蹤跡，只向此江閒釣魚。"]'),
('500344c5-e5c9-40e0-9d34-05cc5425d04a','贈陳管轄','翁卷','宋','宋诗','song-poetry','','[]','一拂清風一袖雲，紫陽容貌鶴精神。',64,'全唐诗/poet.song.170000.json','["一拂清風一袖雲，紫陽容貌鶴精神。", "詩因道進言辭別，丹得師傳火候真。", "廬嶽峰前吟瀑布，渾儀圖上禮星辰。", "我來暫作閑人歇，多謝仙翁相訪頻。"]'),
('e034b8be-1ce0-4619-a341-1bdb3c4e0e22','寄筠州張錄事','翁卷','宋','宋诗','song-poetry','','[]','每到友朋相會地，未嘗一日不思君。',64,'全唐诗/poet.song.170000.json','["每到友朋相會地，未嘗一日不思君。", "小詩曾託鄉僧寄，善政因逢故客聞。", "山上仙蹤丹鼎在，郭邊溪色市橋分。", "公餘若起吟遊興，遊處多應見白雲。"]'),
('ed5e1283-9864-48b8-b1d7-c28a8bb8e833','次徐靈淵韻贈趙靈秀','翁卷','宋','宋诗','song-poetry','','[]','一軸黄庭看不厭，詩囊茶器每隨身。',64,'全唐诗/poet.song.170000.json','["一軸黄庭看不厭，詩囊茶器每隨身。", "三年在任同仙隠，一日還家只舊貧。", "種得溪蒲生似髮，教成野鶴舞如人。", "出門便是登山路，更要遥山翠色勻。"]'),
('be522737-7598-40a0-8db3-5184add823a2','西風','翁卷','宋','宋诗','song-poetry','','[]','一處西風一處愁，又逢鳴雁在滄洲。',32,'全唐诗/poet.song.170000.json','["一處西風一處愁，又逢鳴雁在滄洲。", "芙蓉不分秋蕭索，鬭拆繁紅滿樹頭。"]'),
('fad55836-56cb-4fdb-89ad-9875f37f8f3f','雁池作','翁卷','宋','宋诗','song-poetry','','[]','包家門外柳垂垂，摇蕩春風滿雁池。',32,'全唐诗/poet.song.170000.json','["包家門外柳垂垂，摇蕩春風滿雁池。", "爲是城中最佳處，每經過此立多時。"]'),
('a9957bcc-494c-4981-8837-acae2ba0263b','舍外早梅','翁卷','宋','宋诗','song-poetry','','[]','行遍江村未有梅，一花忽向暖枝開。',32,'全唐诗/poet.song.170000.json','["行遍江村未有梅，一花忽向暖枝開。", "黄蜂何處知消息，便解尋香隔舍來。"]'),
('96b7d3bc-bff1-4ff6-b92d-f7e9098258dc','馮公嶺','翁卷','宋','宋诗','song-poetry','','[]','亂峰千疊拂雲霓，輻合坑崖立似梯。',32,'全唐诗/poet.song.170000.json','["亂峰千疊拂雲霓，輻合坑崖立似梯。", "曾向括州州裏望，衆山却是此山低。"]'),
('7f0d3833-a3ae-4a6a-91c7-106ecc27b834','東陽路傍蠶婦','翁卷','宋','宋诗','song-poetry','','[]','兩鬢樵風一面塵，採桑桑上露沾身。',32,'全唐诗/poet.song.170000.json','["兩鬢樵風一面塵，採桑桑上露沾身。", "相逢却道空辛苦，抽得絲來還別人。"]'),
('849f17ec-bf87-45b5-a2cc-07aee163a292','山雨','翁卷','宋','宋诗','song-poetry','','[]','一夜滿林星月白，且無雲氣亦無雷。',32,'全唐诗/poet.song.170000.json','["一夜滿林星月白，且無雲氣亦無雷。", "平明忽見溪流急，知是他山落雨來。"]'),
('334a0e37-b65f-4927-89e7-f2d72c6ae97e','寄山人徐靈暉','翁卷','宋','宋诗','song-poetry','','[]','只隔煙霞數里間，本期還往共幽閑。',32,'全唐诗/poet.song.170000.json','["只隔煙霞數里間，本期還往共幽閑。", "寧知逸羽飛相背，我入山來君出山。"]'),
('753d604c-6966-4b9f-8383-0ea49027f18f','還家夜同趙端行分韻賦','翁卷','宋','宋诗','song-poetry','','[]','莫怪繁霜滿鬢侵，半年長路幾關心。',32,'全唐诗/poet.song.170000.json','["莫怪繁霜滿鬢侵，半年長路幾關心。", "還家點檢家中物，依舊清風在竹林。"]'),
('5909dcfb-6ccb-41a7-871a-b630dd905ede','東湖行','翁卷','宋','宋诗','song-poetry','','[]','湖水添時宿雨晴，野禽無處不春聲。',32,'全唐诗/poet.song.170000.json','["湖水添時宿雨晴，野禽無處不春聲。", "萬株楊柳青如昨，全是東風染得成。"]'),
('39163939-4f11-4fa8-8b4c-e172fe0e797e','觀落花','翁卷','宋','宋诗','song-poetry','','[]','纔看豔蕾破春晴，又見飛花點點輕。',32,'全唐诗/poet.song.170000.json','["纔看豔蕾破春晴，又見飛花點點輕。", "縱是閑花自開落，東風畢竟亦無情。"]'),
('af47426a-f7dc-402c-84d1-07a8d23cc14f','寄張季思','翁卷','宋','宋诗','song-poetry','','[]','荆吳中隔萬山遥，那得相逢話寂寥。',32,'全唐诗/poet.song.170000.json','["荆吳中隔萬山遥，那得相逢話寂寥。", "長憶梅花好時節，訪君船泊古楓橋。"]'),
('59e46dc0-f1f8-4bdd-8801-02a730ef17a9','題東池','翁卷','宋','宋诗','song-poetry','','[]','一池寒水綠粼粼，池上初梅白未勻。',32,'全唐诗/poet.song.170000.json','["一池寒水綠粼粼，池上初梅白未勻。", "誰念酒旗飛動處，唐朝曾住作詩人。"]'),
('0d891600-036c-4160-b271-0a2921b21f6e','秋懷','翁卷','宋','宋诗','song-poetry','','[]','不管秋天陰復晴，秋懷何處不淒清。',32,'全唐诗/poet.song.170000.json','["不管秋天陰復晴，秋懷何處不淒清。", "江城幾夜無佳月，亦有新詩對雨成。"]'),
('3fdf32a8-5597-432b-9605-be2c8f601607','野望','翁卷','宋','宋诗','song-poetry','','[]','一天秋色冷晴灣，無數峰巒遠近間。',32,'全唐诗/poet.song.170000.json','["一天秋色冷晴灣，無數峰巒遠近間。", "閑上山來看野水，忽於水底見青山。"]'),
('ccec28fe-c27d-48da-87a3-972c401a5426','南塘即事','翁卷','宋','宋诗','song-poetry','','[]','半川寒日滿村煙，紅樹青林古岸邊。',32,'全唐诗/poet.song.170000.json','["半川寒日滿村煙，紅樹青林古岸邊。", "漁子不知何處去，渚禽飛落拗罾船。"]'),
('f2dd02af-21a6-40ac-8f64-a22946f6784a','春登南昌城','翁卷','宋','宋诗','song-poetry','','[]','獨立高城四望低，望中無物不堪題。',32,'全唐诗/poet.song.170000.json','["獨立高城四望低，望中無物不堪題。", "欲知春事幾深淺，芳草青青猶未齊。"]'),
('9b411c51-210e-438a-be1a-5503a498a872','鄉村四月','翁卷','宋','宋诗','song-poetry','','["\u56db\u5e74\u7ea7\u4e0b\u518c", "\u751f\u6d3b", "\u4e61\u6751", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u52b3\u52a8", "\u5b8b\u8bd7"]','綠遍山原白滿川，子規聲裏雨如煙。',32,'全唐诗/poet.song.170000.json','["綠遍山原白滿川，子規聲裏雨如煙。", "鄉村四月閑人少，纔了蠶桑又插田。"]'),
('d27ef3d4-67eb-4bc3-9cf1-1beab35e3238','悼舊呈趙紫芝','翁卷','宋','宋诗','song-poetry','','[]','憶向城南共說詩，山民與我定相隨。',32,'全唐诗/poet.song.170000.json','["憶向城南共說詩，山民與我定相隨。", "如今獨來還獨往，此恨除君人不知。"]'),
('641290b7-2e44-4eb7-8e8e-95d6ba16c1e0','冬日登富覽亭','翁卷','宋','宋诗','song-poetry','','[]','未委海潮水，往來何不閒。',48,'全唐诗/poet.song.170000.json','["未委海潮水，往來何不閒。", "輕烟分近郭，積雪蓋遥山。", "漁舸汀鴻外，僧廊島樹間。", "晚寒難獨立，吟竟小詩還。"]'),
('3323d0d9-3787-4ed1-b78f-6ea49b30d7ba','贈九華李丹士','翁卷','宋','宋诗','song-poetry','','[]','行遍東南地，曾看江水源。',48,'全唐诗/poet.song.170000.json','["行遍東南地，曾看江水源。", "袖藏勾漏藥，身是老君孫。", "去住雲相似，枯榮事不論。", "九華峰最碧，相對舊柴門。"]'),
('fe764bd8-ae79-4f2a-a966-cf4a208a2a59','幽居','翁卷','宋','宋诗','song-poetry','','[]','蓬戶掩還開，幽居稱不才。',48,'全唐诗/poet.song.170000.json','["蓬戶掩還開，幽居稱不才。", "移松連嶠土，買石带溪苔。", "藥信仙方服，衣從古樣裁。", "本無官可棄，何用賦歸來。"]'),
('2548370d-d3e4-4d27-945b-21f2d7efd81f','贈葛天民','翁卷','宋','宋诗','song-poetry','','[]','燕本昔如此，清名千載垂。',48,'全唐诗/poet.song.170000.json','["燕本昔如此，清名千載垂。", "誰將囊米施，自拾束薪炊。", "柳影連山閣，湖波浸竹籬。", "朝昏無別事，只是欲吟詩。"]'),
('80b1e7de-3d68-4ee8-af8f-5a4b978e1c8b','夢回','翁卷','宋','宋诗','song-poetry','','[]','一枕莊生夢，囘來日未衙。',48,'全唐诗/poet.song.170000.json','["一枕莊生夢，囘來日未衙。", "自煎砂井水，更煮岳僧茶。", "宿雨消花氣，驚雷長荻芽。", "故山滄海角，遥念在春華。"]'),
('06eb5872-633c-4f5b-b63e-e0968e498787','寄從善上人','翁卷','宋','宋诗','song-poetry','','[]','數載不相見，師應長閉關。',48,'全唐诗/poet.song.170000.json','["數載不相見，師應長閉關。", "香烟前代寺，秋色五峰山。", "棋進僧誰敵，琴餘鶴共閒。", "幾時重過我，吟話此林間。"]'),
('03783e4b-7b5a-4388-a38c-3ad7bcc9274c','偶題','翁卷','宋','宋诗','song-poetry','','[]','綠樹何稠疊，清風稍羨餘。',48,'全唐诗/poet.song.170000.json','["綠樹何稠疊，清風稍羨餘。", "枕縈雲片片，簾透雨疎疎。", "脩筧通泉壑，殘碑出野鋤。", "丘陵知幾變，耕稼學陶漁。"]'),
('ea140842-0e67-4437-a041-20ff32a0d0f5','泊舟龍游','翁卷','宋','宋诗','song-poetry','','[]','未得橋開鎖，去船難自由。',48,'全唐诗/poet.song.170000.json','["未得橋開鎖，去船難自由。", "渚禽飛入竹，山葉下隨流。", "忽見秋風喜，還成早歲愁。", "卧聞舟子說，明日到衢州。"]'),
('34ab4bfc-1c35-4fea-baa0-b0a040dbe2f7','閩中秋思','翁卷','宋','宋诗','song-poetry','','[]','客愁無定迹，幾處冒風埃。',48,'全唐诗/poet.song.170000.json','["客愁無定迹，幾處冒風埃。", "逢得家鄉便，憑將信息囘。", "海烟蠻樹濕，秋雨瘴花開。", "舊日越王國，吾今身再來。"]'),
('aa68d39e-1f65-4f9a-8db1-d5fd7fd91a32','壽昌道中','翁卷','宋','宋诗','song-poetry','','[]','清遊從此起，過處必須看。',48,'全唐诗/poet.song.170000.json','["清遊從此起，過處必須看。", "背日山梅瘦，隨潮海鴨寒。", "平途迷望闊，峻嶺疾行難。", "聽得居人語，今年冬又殘。"]'),
('c774a0c9-8bee-4da2-a7e9-615fa6eb9d72','周氏東山草堂','翁卷','宋','宋诗','song-poetry','','[]','城隅古謝村，博士草堂存。',48,'全唐诗/poet.song.170000.json','["城隅古謝村，博士草堂存。", "唯見烟霞起，全無市井喧。", "鵲來巢木末，黿出戲蒲根。", "消得吟詩客，凭欄看幾番。"]'),
('4c2c1f44-6560-41ed-bc17-45af72cb0253','同徐道暉趙紫芝泛湖','翁卷','宋','宋诗','song-poetry','','[]','相見即相親，吟壇得幾人。',48,'全唐诗/poet.song.170000.json','["相見即相親，吟壇得幾人。", "扁舟當是日，勝賞共閒身。", "山雨曾添碧，湖風不動塵。", "晚來漁唱起，處處藕花新。"]'),
('df8e8ab0-a7ff-4574-a897-e3f3444f4c1f','玉隆宮周道士自足軒','翁卷','宋','宋诗','song-poetry','','[]','貪得無厭者，應難共此居。',48,'全唐诗/poet.song.170000.json','["貪得無厭者，應難共此居。", "爐中姹女藥，案上老君書。", "花竹庭階潔，風烟戶牖虛。", "道人隨分外，安坐不求餘。"]'),
('2f0c3b6b-3df3-48e3-9bb7-1c9488396cfe','旅泊','翁卷','宋','宋诗','song-poetry','','[]','幾日溪篷下，低垂困水程。',48,'全唐诗/poet.song.170000.json','["幾日溪篷下，低垂困水程。", "喜因山縣泊，略向岸汀行。", "聞笛生羈思，看松減宦情。", "遥知此夜月，必照故山明。"]'),
('f4677037-6b55-49bd-8575-b708d6b5b9be','嶽麓宮道房','翁卷','宋','宋诗','song-poetry','','[]','借問經行處，羣仙第幾家。',48,'全唐诗/poet.song.170000.json','["借問經行處，羣仙第幾家。", "晴簷鳴雪滴，虛砌影梅花。", "香爇何年柏，芽煎未社茶。", "道人三四輩，相對誦南華。"]'),
('cd2bb52c-fba0-4cf9-9dad-ff90279b21eb','贈□□先生','翁卷','宋','宋诗','song-poetry','','[]','隴上窮年不輟耕，風吹糾笠自翾輕。',64,'全唐诗/poet.song.170000.json','["隴上窮年不輟耕，風吹糾笠自翾輕。", "攢眉且復看天醉，枵腹誰能與命爭。", "李實於今難仲子，柳條何似問先生。", "不須遠覓王官谷，雁蕩峰頭雲自橫。"]'),
('3628dc10-4993-45ea-a37a-6eea59862621','尋僧','翁卷','宋','宋诗','song-poetry','','[]','秋凈日暉暉，間行風滿衣。',24,'全唐诗/poet.song.170000.json','["秋凈日暉暉，間行風滿衣。", "尋僧雖不遇，折得菊花歸。"]'),
('a70cd6f8-e703-42a9-8d40-dc4a1fb3c8eb','贈普覺院道上人','翁卷','宋','宋诗','song-poetry','','[]','病來形轉瘦，老忘出家年。',48,'全唐诗/poet.song.170000.json','["病來形轉瘦，老忘出家年。", "對客多無語，貪閑懶赴緣。", "一齋能過日，幾世已修禪。", "住傍觀音閣，門前有井泉。"]'),
('0763288d-9540-41a7-9a55-d48e9af0d817','題定慧寺','翁卷','宋','宋诗','song-poetry','','[]','不知何代寺，寺向一溪分。',48,'全唐诗/poet.song.170000.json','["不知何代寺，寺向一溪分。", "幽磴稀來往，閑僧絕見聞。", "塵昏金佛相，蘚斷石碑文。", "漁子并樵客，爐煙此處焚。"]'),
('12d95c7c-75d6-4d78-aa1c-162a83b8d246','題江心寺','翁卷','宋','宋诗','song-poetry','','[]','名與金山並，僧言景更幽。',48,'全唐诗/poet.song.170000.json','["名與金山並，僧言景更幽。", "寺無雙嶼近，地占一江浮。", "曾是龍爲宅，還疑蜃吐樓。", "他鄉遠歸者，望此得停舟。"]'),
('c9366e02-bf82-4e47-9442-47aff47686a3','壽周少保','翁卷','宋','宋诗','song-poetry','','[]','袖中勳業拂雲煙，筆底文章響澗泉。',64,'全唐诗/poet.song.170000.json','["袖中勳業拂雲煙，筆底文章響澗泉。", "已是貴爲天下宰，不妨長作地行仙。", "蟻浮玉斝秋初熟，鵲報銀河月正圓。", "滿飲壽觴今夜看，相星重入太微躔。"]'),
('5e7b884d-3df3-4477-a05a-24ac14d98292','句  其一','翁卷','宋','宋诗','song-poetry','','[]','留客看花賦詩坐。',8,'全唐诗/poet.song.170000.json','["留客看花賦詩坐。"]'),
('c5f50a27-cdfb-4681-a028-e23be499c674','句  其二','翁卷','宋','宋诗','song-poetry','','[]','獨自卷簾樓上望。',8,'全唐诗/poet.song.170000.json','["獨自卷簾樓上望。"]'),
('43620ed5-4328-4167-8ee2-8472a0ef3fee','句  其三','翁卷','宋','宋诗','song-poetry','','[]','梅花處處妍。',6,'全唐诗/poet.song.170000.json','["梅花處處妍。"]'),
('bbafb204-8bc1-4895-93fe-a5f1400d38dc','句  其四','翁卷','宋','宋诗','song-poetry','','[]','官歷春猶淺。',6,'全唐诗/poet.song.170000.json','["官歷春猶淺。"]'),
('2c7a125f-d30d-4904-b0a1-269b5bac88b2','句  其五','翁卷','宋','宋诗','song-poetry','','[]','空把月中枝。',6,'全唐诗/poet.song.170000.json','["空把月中枝。"]'),
('f1729bb8-616e-4d7b-b503-11606dca68ea','句  其六','翁卷','宋','宋诗','song-poetry','','[]','分石同僧坐，看松見鶴來。',12,'全唐诗/poet.song.170000.json','["分石同僧坐，看松見鶴來。"]'),
('6e196140-d224-4469-b333-14fc7ae4db59','游虎邱','余伯皋','宋','宋诗','song-poetry','','[]','纔出閶門望虎邱，馬行衝雨上扁舟。',64,'全唐诗/poet.song.170000.json','["纔出閶門望虎邱，馬行衝雨上扁舟。", "綠楊碧草沿溪岸，白水青苗滿稻疇。", "雲霧黯然方潤溽，山林蕞爾自清幽。", "吳王邱墓分無所，英氣猶依劍石留。"]'),
('d33a3c4f-79be-4ed4-ada7-c36d9f003589','與錢孝先游洞霄  其一','孫元卿','宋','宋诗','song-poetry','','[]','芒鞋踏明月，入谷聞泉聲。',96,'全唐诗/poet.song.170000.json','["芒鞋踏明月，入谷聞泉聲。", "了知非人間，泠然毛骨清。", "篝燈入幽洞，巖穴何陰陰。", "仙凡隔幾塵，無由問霓旌。", "躋攀上高崖，勢與龍虎爭。", "憑欄試撫掌，碧甃波紋生。", "塵緣苦未斷，世路猶遐征。", "題詩來賢巖，晚歲當再行。"]'),
('88fde3df-3cbe-4124-a54b-6574dc2c6d58','與錢孝先游洞霄  其二','孫元卿','宋','宋诗','song-poetry','','[]','玄冥相我作山行，捲却重陰放曉晴。',64,'全唐诗/poet.song.170000.json','["玄冥相我作山行，捲却重陰放曉晴。", "但見峰巒互扃鎖，不知宮闕隠崢嶸。", "雲根洞穴篝燈入，井底波瀾撫掌生。", "喚客入山還送客，淙琤猶記石泉聲。"]'),
('a19c39b1-232b-4553-9713-0be035150b9b','題舫齋','孫元卿','宋','宋诗','song-poetry','','[]','滿船載月華亭子，泛宅浮家張志和。',32,'全唐诗/poet.song.170000.json','["滿船載月華亭子，泛宅浮家張志和。", "何似舫齋趺坐穩，莫教平地起風波。"]'),
('e1aabc77-ecc3-4167-be38-1a56a3fd4d20','妙庭觀  其一','傅誠','宋','宋诗','song-poetry','','[]','會宴瑶池阿母家，九霞光繞翠瓊車。',32,'全唐诗/poet.song.170000.json','["會宴瑶池阿母家，九霞光繞翠瓊車。", "坐中一曲山香舞，帽上看看有落花。"]'),
('35e9f433-a646-41d1-beca-da2fae48319a','妙庭觀  其二','傅誠','宋','宋诗','song-poetry','','[]','天風萬里擁霓旌，紫鳳青鸞上玉京。',32,'全唐诗/poet.song.170000.json','["天風萬里擁霓旌，紫鳳青鸞上玉京。", "故宅一區千古在，夜深惟有月華明。"]'),
('7dabb468-c8e1-49d9-a9fe-e2469b12780f','柳','朱端常','宋','宋诗','song-poetry','','[]','絲絲煙雨弄輕柔，偏稱黄鳥與白鷗。',32,'全唐诗/poet.song.170000.json','["絲絲煙雨弄輕柔，偏稱黄鳥與白鷗。", "纔著一蟬嘶晚日，西風容易便成秋。"]'),
('eb84a26a-7e87-4318-b0ea-357cae5f9496','春晚','于革','宋','宋诗','song-poetry','','[]','舍南舍北草萋萋，原上行人路欲迷。',32,'全唐诗/poet.song.170000.json','["舍南舍北草萋萋，原上行人路欲迷。", "已是春寒仍禁火，楝花風急子規啼。"]'),
('f9842a06-24af-48d3-8d96-2ab7bc6b25fb','詠箋','于革','宋','宋诗','song-poetry','','[]','七八葉蘆秋水裏，兩三個雁夕陽邊。',32,'全唐诗/poet.song.170000.json','["七八葉蘆秋水裏，兩三個雁夕陽邊。", "筆頭到處渾無礙，掃破寒潭一簇烟。"]'),
('fdde2faa-aa12-49d0-a5b8-a5ee30a84685','龍王廟雲平閣','于革','宋','宋诗','song-poetry','','[]','枯梢突兀天風外，翠靄氤氳水石間。',64,'全唐诗/poet.song.170000.json','["枯梢突兀天風外，翠靄氤氳水石間。", "□吏不容今日去，老夫贏得片時閑。", "烟波艇子東西客，霜岸鐘聲上下山。", "解后真成觀物化，白鷗無數舞江灣。"]'),
('cba0944a-db8a-41f3-98af-dc12385992f0','清都觀','于革','宋','宋诗','song-poetry','','[]','石壇雨洗月華新，白帢青藤曳履行。',32,'全唐诗/poet.song.170000.json','["石壇雨洗月華新，白帢青藤曳履行。", "老檜不知仙馭遠，屋頭猶带玉簫聲。"]'),
('72051ed0-44c3-4f37-aa1f-205b83b50eb6','仰止亭','鮑壄','宋','宋诗','song-poetry','','[]','昔年曾此戀青山，幾度秋風入夢寒。',32,'全唐诗/poet.song.170000.json','["昔年曾此戀青山，幾度秋風入夢寒。", "想得玉岑回合處，夕陽依舊滿朱闌。"]'),
('671565f0-18d3-4741-89b6-1cbfc693e802','贈遇上人','鮑壄','宋','宋诗','song-poetry','','[]','一衲一空身，凝然意不分。',48,'全唐诗/poet.song.170000.json','["一衲一空身，凝然意不分。", "愛閒全似我，我累已輸君。", "野寺同聽水，春山獨看雲。", "有疑仍了取，此外不須聞。"]'),
('213be5aa-aab4-43d9-801a-f178ea039fc3','送周子靜分教桂陽','鮑壄','宋','宋诗','song-poetry','','[]','當時身不顧，義激自諸生。',48,'全唐诗/poet.song.170000.json','["當時身不顧，義激自諸生。", "一日魁南省，無人不識名。", "官尋流水住，路趁落花登。", "遥想憑高處，嶽雲千萬層。"]'),
('9d4318f6-5479-425a-807b-97c0e985af32','初夏閒居','鮑壄','宋','宋诗','song-poetry','','[]','杜門初入夏，貧不厭身閒。',48,'全唐诗/poet.song.170000.json','["杜門初入夏，貧不厭身閒。", "白日靜於水，綠陰濃似山。", "野蔬留客飯，小艇送僧還。", "却憶西庵夜，泉聲石壁間。"]'),
('ddb0566c-fff7-441e-ab3b-26765a3fbbf4','游大滌','李廷忠','宋','宋诗','song-poetry','','[]','清溪路入武陵源，雞犬人家隔近村。',64,'全唐诗/poet.song.170000.json','["清溪路入武陵源，雞犬人家隔近村。", "拔地一峰危作柱，棲雲五洞窄開門。", "空庭有客掃松影，古徑無人踏蘚痕。", "我欲白雲巖畔宿，月明一夜聽啼猿。"]'),
('8797c946-6200-4086-b948-e0b71843e861','戚姑山','董居誼','宋','宋诗','song-poetry','','[]','重上危樓意豁然，倚欄檢點舊山川。',64,'全唐诗/poet.song.170000.json','["重上危樓意豁然，倚欄檢點舊山川。", "身離城郭塵囂裏，眼到雲天杳靄邊。", "只恐老松添歲月，長教修竹障風烟。", "回思燈火書窗下，僂指如今六十年。"]'),
('48384792-1564-4393-a5db-6fa1f9e1046d','青雲亭','董居誼','宋','宋诗','song-poetry','','[]','溪傍好山添翠濕，亭依喬木得陰濃。',32,'全唐诗/poet.song.170000.json','["溪傍好山添翠濕，亭依喬木得陰濃。", "有人欲踏青雲路，認取城南第一峰。"]'),
('66481e62-29df-49db-8f69-9e64e79239c0','見山樓下植梅百本九月見花','董居誼','宋','宋诗','song-poetry','','[]','手種寒梅度一春，主人指日是行人。',64,'全唐诗/poet.song.170000.json','["手種寒梅度一春，主人指日是行人。", "孤根奈久不忘舊，疎蕊逢秋已獻新。", "堪笑世情何恁薄，不知花意却相親。", "年年記取栽培力，爲送幽香入夢頻。"]'),
('1e009ab5-8f33-44a8-b22d-500f85fb409a','靈仙觀和危驪塘韻','董居誼','宋','宋诗','song-poetry','','[]','多病侵尋鬢欲秋，自慚何止四宜休。',32,'全唐诗/poet.song.170000.json','["多病侵尋鬢欲秋，自慚何止四宜休。", "青松十里嵩源路，醉倒仙臺是樂丘。"]'),
('45af5d67-8434-4544-a191-99efc7403e72','羣玉山  其一','董居誼','宋','宋诗','song-poetry','','[]','羈寓零陵過一年，每憐兩脚負山川。',32,'全唐诗/poet.song.170000.json','["羈寓零陵過一年，每憐兩脚負山川。", "忽從榛莽窺神祕，似與仙家有宿緣。"]'),
('698bd982-025e-4b91-8dcd-af71c2241c07','羣玉山  其二','董居誼','宋','宋诗','song-poetry','','[]','石刻嘉名歲月多，苔封蘚蠹欲消磨。',32,'全唐诗/poet.song.170000.json','["石刻嘉名歲月多，苔封蘚蠹欲消磨。", "天成有景無人問，不著新亭奈爾何。"]'),
('401a751b-9dd8-42e4-adab-9fe5bdbf4907','羣玉山  其三','董居誼','宋','宋诗','song-poetry','','[]','浮世囂塵不可干，漫山琮璧照人寒。',32,'全唐诗/poet.song.170000.json','["浮世囂塵不可干，漫山琮璧照人寒。", "客來莫認爲頑石，具眼還須作玉看。"]'),
('3398c9c8-a1a4-449b-bdb2-6e00d6b5249f','羣玉山  其四','董居誼','宋','宋诗','song-poetry','','[]','頃年嘗入道山來，天上圖書不受埃。',32,'全唐诗/poet.song.170000.json','["頃年嘗入道山來，天上圖書不受埃。", "今日有懷群玉府，又從人世得蓬萊。"]'),
('bbbe0631-4291-4c7c-823c-c1511ef7c647','羣玉山  其五','董居誼','宋','宋诗','song-poetry','','[]','經臺石磴鬰深幽，曲折中藏自一邱。',32,'全唐诗/poet.song.170000.json','["經臺石磴鬰深幽，曲折中藏自一邱。", "鑿破藩籬都是路，從今任是永人遊。"]'),
('6c5794ce-161e-49f4-a4df-a9bdd0fab7be','平綠軒即事','莫若拙','宋','宋诗','song-poetry','','[]','結屋地猶淺，鈎簾景盡還。',48,'全唐诗/poet.song.170000.json','["結屋地猶淺，鈎簾景盡還。", "嵐光烟樹外，野色酒杯間。", "別墅從渠樂，清吟屬我閒。", "狎鷗時點白，機事不相關。"]'),
('80a010f4-420f-4c8d-aa3d-0f270dcd4dd0','平綠軒','蔡開','宋','宋诗','song-poetry','','[]','瞰水地仍敞，開窗望不迷。',48,'全唐诗/poet.song.170000.json','["瞰水地仍敞，開窗望不迷。", "良疇連遠近，秀野混高低。", "曉起烟千樹，春耕雨一犁。", "道人深樂此，壞衲且幽棲。"]'),
('004a94c0-2337-46c6-a2ca-797be9e58207','題太岳院壁','林焞','宋','宋诗','song-poetry','','[]','我來勸農值春雨，傍人笑我身藍縷。',127,'全唐诗/poet.song.170000.json','["我來勸農值春雨，傍人笑我身藍縷。", "我身藍縷分當然，唯有擔夫愁艱阻。", "汝擔夫，聽我語，桑麻穀粟生於土。", "若非雨澤滋發生，粒食片衣誰付與。", "豈不見田間耕耨人，泥塗深沒股。", "曉露濕雲鬟，歌笑采桑女。", "他時蠶麥倍豐成，羅列甕盎鳴機杼。", "一旦雨濘不爲勞，當念耕農蠶婦終歲服勤苦。"]'),
('b046fd4f-e5bf-430f-8205-52ff11a17ec2','句','趙庚','宋','宋诗','song-poetry','','[]','腰金不足爲公重，懷寶無瑕乃席珍。',16,'全唐诗/poet.song.170000.json','["腰金不足爲公重，懷寶無瑕乃席珍。"]'),
('2449879d-8c3f-4dae-bff3-bb41df3bb67a','鳳凰臺','劉榘','宋','宋诗','song-poetry','','[]','鳳臺何亭亭，迥與雨華對。',216,'全唐诗/poet.song.170000.json','["鳳臺何亭亭，迥與雨華對。", "憑高一登眺，秋事渺無際。", "鷺洲賞心前，牛首秦淮外。", "萬疊雲稼橫，百纜風檣會。", "睠言簿書隙，載酒邀華旆。", "翰林詩百篇，生公法三昧。", "皮膚雖不似，妙趣總相類。", "懷古睇平蕪，可但高李輩。", "憶昔耿與韓，造膝陳大計。", "高光課厥成，一語不相戾。", "江淮今清晏，河路尚腥穢。", "蛇豕相噬吞，天已厭戎裔。", "箕歛民弗堪，惡稔將自斃。", "憤激聞雞舞，慷慨中流誓。", "尺棰仗皇靈，喋血笞其背。", "燕然彼有石，深刻詔來世。", "兵强在食足，萬竈餘廩廥。", "叶奏酇侯功，接武文石陛。"]'),
('66178b35-0d3d-4a05-8df4-fdf3d9aa389b','定林寺','劉榘','宋','宋诗','song-poetry','','[]','聯鑣小憇定林庵，祗欠携壺太子巖。',32,'全唐诗/poet.song.170000.json','["聯鑣小憇定林庵，祗欠携壺太子巖。", "禪律兵機非二致，山僧笑我飽曾參。"]'),
('13b9e4ad-f221-41c8-b8c3-5d47a7039854','羊角由','劉榘','宋','宋诗','song-poetry','','[]','羊角仙人在何許，江南杳靄蒼烟暮。',96,'全唐诗/poet.song.170000.json','["羊角仙人在何許，江南杳靄蒼烟暮。", "空餘拳石在人間，至今指作神仙處。", "當年館宇幻玲瓏，只今阻絕那能逢。", "市上無非神仙輩，人心自隔蓬萊宮。", "我來訪古思綿邈，月滿譙樓夜吹角。", "神仙咫尺不可知，帝鄉汗漫何可期。"]'),
('a4cdcde1-e521-4f1a-bb3e-e7d1bc0bc799','泮林釋奠偶緣攝事遂獲充員竊觀禮文樂奏之盛不勝欣歎輒成小詩奉呈僚友','陳邕','宋','宋诗','song-poetry','','[]','春丁逢上日方中，涓吉修誠薦泮宮。',64,'全唐诗/poet.song.170000.json','["春丁逢上日方中，涓吉修誠薦泮宮。", "奠璧采璘誠可格，代庖越俎數徒充。", "八音合奏東南少，一道相傳今古同。", "我輩因文須識本，浴沂好詠舞雩風。"]'),
('fc821938-6f2a-4e39-9848-ec0a4e4374dd','二月晦游東屯拜少陵像','陳邕','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','飛飛鳴梟啄金屋，孔雀飲泉牛抵觸。',256,'全唐诗/poet.song.170000.json','["飛飛鳴梟啄金屋，孔雀飲泉牛抵觸。", "杜鵑喜免百巢嗔，鷦鷯强息一枝足。", "燭天光焰幾許長，日眩東極升朝陽。", "世人謾作詩老看，肩拍呂葛心羲皇。", "玉珂金鑰裁通籍，錦水銅梁俄浪迹。", "兩河磔裂甲欲洗，四壁呻吟飯無喫。", "萍漂蓬轉客夔門，栖遲瀼西復東屯。", "羣峰竦壁水縈带，有怪膴膴如周原。", "縱橫豺虎深稂莠，熊兒執耒驥子耨。", "除芒落杵未流匙，問有長安消息否。", "峽雲巴月困冥搜，去醉洞庭湘浦秋。", "溪山留得金石響，定應騎氣時神遊。", "捫參歷井甘飛轍，端爲穿花聽鳥設。", "簿書叢裏掣舟來，風雨聲中與春別。", "仰窺層閣俯平川，想見杜曲桑麻田。", "更起鳴酬儻可待，一彈指頃三千年。"]'),
('14781149-5171-4393-bba2-df027b739c12','岑公洞','陳邕','宋','宋诗','song-poetry','','[]','武陵種桃人，香山茹芝老。',96,'全唐诗/poet.song.170000.json','["武陵種桃人，香山茹芝老。", "世變百戰酣，仙境一蹴倒。", "煬虐浮於秦，海宇爭飛䎂。", "人間別有天，海上應無島。", "我行經南浦，奇跡事幽討。", "出門霜落木，呼渡江空潦。", "莫言不能飲，笑起同醉倒。", "何以侑我觴，泉音玉琴操。"]'),
('02acd99b-7746-408b-b173-7cc7449571fe','春波漁市','陳銘','宋','宋诗','song-poetry','','[]','瀕溪有居廛，兩岸舟競檥。',36,'全唐诗/poet.song.170000.json','["瀕溪有居廛，兩岸舟競檥。", "風含水氣腥，曉作漁人市。", "魚羹何處無，無錢買金鯉。"]'),
('b46f3cc3-df5c-42b2-9de8-9c5e0e689240','春月勸農至華林寺','周震','宋','宋诗','song-poetry','','[]','飛廉怒息海天明，十里籃輿出勸耕。',64,'全唐诗/poet.song.170000.json','["飛廉怒息海天明，十里籃輿出勸耕。", "隴麥低頭須雨意，林花仰面笑春晴。", "熙寮連轡勤因事，父老傳杯識至情。", "及物無功慚竊廩，豐年有願是忠誠。"]'),
('8fb2ba7d-e132-4f15-8b1f-e0a3b77f8405','祗園寺','倪祖常','宋','宋诗','song-poetry','','[]','梵王宮殿有仙家，曾此瑶觴醉碧霞。',64,'全唐诗/poet.song.170000.json','["梵王宮殿有仙家，曾此瑶觴醉碧霞。", "雨過石壇寒象緯，風來祇寺委龍蛇。", "經翻貝葉相騰瑞，飯熟青精味勝麻。", "昨日老僧談妙法，繽紛猶自墜天花。"]'),
('952d263b-7834-407f-a7f4-3a351422a1cd','句','龍旦','宋','宋诗','song-poetry','','[]','便作武陵溪上看，春來何處不開花。',16,'全唐诗/poet.song.170000.json','["便作武陵溪上看，春來何處不開花。"]'),
('3d76d9aa-7815-4b17-a884-1175a295ebb6','平綠軒  其一','王用亨','宋','宋诗','song-poetry','','[]','塵囂胸次嘗苦隘，誰謂一隅天地寬。',64,'全唐诗/poet.song.170000.json','["塵囂胸次嘗苦隘，誰謂一隅天地寬。", "野色供餐來几上，山光極目在林端。", "犁耕宿雨春風暖，舟撼清流夜雨寒。", "却笑賀湖臨水寺，閉門不借俗人看。"]'),
('3256c506-27d1-4102-983a-74d55a80da6d','平綠軒  其二','王用亨','宋','宋诗','song-poetry','','[]','禪窗虛敞瞰西南，野色溪光接畫簷。',32,'全唐诗/poet.song.170000.json','["禪窗虛敞瞰西南，野色溪光接畫簷。", "雲去碧天無間斷，一眉依約見山尖。"]'),
('44caed87-3e95-45ac-b7f2-4c377938457b','右石老人','范子長','宋','宋诗','song-poetry','','[]','欹右堂空怒翼垂，清泉赴壑兩魚嬉。',32,'全唐诗/poet.song.170000.json','["欹右堂空怒翼垂，清泉赴壑兩魚嬉。", "道人强欲安樓宇，閑却南邊一半奇。"]'),
('ed6285bd-6cfe-4c45-8e50-38a3952209a7','南亭','范子長','宋','宋诗','song-poetry','','[]','花木精神面面金，誰將好景作南亭。',64,'全唐诗/poet.song.170000.json','["花木精神面面金，誰將好景作南亭。", "栗留枝上春風思，鶗鴂聲中脫屐痕。", "簷後梅樊兄及弟，檻前竹鶴子生孫。", "我今猶是數旬客，遇意忻時即打門。"]'),
('cce42545-7042-42be-aa36-918e30e3c824','別荆州諸友','呂皓','宋','宋诗','song-poetry','','[]','荆州三度別，此別尤酸冷。',216,'全唐诗/poet.song.170000.json','["荆州三度別，此別尤酸冷。", "兼葭逐岸靡，烟雨隔林迴。", "去棹行且留，離觴醉還醒。", "緬懷荆州士，鵠立霜毛整。", "競爽信何人，班班紛脫穎。", "况是清峻流，魁然挈裘領。", "相逢名教樂，殊忘舊機境。", "草木臭味同，何庸强畦畛。", "虎豹識避就，寧忍覆陷穽。", "人情不相遠，頗諒心耿耿。", "眼裏絕荆蓁，夙生何獨幸。", "時恨多曠遠，赧容發面頸。", "分袂復自茲，深淵惜斷綆。", "斷綆無續期，分袂有時并。", "但願各自珍，時當動深省。", "一簣會成山，九仞猶棄井。", "要令百鍊金，青熒無留礦。", "大哉乾坤內，吾道相與永。"]'),
('6dbe8530-421b-4a30-bff0-69aad61db9f0','題青溪神女祠次東坡韻','呂皓','宋','宋诗','song-poetry','','[]','生居萬山中，二年依澤國。',144,'全唐诗/poet.song.170000.json','["生居萬山中，二年依澤國。", "偶於僧曹暇，聊欲訪禪默。", "再拜神女祠，劈山定何術。", "上有琳公巖，作論期破惑。", "只今澄潭中，異影眩莫執。", "宗源人幽窈，峨眉如可及。", "吾聞大地下，出沒水中日。", "胡爲二魶魚，欲歸猶未得。", "變化乘雲雷，那能繫不食。", "山深風竅號，天寒日車急。", "寄語龍宮君，安隠藏故穴。", "近來托怪多，勿遣容易測。"]'),
('2d458b97-881f-4afb-a330-665d0733b160','峨眉亭','呂皓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','采石山頭月正弦，捉月臺邊酒滿船。',96,'全唐诗/poet.song.170000.json','["采石山頭月正弦，捉月臺邊酒滿船。", "擾擾利名蟻慕羶，如公豈但酒稱賢。", "平生醉裏詩三千，捲起長江作長箋。", "悲哉人世隔天淵，一日乘風反自然。", "死生在我不在天，欲死得死豈其冤。", "欲罷長風大放顛，蒼茫何處可拍肩。"]'),
('fde2eae4-570b-4700-804d-af818335158c','過大浪灘','鄭克己','宋','宋诗','song-poetry','','[]','急浪吹飛雪，鳴篙破曉灘。',48,'全唐诗/poet.song.170000.json','["急浪吹飛雪，鳴篙破曉灘。", "異鄉人易老，行路古來難。", "玉露晨初濕，天河夜不乾。", "飄流雙鬢白，未有一枝安。"]'),
('d42e5b3b-6677-437d-8762-ba2ca5f649b8','水閣','鄭克己','宋','宋诗','song-poetry','','[]','水閣臨堤晚，簾鈎暖翠通。',48,'全唐诗/poet.song.170000.json','["水閣臨堤晚，簾鈎暖翠通。", "睡驚鶑去後，夢到蝶邊空。", "春欲從人別，花消昨日紅。", "多情湖上浪，拍拍戀東風。"]'),
('c318d13e-a90e-46d0-b764-ab1bf75b1317','初月','鄭克己','宋','宋诗','song-poetry','','[]','初月當樓動，風簾倚望斜。',48,'全唐诗/poet.song.170000.json','["初月當樓動，風簾倚望斜。", "光虧微有暈，桂薄不成花。", "雲淡明林葉，溪清印岸沙。", "去年寒露白，旅食在京華。"]'),
('c34364ea-6c27-4b0f-920c-6d88f791bc42','水國','鄭克己','宋','宋诗','song-poetry','','["\u897f\u6e56"]','水國烟霞客，春來始定居。',48,'全唐诗/poet.song.170000.json','["水國烟霞客，春來始定居。", "老逢人事懶，貧覺舊交疎。", "隙影窺蟾滴，芸香散篋書。", "西湖風月好，不到一年餘。"]'),
('f29c8d2c-2e1d-428b-82a4-f9ac7b8f7517','送中書王舍人使北虜','鄭克己','宋','宋诗','song-poetry','','[]','細馬縷金鞍，文星使可汗。',48,'全唐诗/poet.song.170000.json','["細馬縷金鞍，文星使可汗。", "袖中天詔重，帳外節毛寒。", "烽火燕城急，塵沙朔野寬。", "安邊在大體，何必斬樓蘭。"]'),
('9c477e57-2a7e-438b-a9a3-145e4d600a1c','飄轉','鄭克己','宋','宋诗','song-poetry','','[]','飄轉未歸客，風帆不夜舟。',48,'全唐诗/poet.song.170000.json','["飄轉未歸客，風帆不夜舟。", "斷雲依水定，薄月带沙流。", "香倚黄花岸，心清白露秋。", "林鴉棲未穩，飛亂北山頭。"]'),
('60fa7b5c-9aa1-4b2c-b1bd-a2c55d0a0325','浙江十六夜對月','鄭克己','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','急槳浮天闊，長江得月遲。',48,'全唐诗/poet.song.170000.json','["急槳浮天闊，長江得月遲。", "最憐新缺後，全勝未圓時。", "夜雪潮千尺，秋風桂一枝。", "潛蛟易翻動，怨笛莫驚吹。"]'),
('b05d61f8-7fa8-4647-933a-cf8f1bb04bf1','架壁','鄭克己','宋','宋诗','song-poetry','','[]','架壁珍藏萬古書，世間清絕在吾廬。',64,'全唐诗/poet.song.170000.json','["架壁珍藏萬古書，世間清絕在吾廬。", "緣瓶香破分家釀，曲圃雲開剪露蔬。", "白日漸隨秋意短，故人盡向老來疎。", "今年種得回蜂菊，亂點東籬玉不如。"]'),
('e796f602-6a10-49be-ab91-67b50230eb9d','青衫','鄭克己','宋','宋诗','song-poetry','','[]','青衫著破禁中羅，楚澤吳江幾度過。',64,'全唐诗/poet.song.170000.json','["青衫著破禁中羅，楚澤吳江幾度過。", "仕宦宛如杯水澹，朝廷空有故人多。", "漁村疎竹明風旆，烟浦斜陽起暮歌。", "欲買田園歸海上，此身無奈客愁何。"]'),
('821ce8d2-58db-4af1-961c-2aba935f75a0','過李老隠居','鄭克己','宋','宋诗','song-poetry','','[]','南渡中興老，幽棲日月長。',48,'全唐诗/poet.song.170000.json','["南渡中興老，幽棲日月長。", "買山供杖履，引水到池塘。", "習懶今成癖，貪盃剩欲狂。", "相過舊賓客，不換野衣裳。"]'),
('5135bbad-68ab-472b-8320-a0d38432cf14','旅中遇故人','鄭克己','宋','宋诗','song-poetry','','[]','雲薄清溪水，天寒黄葉風。',48,'全唐诗/poet.song.170000.json','["雲薄清溪水，天寒黄葉風。", "鄉關三載別，客路一樽同。", "舊事如昨日，問年俱老翁。", "相看今古意，淚冷菊花叢。"]'),
('dc383a36-333d-4aaa-a528-ac171cc9272e','別蔣世修','鄭克己','宋','宋诗','song-poetry','','[]','傳道賢關客，尋山向會稽。',48,'全唐诗/poet.song.170000.json','["傳道賢關客，尋山向會稽。", "春風千里別，花路寸心迷。", "天倚吳江闊，雲隨禹穴低。", "蘭亭得遺墨，爲我好封題。"]'),
('e80a4be5-cafb-4962-8dc0-1e78526df784','繫纜','鄭克己','宋','宋诗','song-poetry','','[]','繫纜縈回浪，昏林入暮鴉。',48,'全唐诗/poet.song.170000.json','["繫纜縈回浪，昏林入暮鴉。", "水窮人有路，天盡客無家。", "蕉葉浮春蟻，魚歌隔浦沙。", "醉眠星斗下，尋夢卜年華。"]'),
('acbba8c0-592a-4551-a178-cfd954c29eb4','憶別','鄭克己','宋','宋诗','song-poetry','','[]','憶別富公子，山桃兩度花。',48,'全唐诗/poet.song.170000.json','["憶別富公子，山桃兩度花。", "人情皆念舊，客路不如家。", "野草連天闊，重山抱日斜。", "寄書無過鴈，愁眼眩飛鴉。"]'),
('dae3350f-a430-4d62-b605-34d304d9e345','蘆花','鄭克己','宋','宋诗','song-poetry','','[]','眇眇臨窗思美人，荻花楓葉带雞聲。',32,'全唐诗/poet.song.170000.json','["眇眇臨窗思美人，荻花楓葉带雞聲。", "夜深吹笛移船去，三十六灣秋月明。"]'),
('e82d616b-4935-4924-be81-caf09adfe34b','釣魚臺','任逢','宋','宋诗','song-poetry','','[]','不慕渭水濱，豈借嚴陵境。',24,'全唐诗/poet.song.170000.json','["不慕渭水濱，豈借嚴陵境。", "巨人留神跡，持竿釣月影。"]'),
('78e45153-3d67-41af-abf2-d56b2fe65005','句','任逢','宋','宋诗','song-poetry','','[]','縱無渭水周家望，合有嚴陵漢室光。',16,'全唐诗/poet.song.170000.json','["縱無渭水周家望，合有嚴陵漢室光。"]'),
('24ae8a13-e38e-4c03-b7b8-c7a929909cec','山茶花  其一','俞國寶','宋','宋诗','song-poetry','','[]','花近東溪居士家，好携樽酒款携茶。',32,'全唐诗/poet.song.170000.json','["花近東溪居士家，好携樽酒款携茶。", "玉皇收拾還天上，便恐筠陽無此花。"]'),
('479f88eb-019b-482c-984a-8952fadb91aa','山茶花  其二','俞國寶','宋','宋诗','song-poetry','','[]','玉潔冰寒自一家，地偏驚此對山花。',32,'全唐诗/poet.song.170000.json','["玉潔冰寒自一家，地偏驚此對山花。", "歸來不負西遊眼，曾識人間未見花。"]'),
('9f0620b2-5a72-40ea-a92d-4f3951ba3a14','寄楊誠齋','羅椿','宋','宋诗','song-poetry','','[]','不愁風月只憂時，髮爲君王寸寸絲。',64,'全唐诗/poet.song.170000.json','["不愁風月只憂時，髮爲君王寸寸絲。", "司馬要爲元祐起，西樞政坐壽皇知。", "苦辭君命驚凡子，清對梅花更與誰。", "夢繞師門三稽首，起敲冰硯訴相思。"]'),
('fef2ad7b-53dc-472e-98e9-3f85382da7b4','送永豐汪令','羅椿','宋','宋诗','song-poetry','','[]','錦纜梅花浦，江南作縣歸。',48,'全唐诗/poet.song.170000.json','["錦纜梅花浦，江南作縣歸。", "新來薦鶚牘，驚動衮龍衣。", "歲晚情難別，心親事却違。", "恐君天上去，扶病出煙霏。"]'),
('94405a38-8e3f-43cd-947a-13b6988902ad','句  其一','羅椿','宋','宋诗','song-poetry','','[]','露濕看花脚，鶑啼欲曉山。',12,'全唐诗/poet.song.170000.json','["露濕看花脚，鶑啼欲曉山。"]'),
('962efcd7-abcd-43f7-a188-bd9efd678e90','句  其二','羅椿','宋','宋诗','song-poetry','','[]','春消千嶂雪，清逼五湖秋。',12,'全唐诗/poet.song.170000.json','["春消千嶂雪，清逼五湖秋。"]'),
('291fb522-94cc-4945-b0b8-acc6bbacc8b0','文昌橋','邱泰','宋','宋诗','song-poetry','','[]','玉馬橫江直接艫，青鼇長此鎮名都。',64,'全唐诗/poet.song.170000.json','["玉馬橫江直接艫，青鼇長此鎮名都。", "川雲占路通三峽，谿雪衝瀾出五湖。", "不媿授書初志遂，每思題柱此才無。", "未須擊楫蒼茫裏，坐見中流出畫圖。"]'),
('b8c3fc6d-05ea-407a-af0a-dde3e2fd8022','句  其一','陳善','宋','宋诗','song-poetry','','[]','春風一日歸深院，巫峽千山鎖暮雲。',16,'全唐诗/poet.song.170000.json','["春風一日歸深院，巫峽千山鎖暮雲。"]'),
('cfec2c1f-fe19-4624-8683-475db3e8cca5','句  其二','陳善','宋','宋诗','song-poetry','','[]','聞說平生輔漢卿，武夷山下啜殘羹。',16,'全唐诗/poet.song.170000.json','["聞說平生輔漢卿，武夷山下啜殘羹。"]'),
('e4e7b857-ab13-46b7-9e42-e53c744ae2bf','句  其三','陳善','宋','宋诗','song-poetry','','[]','不知筋力衰多少，但覺新來嬾上樓。',16,'全唐诗/poet.song.170000.json','["不知筋力衰多少，但覺新來嬾上樓。"]'),
('a89c45f4-f087-40d3-b071-4d5781f98b66','送徐棲霞','周真一','宋','宋诗','song-poetry','','[]','顧我慚稱十高士，與君同是兩閒人。',32,'全唐诗/poet.song.170000.json','["顧我慚稱十高士，與君同是兩閒人。", "君今獨向名山去，說與歸雲我問津。"]'),
('6acf3db0-e22d-42f2-b15e-c3a251bd2ac1','寄陳秋塘','張氏','宋','宋诗','song-poetry','','[]','五湖風雪分頭去，千里淮山信脚行。',64,'全唐诗/poet.song.170000.json','["五湖風雪分頭去，千里淮山信脚行。", "涉世真成妄男子，談詩長憶老先生。", "塘邊瓜茹須頻灌，郭外田疇粗可耕。", "莫倚瘦筇吟白髮，浪傳新句入都城。"]'),
('eb3740c2-4500-4842-96a2-11ca136b44c7','題臨安邸','林升','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u751f\u6d3b", "\u5199\u666f", "\u8bbd\u523a", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7"]','山外青山樓外樓，西湖歌舞幾時休。',32,'全唐诗/poet.song.170000.json','["山外青山樓外樓，西湖歌舞幾時休。", "暖風薰得遊人醉，直把杭州作汴州。"]'),
('ce75c62d-5a13-4efd-89ec-5e134a46ce76','題臞庵','蒙與義','宋','宋诗','song-poetry','','[]','一島風烟水四圍，軒亭窈窕更幽奇。',64,'全唐诗/poet.song.170000.json','["一島風烟水四圍，軒亭窈窕更幽奇。", "眼中泉石論溪買，行處壺觴逐境移。", "倦馬虺隤前日路，寒松偃蹇舊年枝。", "自嗟老去殊癡絕，一月春愁廢作詩。"]'),
('4a25791b-c35c-42d8-b226-282cf0737672','句  其一','朱皆','宋','宋诗','song-poetry','','[]','千金常恨鄰難買，一笑那知蓋已傾。',16,'全唐诗/poet.song.170000.json','["千金常恨鄰難買，一笑那知蓋已傾。"]'),
('8fc792ea-3ee1-41cd-a014-fde67efb6615','句  其二','朱皆','宋','宋诗','song-poetry','','[]','牆東凉月頻留夜，渡口垂楊幾惜春。',16,'全唐诗/poet.song.170000.json','["牆東凉月頻留夜，渡口垂楊幾惜春。"]'),
('0c9dfca1-607d-4287-9a87-25826409e83b','句','許葆光','宋','宋诗','song-poetry','','[]','有官千里再分竹，無地平畦堪種瓜。',16,'全唐诗/poet.song.170000.json','["有官千里再分竹，無地平畦堪種瓜。"]'),
('0b7d5779-5630-4a8b-a620-da026bb0376a','義役','汪師旦','宋','宋诗','song-poetry','','[]','管窺當世務，如見肺與肝。',288,'全唐诗/poet.song.170000.json','["管窺當世務，如見肺與肝。", "惟有差役法，立判最爲難。", "姑以一鄉論，利病胡可殫。", "地里有寬狹，戶籍有耗繁。", "富者産日聚，貧者稅不㨏。", "懦者畏如鼠，强者虎而翰。", "選以流水法，物力匪一般。", "否則白脚差，又有丁戶單。", "齬齟常不齊，可充凡若干。", "今之鳬鶩輩，舞文過於殘。", "往往憑一紙，火急追至官。", "曰汝充保副，詰姦不停鞍。", "曰汝任戶長，催科不容餐。", "稍或稽聽命，怒訶裂巾冠。", "長官一不察，揚波助其瀾。", "箠械微完膚，路行爲悲酸。", "平民如冤苦，回睇生理乾。", "事勢不獲已，交興爭訟端。", "甲尋乙之後，乙搜甲之瘢。", "碎家猶未平，寧復生聚歡。", "仁人一動心，不作秦越看。", "奏曰舉義役，少舒民力刓。", "而我賢令尹，風流謝家蘭。", "和氣春可掬，冰壺照人寒。"]'),
('4107a7d5-40e4-4048-9fdb-920fb8fe250d','石門題壁','徐時','宋','宋诗','song-poetry','','[]','山中薄業有萊田，出入於茲五十年。',64,'全唐诗/poet.song.170000.json','["山中薄業有萊田，出入於茲五十年。", "夾徑兩崖幾蜀道，沿流十度異貪泉。", "鹿門莫遂平生願，屐齒常爲險阻穿。", "晚卜一丘旗嶺上，輞川風月爲留連。"]'),
('6da5ddc5-a2e3-4d1f-b0a4-b43eab1cf9e0','游大滌','姚舜元','宋','宋诗','song-poetry','','[]','此是名山第一宮，仙人何在獨遺蹤。',64,'全唐诗/poet.song.170000.json','["此是名山第一宮，仙人何在獨遺蹤。", "玲瓏兩洞通玄境，突兀一山爲柱峰。", "水泛紅雲出幽谷，風吹蒼雪落長松。", "何時覓得人間暇，徧踏烟嵐翠萬重。"]'),
('4c07b3ed-fea3-4aa1-aecd-215101dbe997','慶侍郎  其一','趙孟僖','宋','宋诗','song-poetry','','[]','不戀持荷侍玉皇，再從均燕似山堂。',32,'全唐诗/poet.song.170000.json','["不戀持荷侍玉皇，再從均燕似山堂。", "世間何物侔清節，照水梅花傲雪霜。"]'),
('13225838-684e-413d-bc1a-4b7fc0934d83','慶侍郎  其二','趙孟僖','宋','宋诗','song-poetry','','[]','去年臘月正茲時，曾逐賓塵獻壽詩。',32,'全唐诗/poet.song.170000.json','["去年臘月正茲時，曾逐賓塵獻壽詩。", "今歲威儀多勝舊，子孫顯達福累□。"]'),
('95ef4e19-7abd-4a17-84e8-90fb8d169cde','慶侍郎  其三','趙孟僖','宋','宋诗','song-poetry','','[]','幸逢八秩慶生申，搦管濡毫灑翰新。',32,'全唐诗/poet.song.170000.json','["幸逢八秩慶生申，搦管濡毫灑翰新。", "十字頂頭添個丿，八千歲壽邁莊椿。"]'),
('e184d609-6e91-4e83-8487-991183efd447','慶侍郎  其四','趙孟僖','宋','宋诗','song-poetry','','[]','渭川此際載非熊，紫詔行頒玉殿東。',32,'全唐诗/poet.song.170000.json','["渭川此際載非熊，紫詔行頒玉殿東。", "正好促裝趨北闕，元正端的拜三公。"]'),
('cc0ec21d-73df-41ac-96b7-555e81a65619','金丹','陳以莊','宋','宋诗','song-poetry','','[]','鳳簫一去幾經年，古木青蘿鎖洞天。',64,'全唐诗/poet.song.170000.json','["鳳簫一去幾經年，古木青蘿鎖洞天。", "黠鬼不量曾竊藥，真人豈礙作飛仙。", "細看丹竈凝烟地，知有清朝應世賢。", "欲下蒼崖却回首，何時著我弄雲泉。"]'),
('445511dd-ebdb-4200-a94b-8e3b66e5551d','春興','陳以莊','宋','宋诗','song-poetry','','[]','輕衫短帽久塵埃，零落香篝媿麝煤。',64,'全唐诗/poet.song.170000.json','["輕衫短帽久塵埃，零落香篝媿麝煤。", "春半工夫花繡了，社邊消息燕銜來。", "豈無綠野供千騎，幸有黄封可一杯。", "明日清明能出否，憑誰先爲掃莓苔。"]'),
('107febac-d68b-459c-9163-e16c511445aa','華延年卜詩','劉夢求','宋','宋诗','song-poetry','','[]','邲鑒總龜如往學，未見才名能廣博。',32,'全唐诗/poet.song.170000.json','["邲鑒總龜如往學，未見才名能廣博。", "希點若來參學時，同年從此不須疑。"]'),
('edc0b6f9-cc91-4e57-ad4e-2096843691f5','華亭百詠 顧亭林','許尚','宋','宋诗','song-poetry','','[]','旦暮潮流急，東西徑路斜。',24,'全唐诗/poet.song.170000.json','["旦暮潮流急，東西徑路斜。", "無從質疑字，共屬野王家。"]'),
('315327c4-643d-4d07-8cd6-156e5c672d49','華亭百詠 顧府君宅','許尚','宋','宋诗','song-poetry','','[]','蕭蕭蘭若地，知是府君居。',24,'全唐诗/poet.song.170000.json','["蕭蕭蘭若地，知是府君居。", "祠事今誰奉，吾來一嘆吁。"]'),
('56e619ef-dbdc-49eb-8957-00fbe157cd81','華亭百詠 東庵異跡','許尚','宋','宋诗','song-poetry','','[]','地勝風雷吼，人疑湧海潮。',24,'全唐诗/poet.song.170000.json','["地勝風雷吼，人疑湧海潮。", "將軍英爽在，何物敢興妖。"]'),
('49546fd5-36ad-44eb-bde1-38fdd867473a','華亭百詠 金山','許尚','宋','宋诗','song-poetry','','[]','激浪聞澎湃，山神陰力多。',24,'全唐诗/poet.song.170000.json','["激浪聞澎湃，山神陰力多。", "風濤歸指顧，海若敢誰何。"]'),
('834c04eb-a168-473a-9d66-64877b8c9423','華亭百詠 安公像','許尚','宋','宋诗','song-poetry','','[]','浮鉢來滄海，幡然厭世塵。',24,'全唐诗/poet.song.170000.json','["浮鉢來滄海，幡然厭世塵。", "補陀崖畔月，長照定中身。"]'),
