('70867258-3bb4-4e54-8349-8ec9f499c76e','華亭百詠 雲閒館','許尚','宋','宋诗','song-poetry','','[]','郵亭臨爽塏，杗廇架修虹。',24,'全唐诗/poet.song.170000.json','["郵亭臨爽塏，杗廇架修虹。", "我亦輪蹄客，心期訪士龍。"]'),
('9642c840-4baa-497a-aa53-459ee1f697e7','華亭百詠 福順廟','許尚','宋','宋诗','song-poetry','','[]','門垣雖蠹壞，古屋尚深沈。',24,'全唐诗/poet.song.170000.json','["門垣雖蠹壞，古屋尚深沈。", "鳥雀猶知避，斯民盍致欽。"]'),
('50f7269d-ceb2-4310-a21f-0dcf1a525cf2','華亭百詠 東嶽行祠','許尚','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','明主東封後，龜蒙望益尊。',24,'全唐诗/poet.song.170000.json','["明主東封後，龜蒙望益尊。", "巍然此行宇，時許薦蘋蘩。"]'),
('8642eb5f-d359-45c9-be9e-8643d637f26b','華亭百詠 西庵','許尚','宋','宋诗','song-poetry','','[]','蚤爲儒冠誤，齊心學竺乾。',24,'全唐诗/poet.song.170000.json','["蚤爲儒冠誤，齊心學竺乾。", "而今林下塔，夜夜戒光圓。"]'),
('b8fe4454-9df3-4d46-b019-b2c939fbf87c','華亭百詠 白龍潭','許尚','宋','宋诗','song-poetry','','[]','神物幽潛地，滄滄水接空。',24,'全唐诗/poet.song.170000.json','["神物幽潛地，滄滄水接空。", "不緣嘗應禱，誰識有殊功。"]'),
('f6f93081-4dbb-4600-a559-6ca88e715e55','華亭百詠 毗盧庵','許尚','宋','宋诗','song-poetry','','[]','捫蘿通一徑，修竹蔽中籬。',24,'全唐诗/poet.song.170000.json','["捫蘿通一徑，修竹蔽中籬。", "只有奎章在，龍神暗護持。"]'),
('c50d8a4b-4a75-4428-97cf-492a344557a4','華亭百詠 西林','許尚','宋','宋诗','song-poetry','','[]','林外初晴後，斜陽滿芰荷。',24,'全唐诗/poet.song.170000.json','["林外初晴後，斜陽滿芰荷。", "頻來指靈鷲，此去路無多。"]'),
('75e5e140-f4e7-427b-b137-e21711235621','華亭百詠 陸瑁養魚池','許尚','宋','宋诗','song-poetry','','[]','誰得陶朱術，修池一水寬。',24,'全唐诗/poet.song.170000.json','["誰得陶朱術，修池一水寬。", "皇恩浹魚鼈，不復敢垂竿。"]'),
('7d5a3855-79ae-4708-8599-4e36c4730a30','華亭百詠 小湖','許尚','宋','宋诗','song-poetry','','[]','獵獵風蒲外，淵淵明月秋。',24,'全唐诗/poet.song.170000.json','["獵獵風蒲外，淵淵明月秋。", "詩翁浮短艇，弭棹看浮鯈。"]'),
('e7321c62-0bf9-499c-9896-af91d4883b1d','華亭百詠 湖橋','許尚','宋','宋诗','song-poetry','','[]','瀲灩湖光好，荷風六月涼。',24,'全唐诗/poet.song.170000.json','["瀲灩湖光好，荷風六月涼。", "倚欄吟不倦，魚鳥亦相忘。"]'),
('26b4fb30-4c82-44c9-b24a-44d9f52a9bc8','華亭百詠 唳鶴灘','許尚','宋','宋诗','song-poetry','','[]','養鶴人何在，湖邊水尚清。',24,'全唐诗/poet.song.170000.json','["養鶴人何在，湖邊水尚清。", "喚回中夜夢，灘上戛然聲。"]'),
('142dfc38-b1dd-4460-94f1-1bacc95e0de1','華亭百詠 泳波亭','許尚','宋','宋诗','song-poetry','','[]','呂梁觀已遠，沂水浴應難。',24,'全唐诗/poet.song.170000.json','["呂梁觀已遠，沂水浴應難。", "却倚亭前柳，時時照影寒。"]'),
('44d8d05b-0f17-48bd-adca-064afc625d00','華亭百詠 風月堂','許尚','宋','宋诗','song-poetry','','[]','夜靜蒲萄皺，雲舒玉鑑涼。',24,'全唐诗/poet.song.170000.json','["夜靜蒲萄皺，雲舒玉鑑涼。", "築堂人不見，樽酒暗相望。"]'),
('523bd57f-d23e-4db7-b4eb-c40dd99fe44f','華亭百詠 湖光亭','許尚','宋','宋诗','song-poetry','','[]','日暮蝦鬚卷，亭中雅燕開。',24,'全唐诗/poet.song.170000.json','["日暮蝦鬚卷，亭中雅燕開。", "微風起蘋末，波影動樽罍。"]'),
('cea6da0f-bdf6-48b8-81f8-24677a330bf7','華亭百詠 道院','許尚','宋','宋诗','song-poetry','','[]','浄觀今何在，唯餘柏色新。',24,'全唐诗/poet.song.170000.json','["浄觀今何在，唯餘柏色新。", "棲棲抱甕者，不是鍊丹人。"]'),
('1b58ad25-de96-44bc-a4fe-216f8ff5e060','華亭百詠 異木','許尚','宋','宋诗','song-poetry','','[]','蟠根知永遠，曲幹聳蛟虬。',24,'全唐诗/poet.song.170000.json','["蟠根知永遠，曲幹聳蛟虬。", "閩賈蒙私庇，年年此薦羞。"]'),
('e07915da-dabf-4721-836c-9f2300576ff0','華亭百詠 顯忠廟','許尚','宋','宋诗','song-poetry','','[]','俯拜祠堂下，遥思弼漢功。',24,'全唐诗/poet.song.170000.json','["俯拜祠堂下，遥思弼漢功。", "吁嗟孝宣帝，忘德太匆匆。"]'),
('66e76acd-6f68-4fe8-a5b0-c9c72bed964d','華亭百詠 東寺','許尚','宋','宋诗','song-poetry','','[]','愛此楞伽士，勤修戒行成。',24,'全唐诗/poet.song.170000.json','["愛此楞伽士，勤修戒行成。", "文龜亦知善，來聽講經聲。"]'),
('39075142-5661-4bc4-a631-15d9f04a8776','華亭百詠 證覺院','許尚','宋','宋诗','song-poetry','','[]','有人明七浄，蠠沒締良因。',24,'全唐诗/poet.song.170000.json','["有人明七浄，蠠沒締良因。", "歎惜流風替，誰爲無垢人。"]'),
('38701566-dfdd-496d-a9a9-a88c1a0fc6c5','華亭百詠 栖真庵','許尚','宋','宋诗','song-poetry','','[]','仙路多官府，真人未上升。',24,'全唐诗/poet.song.170000.json','["仙路多官府，真人未上升。", "松窗霜月白，相對誦黄庭。"]'),
('8c614b62-b8eb-4548-8076-1c4e869c449f','華亭百詠 柳園','許尚','宋','宋诗','song-poetry','','[]','芳草池塘暖，東風桃杏繁。',24,'全唐诗/poet.song.170000.json','["芳草池塘暖，東風桃杏繁。", "春歸人亦散，寂寞鎖園門。"]'),
('96883405-a7af-43c0-b575-1cb423e54d5c','華亭百詠 陸四公廟','許尚','宋','宋诗','song-poetry','','[]','晉傑云亡久，嘉名未遽湮。',24,'全唐诗/poet.song.170000.json','["晉傑云亡久，嘉名未遽湮。", "嚴祠坐遺像，猶解福吳民。"]'),
('e383c7fe-09b3-4f46-8a44-fe3cb25df72b','華亭百詠 南庵','許尚','宋','宋诗','song-poetry','','[]','施水功成後，眈眈梵宇深。',24,'全唐诗/poet.song.170000.json','["施水功成後，眈眈梵宇深。", "升堂瞻貌象，默會祖師心。"]'),
('68a0e09a-38c6-48fc-a8a0-da43f1286c53','華亭百詠 姜庵','許尚','宋','宋诗','song-poetry','','[]','陰曀楸梧裏，鳥鳴落日中。',24,'全唐诗/poet.song.170000.json','["陰曀楸梧裏，鳥鳴落日中。", "九原人不作，明贊亦何功。"]'),
('5c8053f1-1c3e-402a-b28d-84be9945d290','華亭百詠 望仙橋','許尚','宋','宋诗','song-poetry','','[]','鶴駕乘風去，千年竟不歸。',24,'全唐诗/poet.song.170000.json','["鶴駕乘風去，千年竟不歸。", "石梁憑望處，空復白雲飛。"]'),
('f1aed778-0047-4707-ba41-512ae6693727','華亭百詠 三洞庵','許尚','宋','宋诗','song-poetry','','[]','勾曲山頭客，遨遊到市塵。',24,'全唐诗/poet.song.170000.json','["勾曲山頭客，遨遊到市塵。", "星冠頂霜月，夜半正朝真。"]'),
('65546db5-442b-488d-99e1-e7fcdcf57751','華亭百詠 浄居院','許尚','宋','宋诗','song-poetry','','[]','明眼知何在，山門久寂然。',24,'全唐诗/poet.song.170000.json','["明眼知何在，山門久寂然。", "宗風未淪替，還喜一鐙傳。"]'),
('025ea743-cf29-4ca8-86f5-0d586ec05fbe','華亭百詠 冰檗庵','許尚','宋','宋诗','song-poetry','','[]','鳬舄栖遲地，池流一徑斜。',24,'全唐诗/poet.song.170000.json','["鳬舄栖遲地，池流一徑斜。", "先生久清苦，不肯競紛華。"]'),
('4dc9b86e-9e18-4029-9acf-1c93c4a47033','華亭百詠 圓珠庵','許尚','宋','宋诗','song-poetry','','[]','定回人寂靜，繞鼻碧蓮香。',24,'全唐诗/poet.song.170000.json','["定回人寂靜，繞鼻碧蓮香。", "却認循簷月，摩尼發夜光。"]'),
('aba03e44-0004-464f-a838-4e3154ea7194','答曾伯玉借長編二首  其一','黄榦','宋','宋诗','song-poetry','','[]','白露下百草，迅商薄脩林。',72,'全唐诗/poet.song.170000.json','["白露下百草，迅商薄脩林。", "幽人起長懷，感此節物深。", "攬衣自徘徊，撫劍還悲吟。", "丈夫各有志，莫作兒曹心。", "涉遠當疾趨，畏景須就陰。", "願言理輕車，去上南山岑。"]'),
('2607a044-3e0c-4d84-9ce3-6a99f4c2fa76','答曾伯玉借長編二首  其二','黄榦','宋','宋诗','song-poetry','','[]','祥麟踣魯郊，孔袂何漣漣。',72,'全唐诗/poet.song.170000.json','["祥麟踣魯郊，孔袂何漣漣。", "傷哉經濟心，付與文字傳。", "馬公述孔志，托意爲編年。", "是非一以判，纖悉不復捐。", "聞君卧丘壑，繭手磨丹鉛。", "願言得其解，努力希聖賢。"]'),
('5e639fe8-da1e-403a-9802-02f4d80d5e50','紹熙庚戌十月偕趙仲宗舜和潘謙之曾魯仲遊九峰芙蓉壽山紀行十首 九日早登桃枝嶺','黄榦','宋','宋诗','song-poetry','','[]','登山豈不樂，屬此風露清。',120,'全唐诗/poet.song.170000.json','["登山豈不樂，屬此風露清。", "排簷夜雨滴，詰旦天空明。", "歡然金石交，要我林泉盟。", "支筇趁汗漫，勇往不計程。", "一水何縈紆，千峰鬰崢嶸。", "仰視流雲馳，俯聽幽壑鳴。", "班荆得所適，斗酒聊共傾。", "人生會有累，聚散如浮萍。", "今辰諧勝遊，異日難忘情。", "意愜各賦詩，庶以紀此行。"]'),
('e8d6feea-58f2-4585-9422-2eecfc3ad03e','紹熙庚戌十月偕趙仲宗舜和潘謙之曾魯仲遊九峰芙蓉壽山紀行十首 道間觀瀑布','黄榦','宋','宋诗','song-poetry','','[]','行行益以遠，愜此心期幽。',96,'全唐诗/poet.song.170000.json','["行行益以遠，愜此心期幽。", "一徑險復夷，千林密相樛。", "回首天際山，矗面懸飛流。", "銀潢倚石壁，玉龍下山湫。", "光摇日璀璨，勢激水颼飀。", "可望不可親，神往形獨留。", "眷言桃枝山，久矣卜築謀。", "豈無一日閒，努力窮冥搜。"]'),
('c00821e1-2958-47b7-89d2-6782359521c4','紹熙庚戌十月偕趙仲宗舜和潘謙之曾魯仲遊九峰芙蓉壽山紀行十首 夜宿九峰寺','黄榦','宋','宋诗','song-poetry','','[]','冥逐歸雲入遠山，九峰環立似人間。',64,'全唐诗/poet.song.170000.json','["冥逐歸雲入遠山，九峰環立似人間。", "摩挲石刻元和體，矍鑠僧譚宣政間。", "往古來今渾昨夢，隻雞斗酒强開顔。", "明朝酌取龍湫水，直上層霄不復還。"]'),
('9de8fd49-464d-4bba-afbc-e00a12f3bbdf','紹熙庚戌十月偕趙仲宗舜和潘謙之曾魯仲遊九峰芙蓉壽山紀行十首 十日值雨','黄榦','宋','宋诗','song-poetry','','[]','催粥華鯨徹翠微，覺來屋瓦白差差。',64,'全唐诗/poet.song.170000.json','["催粥華鯨徹翠微，覺來屋瓦白差差。", "初疑淡月霜天曉，忽失前山雲幙垂。", "田父腰鎌禾欲耳，行人策杖足如錐。", "老僧莫笑芒鞋苦，破釜生塵儂更悲。"]'),
('a66031a4-4c43-47c6-81c7-4e8757a5f85d','紹熙庚戌十月偕趙仲宗舜和潘謙之曾魯仲遊九峰芙蓉壽山紀行十首 早觀龍湫','黄榦','宋','宋诗','song-poetry','','[]','夜宿羣峰裏，朝遊大石湫。',48,'全唐诗/poet.song.170000.json','["夜宿羣峰裏，朝遊大石湫。", "寒潭飛薄霧，疊障瀉洪流。", "側徑蒼苔滑，叢祠古木幽。", "神龍好高卧，雲雨不勝愁。"]'),
('2cceade5-ad0e-4f95-b39f-daec6a0b4a4d','紹熙庚戌十月偕趙仲宗舜和潘謙之曾魯仲遊九峰芙蓉壽山紀行十首 宿芙蓉寺','黄榦','宋','宋诗','song-poetry','','[]','萬疊雲山踏雨來，白雲依舊冒山隈。',64,'全唐诗/poet.song.170000.json','["萬疊雲山踏雨來，白雲依舊冒山隈。", "尊罍罄盡客懷惡，衣屨沾濡僧意猜。", "默坐香爐煙起伏，喜聞靈洞石崔嵬。", "五更清磬丁東響，參斗橫空天四開。"]'),
('fc94dda9-1269-46b9-9942-fe10948f996c','紹熙庚戌十月偕趙仲宗舜和潘謙之曾魯仲遊九峰芙蓉壽山紀行十首 十一日早登靈洞巖','黄榦','宋','宋诗','song-poetry','','[]','寒巖突兀山之阿，足履危磴攀藤蘿。',128,'全唐诗/poet.song.170000.json','["寒巖突兀山之阿，足履危磴攀藤蘿。", "巖下清泉響環珮，巖前古木交枝柯。", "當中洞門忽開豁，上有石屋高嵯峨。", "乾坤開關已呈露，鬼神守護頻揮呵。", "重門黯淡不可入，以火來照所見多。", "出門小洞亦奇絕，神龍奮怒吞蛟鼉。", "勝景如此難重過，手倚石壁頻摩挲。", "安得雄思如懸河，長吟大詠仍高歌。"]'),
('cb9a3d5a-fbb0-4570-a510-88876cbc2eb3','紹熙庚戌十月偕趙仲宗舜和潘謙之曾魯仲遊九峰芙蓉壽山紀行十首 過翠微院','黄榦','宋','宋诗','song-poetry','','[]','古寺殘僧少，孤村碧樹圍。',24,'全唐诗/poet.song.170000.json','["古寺殘僧少，孤村碧樹圍。", "明朝山下路，愁絕望烟歸。"]'),
('081e4cab-7aec-40a1-ad22-69b6c635e38b','紹熙庚戌十月偕趙仲宗舜和潘謙之曾魯仲遊九峰芙蓉壽山紀行十首 十二日復歸桃枝嶺','黄榦','宋','宋诗','song-poetry','','[]','大溪章溪溪水清，上寮下寮山路平。',192,'全唐诗/poet.song.170000.json','["大溪章溪溪水清，上寮下寮山路平。", "三山屹立相犄角，百里連亙如長城。", "仰干雲霄不盈尺，俯視天高浮寸碧。", "閑雲吞吐溢澗谷，飛泉噴灑下石壁。", "中有一山名芙蓉，端冕正色羣山空。", "望之可敬不可慢，僧言直與衡嶽同。", "坡陀突兀作雲洞，虎豹蹲踞棲鸞鳳。", "聞道前山開闢日，曾住浮屠幾千衆。", "我來已作五日行，皇天一雨復一晴。", "穹林杳靄非人世，手接羣仙上玉京。", "曉來更向山前去，忽到山翁棲隠處。", "却憶桃源洞裏人，日出烟銷忘舊路。"]'),
('01cc35ab-158c-4eb5-86db-f33e10761d69','紹熙庚戌十月偕趙仲宗舜和潘謙之曾魯仲遊九峰芙蓉壽山紀行十首 壽山','黄榦','宋','宋诗','song-poetry','','[]','石爲文多招斧鑿，寺因野燒轉熒煌。',32,'全唐诗/poet.song.170000.json','["石爲文多招斧鑿，寺因野燒轉熒煌。", "世間榮辱不足較，日暮天寒山路長。"]'),
('84ff159a-95ae-4b05-a55d-032b87e0d4d2','凡今之人莫如兄弟詩','黄榦','宋','宋诗','song-poetry','','[]','物理須深玩，人心定不凡。',192,'全唐诗/poet.song.170000.json','["物理須深玩，人心定不凡。", "棣華春競秀，鴻影暮相銜。", "天性人爲貴，同胞豈異心。", "疾行迷後長，思昔更傷今。", "憶昔孩提日，堂前聚戲嬉。", "利心驅逸馬，分背欲何之。", "富貴真餘事，兒孫亦後身。", "四支先自賊，駢拇若爲人。", "矢束折應難，葉密根無托。", "斯道固昭然，歎息人何莫。", "儒衣而儒冠，滿口談詩書。", "君看鬩牆心，異類誠不如。", "我行箕山顛，上有賢弟兄。", "高節振頹俗，餘芳丐後生。", "二父及諸郎，異世真一體。", "賦詩豈遺君，自以警不弟。"]'),
('5342bc0b-4278-4433-a3e3-d97cd4d01197','遊鼓山登大頂峰','黄榦','宋','宋诗','song-poetry','','[]','登山如學道，可進不可已。',180,'全唐诗/poet.song.170000.json','["登山如學道，可進不可已。", "懸崖更千仞，壯志須萬里。", "平生石鼓懷，獨酌靈源水。", "峩峩大頂峰，欲往輒中止。", "今朝復何朝，擊楫渡清泚。", "好風從西來，縹渺吹遊子。", "褰褰涉危巔，萬象得俯視。", "東南際大海，日月旋磨蟻。", "烟雲隔洲渚，歷歷猶可指。", "城中十萬家，囂雜不到耳。", "郊原與廛市，瑣碎如聚米。", "同來皆良儔，得酒共歡喜。", "深林更叫嘯，磐石恣徙倚。", "摩挲陳公碑，歲月爲我紀。", "更持末後句，歸以銘吾几。"]'),
('3c333f4f-1894-48a0-8418-79825ab9c9dd','雙髻峰','黄榦','宋','宋诗','song-poetry','','[]','萬山環立兩山起，伯仲壎箎風味多。',32,'全唐诗/poet.song.170000.json','["萬山環立兩山起，伯仲壎箎風味多。", "軒冕直能驚俗子，采薇千古不消磨。"]'),
('f73e1d4e-60d6-42e0-b3d5-22288e4ef663','侍晦翁飲浮翠用劉叔通韻','黄榦','宋','宋诗','song-poetry','','[]','涼風振幽壑，陰雲翳前山。',84,'全唐诗/poet.song.170000.json','["涼風振幽壑，陰雲翳前山。", "高懷勵清秋，適意林莽間。", "烟橫萬家井，水浄雙溪灣。", "徙倚暮忘歸，人境相與閒。", "遊子獨何爲，千里方言還。", "陪此杖履遊，忘彼道路艱。", "心期更他年，依巖結柴關。"]'),
('4cbd16a2-b44d-4a14-ab66-3872920e866d','讀史記荆卿傳','黄榦','宋','宋诗','song-poetry','','[]','說與男兒莫愛身，簞瓢陋巷不爲貧。',32,'全唐诗/poet.song.170000.json','["說與男兒莫愛身，簞瓢陋巷不爲貧。", "古來亭士君知否，拚得頭顱斫與人。"]'),
('fa466a2f-8fa5-4730-a9fa-faa89e8fc5dc','食竹䶉','黄榦','宋','宋诗','song-poetry','','[]','北山何嗟峨，猛虎之所藏。',156,'全唐诗/poet.song.170000.json','["北山何嗟峨，猛虎之所藏。", "咆哮一震怒，百獸不敢當。", "有竹山之阿，挺挺青琳琅。", "威鳳鳴且棲，衆鳥空回皇。", "彼䶉獨何爲，莫夜爭跳踉。", "鑽山窟穴深，嚙竹根本傷。", "鼠腹漲彭亨，鴟怒獨奮張。", "誰知樵蘇輩，歎彼枝葉黄。", "鋤耰擣其室，束縛登我堂。", "遂令婉孌者，污此牙頰剛。", "才質既不同，分守合有常。", "曷不效爾曹，竊食仍循牆。", "直節永蕭森，庇此千仞岡。"]'),
('9fcbe89c-b793-432c-99a7-04850133af0c','讒人','黄榦','宋','宋诗','song-poetry','','[]','監謗兆周蹙，偶語擠秦亡。',60,'全唐诗/poet.song.170000.json','["監謗兆周蹙，偶語擠秦亡。", "古風下刺上，國步安且强。", "靖康發深痛，熙豐啟餘殃。", "惜哉天子明，未免讒者傷。", "讒者亦何爲，君子名愈彰。"]'),
('41a9b595-3c2d-44b4-b35e-2d7907fd53b0','生平','黄榦','宋','宋诗','song-poetry','','[]','生平因寡合，歲晚交更少。',24,'全唐诗/poet.song.170000.json','["生平因寡合，歲晚交更少。", "非干世俗薄，自是志量小。"]'),
('47f2d194-c07a-430b-b4e7-111636a8eec7','拜文公先生墓下','黄榦','宋','宋诗','song-poetry','','[]','暝投大林谷，晨登崒如亭。',72,'全唐诗/poet.song.170000.json','["暝投大林谷，晨登崒如亭。", "高墳鬰嵯峨，百拜雙淚零。", "白楊自蕭蕭，宿草何青青。", "悲風振林薄，猿鳥爲悲鳴。", "音容久寂寞，欲語誰爲聽。", "空使千載後，儒生抱遺經。"]'),
('eaccf791-10f9-495c-b833-3820fdd80d42','答劉正之見招四絕  其一','黄榦','宋','宋诗','song-poetry','','[]','求田問舍兩參差，木壞山頹萬古悲。',32,'全唐诗/poet.song.170000.json','["求田問舍兩參差，木壞山頹萬古悲。", "多謝劉郎能館我，短檠疎雨聽清規。"]'),
('8a569e53-cfa2-4564-abec-69c5bf524d0b','答劉正之見招四絕  其二','黄榦','宋','宋诗','song-poetry','','[]','昔年曾學屏山下，炯炯胡劉風味長。',32,'全唐诗/poet.song.170000.json','["昔年曾學屏山下，炯炯胡劉風味長。", "滿目青山非故國，人生熟處尚難忘。"]'),
('b23584dd-b2f4-410a-9410-c8168f8dbe99','答劉正之見招四絕  其三','黄榦','宋','宋诗','song-poetry','','[]','君因戇直招時論，我以疎愚厭俗紛。',32,'全唐诗/poet.song.170000.json','["君因戇直招時論，我以疎愚厭俗紛。", "萬事不須開著眼，蒼山白醑對西曛。"]'),
('edf645a0-f97d-4fbc-8a0d-1da0b6cde298','答劉正之見招四絕  其四','黄榦','宋','宋诗','song-poetry','','[]','石馬臺邊森古木，晝寒亭下鎖晴烟。',32,'全唐诗/poet.song.170000.json','["石馬臺邊森古木，晝寒亭下鎖晴烟。", "紫陽不作遠菴死，一醉同君話昔年。"]'),
('03fa9d2c-f169-4646-9b1e-00bd1c500863','讀史戲呈劉正之','黄榦','宋','宋诗','song-poetry','','[]','君不見漢初曹相國，日飲醇酒不事事。',298,'全唐诗/poet.song.170000.json','["君不見漢初曹相國，日飲醇酒不事事。", "相舍後園近吏舍，點吏醉呼不肯避。", "相國取酒飲園後，恨不呼吏與共醉。", "又不見後來丙丞相，馭吏不畏丞相嗔。", "嗜酒酒翻車上茵，醉飽去爾何容身。", "兩公一心相有漢，一夫見辱非吾患。", "但得時平酒價賤，從渠醉後來相慢。", "李斯逐客徒自尊，東門黄犬還悲辛。", "西曹地近不足貴，不過能汙車上茵。", "人言兩公固寬平，我謂兩吏非庸生。", "庸生無益兩丞相，故辱丞相成其名。", "至今漢家四百載，曹獨爲冠丙有聲。", "劉侯劉侯汝太癡，世間曹丙能幾箇。", "但知憤世快我意，醉語誰知官小大。", "却來東屯起田舍，日與田翁相唱和。", "人道劉侯只是一醉人，誰知胸中自有渭與涇。", "一雙怪眼如老鷹，每於醉後白復青。", "劉侯藏鋒斂鍔莫妄用，君家自是提兵冠豸種。"]'),
('1dddf373-7055-44cd-8c26-259e1cec317e','和魏元明四月菊','黄榦','宋','宋诗','song-poetry','','[]','鵜鴂纔鳴歇衆芳，忽看佳菊變秋光。',64,'全唐诗/poet.song.170000.json','["鵜鴂纔鳴歇衆芳，忽看佳菊變秋光。", "江頭雨漲梅同熟，隴上風清麥正黄。", "莫待重陽拚一醉，不愁長夏自微涼。", "籬根休遣兒曹見，又說梨花捧壽觴。"]'),
('3cd82ec6-cae8-4336-b5c2-59bee4d7d593','和劉實之喜雨','黄榦','宋','宋诗','song-poetry','','[]','忽忽久不樂，中腸若焦焚。',216,'全唐诗/poet.song.170000.json','["忽忽久不樂，中腸若焦焚。", "非無一樽酒，高堂細論文。", "塵俗了不知，學殖聊自耘。", "念此農事畢，膏雨猶未均。", "東郊與西疇，禱旱胡紛紛。", "長年四月時，蝸舍嗟梅蒸。", "旱魃逞威虐，暘烏麗朱明。", "風伯真可訟，田祖非無神。", "曷不駕飛龍，一息萬里奔。", "兀坐正長吁，仰瞻白雲屯。", "須臾梧桐上，策策琅玕聲。", "清溪一綫流，澒洞如盆傾。", "只此一日澤，便想百室盈。", "呼童索濁醪，爲我驅愁襟。", "珠玉忽滿前，語句何清新。", "此意久不傳，舉坐爲君興。", "鷄蟲無了時，江閣聊自憑。", "竊恐讀君詩，愁殺閉糴人。"]'),
('b1757bcb-2598-4a49-ba5a-53411a970f75','再和實之喜雨呈正之','黄榦','宋','宋诗','song-poetry','','[]','苦海渺無涯，火宅常自焚。',192,'全唐诗/poet.song.170000.json','["苦海渺無涯，火宅常自焚。", "青衫不療饑，白首非工文。", "勉策疲駑姿，舍己爲人耘。", "造物真小兒，苦樂胡不均。", "突如四月時，梅雨成炎蒸。", "安得玉燭調，一晦復一明。", "中夜忽自悟，感慨若有神。", "有名汝不趨，有利汝不奔。", "獨與迂闊友，卜鄰向東屯。", "燕坐想羲皇，浩歌發商聲。", "床頭有濁醪，嘯詠聊自傾。", "又如苦旱中，一雨澗壑盈。", "草木回春姿，萬象皆更新。", "君今東屯成，拙寢復幾興。", "我亦側西流，草閣時共憑。", "長想千載上，依依耦耕人。"]'),
('da3fff54-25c7-4381-9072-bb3f4c43e164','和劉實之寄生日','黄榦','宋','宋诗','song-poetry','','[]','朝來謾與兒曹語，欲看羣峰插天宇。',144,'全唐诗/poet.song.170000.json','["朝來謾與兒曹語，欲看羣峰插天宇。", "携筇直上君子堂，出門復向東屯去。", "東屯田舍翁，邂逅成賓主。", "謂予始生朝，盃盤各碁布。", "須臾剝啄者爲誰，珠玉懷中來舉似。", "滿堂賓客且停盃，看我蓮桃羅十數。", "感君厚意興轉逸，百斛瓊漿當鯨吸。", "造物亦何意，萬品齊結實。", "休論脩與短，大是空中色。", "但願雙橋茅屋成，款段從君豈終極。"]'),
('70ec2132-ea89-495c-9ac5-7e163c5da2b6','劉正之宜樓四章  其一','黄榦','宋','宋诗','song-poetry','','[]','春風滿庭除，琴瑟亦靜好。',24,'全唐诗/poet.song.170000.json','["春風滿庭除，琴瑟亦靜好。", "甕中有歡伯，相祝以偕老。"]'),
('6cdbfeb6-0059-4155-9d7e-3ce5f7e2a930','劉正之宜樓四章  其二','黄榦','宋','宋诗','song-poetry','','[]','屏山重回首，日暮起長思。',24,'全唐诗/poet.song.170000.json','["屏山重回首，日暮起長思。", "鴻鴈來翩翩，共賦棠棣詩。"]'),
('af670ba1-5d71-4838-bf6d-605aa4ffc22d','劉正之宜樓四章  其三','黄榦','宋','宋诗','song-poetry','','[]','君家兩寧馨，翠竹棲鸞鳳。',24,'全唐诗/poet.song.170000.json','["君家兩寧馨，翠竹棲鸞鳳。", "筦簟燕新居，孔釋復抱送。"]'),
('7859d92e-6d90-486b-b6b2-500f18dd8151','劉正之宜樓四章  其四','黄榦','宋','宋诗','song-poetry','','[]','山以靜故高，水以靜故深。',24,'全唐诗/poet.song.170000.json','["山以靜故高，水以靜故深。", "福祿豈外求，萬感皆人心。"]'),
('fdf86be2-9d11-4435-83cc-538575cc0939','與胡西園','黄榦','宋','宋诗','song-poetry','','[]','白露下百草，玄雲翳崇岡。',216,'全唐诗/poet.song.170000.json','["白露下百草，玄雲翳崇岡。", "遊子暮何之，倏若孤鴈翔。", "朝發長沙渚，夕息湘山陽。", "飛鳴念儔侶，慷慨增悲傷。", "故人懷我深，遠寄金玉章。", "開緘且疾讀，慰此饑渴腸。", "是時焞中火，朔風掃枯黄。", "歲月能幾何，臯蘭結微霜。", "靜觀天地間，至理何昭彰。", "乾行固不息，坤應還無疆。", "兩曜各循環，皦皦臨四方。", "人道政如斯，願君勉其常。", "脂車策良馬，日暮道正長。", "徒僕審驅馳，前途畏榛荒。", "劣質苦難任，白雲懷故鄉。", "南山一舍隔，動若參與商。", "大舶漾中流，矯首空西望。", "昆弟真可人，行樂毋相忘。"]'),
('aa1d0b72-412c-46eb-a9fd-9127243d8280','嘉興道間二首  其一','黄榦','宋','宋诗','song-poetry','','[]','平生事幽貞，足跡不出門。',24,'全唐诗/poet.song.170000.json','["平生事幽貞，足跡不出門。", "歲晚迫饑寒，暫得媒妁言。"]'),
('a2796d03-f53b-486f-9c48-560be48276d1','嘉興道間二首  其二','黄榦','宋','宋诗','song-poetry','','[]','征途不寐輒終夕，故里無書今幾時。',32,'全唐诗/poet.song.170000.json','["征途不寐輒終夕，故里無書今幾時。", "離別因知雙鬢改，饑寒解使寸心悲。"]'),
('495fd6c0-0ee7-4191-9a67-a8359f7cdb71','謁陸宣公祠於嘉興府學門外二首  其一','黄榦','宋','宋诗','song-poetry','','[]','年來風俗軟如綿，再拜公祠氣凜然。',32,'全唐诗/poet.song.170000.json','["年來風俗軟如綿，再拜公祠氣凜然。", "莫是平生太忠鯁，只今猶斥學宮前。"]'),
('517c428f-1bbe-4629-ac1b-69bca8e64be9','謁陸宣公祠於嘉興府學門外二首  其二','黄榦','宋','宋诗','song-poetry','','[]','徘徊無處謁精廬，義膽忠肝一卷書。',32,'全唐诗/poet.song.170000.json','["徘徊無處謁精廬，義膽忠肝一卷書。", "昏主亂時公尚爾，清朝平世合何如。"]'),
('0f4eb04a-9bf0-48ea-9981-2f07e50bab42','石門','黄榦','宋','宋诗','song-poetry','','[]','吳越天下富，京畿遊俠鄉。',96,'全唐诗/poet.song.170000.json','["吳越天下富，京畿遊俠鄉。", "隴畝盡膏腴，第宅皆侯王。", "世言蘇湖熟，霑丐及四方。", "自我來石門，觸目何淒涼。", "清晨開務門，有酒誰復嘗。", "纍纍挈妻子，汲汲求糟糠。", "父老稱近年，十載嘗九荒。", "聚落成丘墟，少壯爭逃亡。"]'),
('76368955-0950-4de8-b72b-471066bfb273','訪高僉判所居','黄榦','宋','宋诗','song-poetry','','[]','遠樹分高下，平洲半有無。',48,'全唐诗/poet.song.170000.json','["遠樹分高下，平洲半有無。", "短亭低密竹，小艇隠寒蘆。", "轉浪魚深入，斜陽鴉亂呼。", "自慚貴公子，未老賦歸歟。"]'),
('a5111167-1948-4001-aa5d-1dbfa72798d4','甲子語溪閔雨四首  其一','黄榦','宋','宋诗','song-poetry','','[]','檣頭五兩摇空飛，船頭百丈牽何遲。',32,'全唐诗/poet.song.170000.json','["檣頭五兩摇空飛，船頭百丈牽何遲。", "數篙塘水清可涉，故鄉千里歸何時。"]'),
('2896912b-1993-4805-b796-206fe459dcf5','甲子語溪閔雨四首  其二','黄榦','宋','宋诗','song-poetry','','[]','塘中龍骨高數層，龜坼田中縱復橫。',32,'全唐诗/poet.song.170000.json','["塘中龍骨高數層，龜坼田中縱復橫。", "青裙箬笠倚車卧，但有空車無水聲。"]'),
('9b41a46b-d865-4d80-8780-611f19a1da5e','甲子語溪閔雨四首  其三','黄榦','宋','宋诗','song-poetry','','[]','牛女盈盈河漢傍，清風肅肅吹羅裳。',32,'全唐诗/poet.song.170000.json','["牛女盈盈河漢傍，清風肅肅吹羅裳。", "朱門達旦聽歌曲，莫遣濃陰蔽夜涼。"]'),
('578c5cc8-6b86-472e-9e80-680184c6dbb5','甲子語溪閔雨四首  其四','黄榦','宋','宋诗','song-poetry','','[]','老夫年來百不悲，夜聽羣兒聲吾伊。',32,'全唐诗/poet.song.170000.json','["老夫年來百不悲，夜聽羣兒聲吾伊。", "呼兒握手長太息，不見儂家數口饑。"]'),
('792ab306-959b-4820-8e2f-b3dba5e83f12','喜雨用前韻  其一','黄榦','宋','宋诗','song-poetry','','[]','莫愁塵土壓天飛，六月栽田未是遲。',32,'全唐诗/poet.song.170000.json','["莫愁塵土壓天飛，六月栽田未是遲。", "待得麥麻收拾後，通宵好雨定知時。"]'),
('8f424d03-df77-4285-85df-bd627e1678e0','喜雨用前韻  其二','黄榦','宋','宋诗','song-poetry','','[]','雲霓天外起層層，畢月相隨徹夜橫。',32,'全唐诗/poet.song.170000.json','["雲霓天外起層層，畢月相隨徹夜橫。", "費得天公能幾力，數州愁苦變歌聲。"]'),
('fbd734e3-dbe3-4984-8a9a-35d7942ef8c7','喜雨用前韻  其三','黄榦','宋','宋诗','song-poetry','','[]','睡覺歌聲古道傍，有人中夜攬衣裳。',32,'全唐诗/poet.song.170000.json','["睡覺歌聲古道傍，有人中夜攬衣裳。", "床頭斗酒聊自酌，不爲書窗一夜涼。"]'),
('3cf04b1f-63ff-4c69-bb18-5fca8562419d','喜雨用前韻  其四','黄榦','宋','宋诗','song-poetry','','[]','山中書生休浪悲，燮調自有臯與伊。',32,'全唐诗/poet.song.170000.json','["山中書生休浪悲，燮調自有臯與伊。", "清香一瓣來天竺，更把民饑作己饑。"]'),
('4311ec56-de33-4798-a3ce-56c92d55c1f4','又用前韻謝葉宰  其一','黄榦','宋','宋诗','song-poetry','','[]','誰推雙轂遶天飛，短髮蕭疎蚤是遲。',32,'全唐诗/poet.song.170000.json','["誰推雙轂遶天飛，短髮蕭疎蚤是遲。", "腸斷金錢門外月，曉天秋露稻花時。"]'),
('08d93851-ab1a-4ec4-b16f-00a9db47324a','又用前韻謝葉宰  其二','黄榦','宋','宋诗','song-poetry','','[]','明招古木葉千層，山自浮雲溪自橫。',32,'全唐诗/poet.song.170000.json','["明招古木葉千層，山自浮雲溪自橫。", "春樹鶑藏無覓處，遺編燈火屢吞聲。"]'),
('7624d7e9-7bad-40af-aa2e-a083f9b5aa93','又用前韻謝葉宰  其三','黄榦','宋','宋诗','song-poetry','','[]','歲晚投身糟甕傍，旋除野服著公裳。',32,'全唐诗/poet.song.170000.json','["歲晚投身糟甕傍，旋除野服著公裳。", "折腰可愧更無米，贏得虛堂一味涼。"]'),
('1f1a8115-840a-4b0b-a80d-c6bf93d53dd5','又用前韻謝葉宰  其四','黄榦','宋','宋诗','song-poetry','','[]','世事年來最可悲，開口不得洛與伊。',32,'全唐诗/poet.song.170000.json','["世事年來最可悲，開口不得洛與伊。", "兩君論交大左計，芋栗不足充人饑。"]'),
('12a7c714-5ef5-4206-93ec-3bf20e33e862','噫嘻示兒','黄榦','宋','宋诗','song-poetry','','[]','噫嘻!吾退不能爲高蹈之靖節，吾進不能爲玩世之東方。',121,'全唐诗/poet.song.170000.json','["噫嘻!吾退不能爲高蹈之靖節，吾進不能爲玩世之東方。", "腰折亦無米五斗，餓死安得粟一囊。", "徒令汝曹困齏鹽，對我面目青且黄。", "冬寒輕裘不得御，朝饑軟飯不得嘗。", "大兒知書故自忍，小兒叫怒來牽裳。", "老夫對此忽自悟，呼兒并集來我傍。", "人生窮通固有命，丈夫志氣當自强。"]'),
('002a5917-a813-4037-a8f4-19b2318e8123','送宋知府歸閬州','黄榦','宋','宋诗','song-poetry','','[]','丈夫不遇歸西州，天遣旱魃爲王留。',96,'全唐诗/poet.song.170000.json','["丈夫不遇歸西州，天遣旱魃爲王留。", "誰知冥鴻向蓬蓽，一使深鷁膠淺流。", "載書萬卷堪自樂，端坐十日吾何憂。", "使君高懷不可挽，飛廉驅雨扶君舟。", "君今捩柂清江頭，江漢滾滾來爲浮。", "張帆掛席日千里，巨魚豈戀尋常溝。"]'),
('7cb3f8aa-f41c-4377-874a-dc2443e43e6e','浙江舟行遇風','黄榦','宋','宋诗','song-poetry','','[]','扁舟泝浙江，日暖天氣清。',162,'全唐诗/poet.song.170000.json','["扁舟泝浙江，日暖天氣清。", "胥濤寂無聲。", "篙工掛席帆，涉險如履平。", "不謂時適然，自詫伎已精。", "中流捨維楫，醉卧日月橫。", "烟雲忽異色，亭午風浪生。", "兩涯忽黯淡，一葉隨欹傾。", "津人巧不施，反念西佛名。", "同舟已自訣，立葬東海鯨。", "雨聲忽自霽，霧暗忽復明。", "舉酒迭相賀，驕氣又已盈。", "同舟幸身安，氣塞莫敢爭。", "誰知翻覆手，頃刻分陰晴。", "既乏共濟力，拂衣起徒行。"]'),
('d3b7ba31-f6cb-4147-9fb3-4ff75d44f4a1','和江西王倉中秋賞月韻','黄榦','宋','宋诗','song-poetry','','[]','明晦從渠造物慳，好天佳月靜時看。',64,'全唐诗/poet.song.170000.json','["明晦從渠造物慳，好天佳月靜時看。", "一輪天外長明徹，萬象胸中自屈盤。", "星逐使來隨處見，霜侵臺迥逼人寒。", "休觀玉免頻頻擣，活國須公九轉丹。"]'),
('caadada5-b2df-47e2-b805-d09baf8c2c23','勉都幹權君','黄榦','宋','宋诗','song-poetry','','[]','長安城中豪俊林，錦韉玉勒馳駸駸。',192,'全唐诗/poet.song.170000.json','["長安城中豪俊林，錦韉玉勒馳駸駸。", "入門朱粉誇妙麗，出門青紫爭浮沈。", "東有問醫西問相，君獨燕坐鈎其深。", "冰眸一睨窮達判，刀劑不許寒暑侵。", "長安城外天陰陰，行人駐馬爲悲吟。", "高墳崔嵬葬白骨，安得不死腰黄金。", "世間萬事何足恃，禍福倚伏常相尋。", "渠儂自愚君自强，誰肯一笑忘華簪。", "蜀人賣卜嚴君平，垂簾閉肆窮古今。", "逢人但說忠與孝，自有達者能知音。", "察形察色君所解，直須洞燭賢愚心。", "屈伸壽夭亦命爾，公平正直神所欽。"]'),
('a8b8e25e-9ed0-48f8-94d2-58f9cbe5433c','送章元德司理罷官歸永嘉','黄榦','宋','宋诗','song-poetry','','[]','送君北門阪，遥望東甌路。',180,'全唐诗/poet.song.170000.json','["送君北門阪，遥望東甌路。", "峩峩白鶴嶺，渺渺飛鸞渡。", "上有虎豹嘷，下有蛟龍怒。", "車馬堅且良，維檝夙已具。", "褰裳涉其險，萬怪不足懼。", "世路劇羊腸，皦皦誠易汙。", "但能心無愧，窮達安所遇。", "毋爲婉孌者，暫蹶輒驚顧。", "生平麋鹿姿，處世每多忤。", "胡爲展良覿，握手便如故。", "高懷發鍼石，正論諧韶濩。", "情親復告別，欲語誰與晤。", "乾坤一逆旅，日月雙脫兔。", "寒儒守蓬蓽，白首困章句。", "期君以遠大，庶足慰遲暮。"]'),
('36269650-2929-40ff-abff-0f11078bf776','謝潘謙之二首  其一','黄榦','宋','宋诗','song-poetry','','[]','生平不作溫飽計，歲晚寧愁衣褐無。',32,'全唐诗/poet.song.170000.json','["生平不作溫飽計，歲晚寧愁衣褐無。", "一夜嬌兒啼徹曉，始知寒色已侵膚。"]'),
('bc49fdc3-5d3c-46c3-b11a-222dd0a172a1','謝潘謙之二首  其二','黄榦','宋','宋诗','song-poetry','','[]','綈袍戀戀故人情，寒谷瀟瀟春意生。',32,'全唐诗/poet.song.170000.json','["綈袍戀戀故人情，寒谷瀟瀟春意生。", "寂寞窮儒應易足，牀頭鼻息便雷鳴。"]'),
('fd8575e7-8c67-4521-936e-d03a5ac31c05','慶元己未冬至前二日訪林公度至栗山翌日同訪吳必大林季亨容之偕行愛其溪山池亭之勝爲之賦詩','黄榦','宋','宋诗','song-poetry','','[]','篝火下脩嶺，褰衣涉清川。',168,'全唐诗/poet.song.170000.json','["篝火下脩嶺，褰衣涉清川。", "夜投故人廬，洞壑藏真仙。", "一水遠縈紆，兩山對蜿蜒。", "但見烟雲深，不識車馬喧。", "主人敬客至，盃酒羅堂前。", "諸孫競勸酬，烹羊雜雞鮮。", "同來二三人，妙語爭春妍。", "此會良獨難，達旦不復眠。", "雞鳴秉燭遊，到君新池邊。", "中有讀書堂，藏書足精研。", "把筆記姓名，徘徊悵無緣。", "天明驅車去，去上層岡巔。", "回首三歎息，安得數畝田。", "結茅與君鄰，嘯傲終殘年。"]'),
('b8fcc4e0-3fd2-4657-9a33-8ddde3049b6f','會南禪遊鄒氏園和知丞韻','黄榦','宋','宋诗','song-poetry','','[]','盃酒聯翩臭味同，橫枝疎影費天工。',32,'全唐诗/poet.song.170000.json','["盃酒聯翩臭味同，橫枝疎影費天工。", "千林落木人烟絕，獨倚斜陽對晚風。"]'),
('46a2b55f-d49d-4f25-baa9-8bb6db7b3584','寄鄭維忠葉雲叟諸友','黄榦','宋','宋诗','song-poetry','','[]','村村簫鼓競龍舟，萸菊巖前倚晚秋。',32,'全唐诗/poet.song.170000.json','["村村簫鼓競龍舟，萸菊巖前倚晚秋。", "老懶焚香書一卷，淡烟疎竹月侵樓。"]'),
('d54275f8-7305-48c9-9d1d-0a687ef745f3','宿廬阜歸宗題正覺禪師','黄榦','宋','宋诗','song-poetry','','[]','稽首歸宗正覺師，長懷千里鬢如絲。',32,'全唐诗/poet.song.170000.json','["稽首歸宗正覺師，長懷千里鬢如絲。", "早知具眼番成闇，不作人間了事癡。"]'),
('5ad5f603-adca-47e4-9a9a-09a1baef8396','挽雲門鄭君','黄榦','宋','宋诗','song-poetry','','[]','結友雲門日，曾聞谷口翁。',48,'全唐诗/poet.song.170000.json','["結友雲門日，曾聞谷口翁。", "松肥三徑雨，鱸熟一絲風。", "行業鄉閭敬，詩書子姓同。", "論心獨餘恨，秋草對碑豐。"]'),
('be9a7325-ace9-4dfa-978c-c8920ac44ba8','挽潘孺人  其一','黄榦','宋','宋诗','song-poetry','','[]','聞說初年失偶時，回看囊篋鬢成絲。',64,'全唐诗/poet.song.170000.json','["聞說初年失偶時，回看囊篋鬢成絲。", "誰知舊室如新室，解撫前兒似後兒。", "南澗蘋生方得助，河陽花落不勝悲。", "高樓百尺今休上，望著佳城空淚垂。"]'),
('d9b1e7af-9d95-4c43-bb65-0f011810501c','挽潘孺人  其二','黄榦','宋','宋诗','song-poetry','','[]','紅雲照水春將暮，皓月盈盈院落深。',64,'全唐诗/poet.song.170000.json','["紅雲照水春將暮，皓月盈盈院落深。", "正是佳人行樂地，翻令公子獨傷心。", "床頭琴瑟空長在，眼底音容無處尋。", "寒食紙錢飛滿野，一聲薤露涕沾襟。"]'),
('b4fcd3e5-2e37-462b-8660-94625ffef6f1','挽新市張監酒三首  其一','黄榦','宋','宋诗','song-poetry','','[]','曲江人已矣，風采獨依然。',48,'全唐诗/poet.song.170000.json','["曲江人已矣，風采獨依然。", "薄宦何曾顯，英名到處傳。", "諸公交薦士，造物竟遺賢。", "窮達君應悟，怡神向九泉。"]'),
('d49efce8-4dbe-4627-9ce5-6ea64331977e','挽新市張監酒三首  其二','黄榦','宋','宋诗','song-poetry','','[]','捧檄來新市，逢人說舊官。',48,'全唐诗/poet.song.170000.json','["捧檄來新市，逢人說舊官。", "臘殘千醆熟，春到萬家歡。", "不見文移急，惟聞酒禁寬。", "摩挲石梁柱，俛仰歎才難。"]'),
('3aa26194-dfff-46f9-aacd-56d43b9a6c48','挽新市張監酒三首  其三','黄榦','宋','宋诗','song-poetry','','[]','淡薄心無累，行藏惠及人。',48,'全唐诗/poet.song.170000.json','["淡薄心無累，行藏惠及人。", "詩書長孫子，雍睦化比鄰。", "我亦塵中客，來司甕底春。", "從公得遺範，惆悵重書紳。"]'),
('fd3edf97-46c2-4344-a35b-41c4c748af15','代王維謹挽李察院二首  其一','黄榦','宋','宋诗','song-poetry','','[]','關洛蕭條南渡日，龜山往事屬龍津。',64,'全唐诗/poet.song.170000.json','["關洛蕭條南渡日，龜山往事屬龍津。", "過庭詩禮傳宗旨，蓋世功名付後人。", "風憲隻身中與外，清忠壯節晚如新。", "崇蘭香歇玉剛折，定與天皇作侍臣。"]'),
('a3358d21-632a-4bb9-a17f-d39a71a21a94','代王維謹挽李察院二首  其二','黄榦','宋','宋诗','song-poetry','','[]','牛角短歌頭半白，龍門峻級眼常青。',64,'全唐诗/poet.song.170000.json','["牛角短歌頭半白，龍門峻級眼常青。", "一官多是春風力，千里俄驚秋淚零。", "坐想德容今寂寞，夢回耳語尚丁寧。", "夜臺雖閉公長在，有子能存舊典刑。"]'),
('d7a647e0-f18d-4bc4-89d2-e10749fdd336','代曾魯仲挽蔣同叔母二首  其一','黄榦','宋','宋诗','song-poetry','','[]','釜竈朝晡百儉艱，巵匜滫瀡悅慈顔。',64,'全唐诗/poet.song.170000.json','["釜竈朝晡百儉艱，巵匜滫瀡悅慈顔。", "欲知婦順妻賢處，盡在姑啼夫哭間。", "庭下芝蘭方擢秀，堂前松檜未應慳。", "空餘馬鬣崔嵬在，及見春風衣錦還。"]'),
('bf511900-febd-4cba-9206-6d3a94465a36','代曾魯仲挽蔣同叔母二首  其二','黄榦','宋','宋诗','song-poetry','','[]','不樂何蕃歲一歸，歐陽越客飽京師。',64,'全唐诗/poet.song.170000.json','["不樂何蕃歲一歸，歐陽越客飽京師。", "腰間未許印如斗，堂上還驚鬢已絲。", "男子但知三釜計，人生合是百年期。", "他時此恨憑誰說，見著魚軒心轉悲。"]'),
('d691a794-07c8-4c1d-9654-bb8ea0b8e0d0','代季亨二首  其一','黄榦','宋','宋诗','song-poetry','','[]','枌榆接影一牛鳴，淑德相傳到後生。',64,'全唐诗/poet.song.170000.json','["枌榆接影一牛鳴，淑德相傳到後生。", "三世隻身長婉娩，兩兒雙淚遽縱橫。", "蘋蘩春澗情何切，機杼秋堂眼倍明。", "細讀古今賢婦傳，誰家騃女亦書名。"]'),
('e78c80b0-2bb6-4d6b-89a8-1424349d86ab','代季亨二首  其二','黄榦','宋','宋诗','song-poetry','','[]','慇懃慈母手中線，縫作行人身上衣。',64,'全唐诗/poet.song.170000.json','["慇懃慈母手中線，縫作行人身上衣。", "待換青衫朝日去，誰知白帽带星歸。", "別時早覺終天訣，底事能堪跬步違。", "一路顯親須努力，九原荒草恨依依。"]'),
('ece58fb4-35f7-4d70-ace1-027b2c9359b0','代良夫人二首  其一','黄榦','宋','宋诗','song-poetry','','[]','早歲爲儒讀國風，夫人高節有誰同。',64,'全唐诗/poet.song.170000.json','["早歲爲儒讀國風，夫人高節有誰同。", "至今桑梓傳家法，便說蘋蘩力婦功。", "閨內衾裯長自苦，堂前滫瀡得能豐。", "欲知淑德碑何在，只聽鄉人嘆息中。"]'),
('bf6d7cc2-d6f6-4e75-b14a-0b5d5a90a4f9','代良夫人二首  其二','黄榦','宋','宋诗','song-poetry','','[]','聞道夫人遣子時，丁寧捧檄是歸期。',64,'全唐诗/poet.song.170000.json','["聞道夫人遣子時，丁寧捧檄是歸期。", "青衫到手非難事，白髮驚心祗自悲。", "長翣忍聽蒿里句，短檠休唱蓼莪詩。", "九原精爽應長在，列戟松楸莫恨遲。"]'),
('8ca386f7-46fa-45f2-a71d-a4e567efd910','挽李尚書母太淑人  其一','黄榦','宋','宋诗','song-poetry','','[]','少壯聞忠教，生平閲險夷。',48,'全唐诗/poet.song.170000.json','["少壯聞忠教，生平閲險夷。", "篆烟長寂寞，騶從任驅馳。", "塵俗渾無染，湖山每自怡。", "儒冠慚佛學，列婦勝男兒。"]'),
('4883a450-74f2-4c10-94da-3ecb13401d2f','挽李尚書母太淑人  其二','黄榦','宋','宋诗','song-poetry','','[]','紫橐光先烈，青衫拾世科。',48,'全唐诗/poet.song.170000.json','["紫橐光先烈，青衫拾世科。", "家聲今益振，母訓昔應多。", "方聽焚舟誓，俄聞鼓缶歌。", "定非孫與祖，一戰一言和。"]'),
('57bcbe7c-2428-4d80-9c97-c3705e0a00e6','挽李尚書母太淑人  其三','黄榦','宋','宋诗','song-poetry','','[]','枌社傳家範，階庭著義方。',48,'全唐诗/poet.song.170000.json','["枌社傳家範，階庭著義方。", "能令鏘劍履，爭欲倚門牆。", "么麽真無用，提撕獨異常。", "登堂今已尖，收淚轉淋浪。"]'),
('a96da4ed-0352-409d-97ca-252b592c3110','和伯高弟夢宗氏子寄生舍下','陽景春','宋','宋诗','song-poetry','','[]','黑貂敝色嗟蘇郎，苦茶兩餠話難詳。',144,'全唐诗/poet.song.170000.json','["黑貂敝色嗟蘇郎，苦茶兩餠話難詳。", "老嫗糟糠未鼎肉，漫勞戲綵啼其傍。", "造物寄意知何許，慈竹生舍貽吉祥。", "晚年慰見萬事足，無乃宗子爲小陽。", "當時顧後悲不孝，今日兒女還成行。", "難弟二珠奇男子，已角既鹿未角麞。", "先人有後欲昌熾，繹思爲善寧無常。", "菊開佳色采盈手，酒浮蟻綠仍鵝黄。", "喜有詩書起門戶，佳興吹入秋風長。"]'),
('c7f12c7c-40b7-40dc-995e-9e7fca42a965','仲子枋試晬取墨','陽景春','宋','宋诗','song-poetry','','[]','俚俗兒周晬，羅陳試子材。',48,'全唐诗/poet.song.170000.json','["俚俗兒周晬，羅陳試子材。", "怡愉觀物色，揀擇取烟煤。", "志在文章富，毫揮錦繡開。", "弟兄心筆硯，予豈怨貧哉。"]'),
('8e3fabf8-eaee-4b79-ae32-96f3555a8adf','句  其一','陽景春','宋','宋诗','song-poetry','','[]','詩書有味嚼逾美，編簡無花開自香。',16,'全唐诗/poet.song.170000.json','["詩書有味嚼逾美，編簡無花開自香。"]'),
('5968a3f6-ba70-4bb8-a04e-54fe338edb24','句  其二','陽景春','宋','宋诗','song-poetry','','[]','五十三年墮鬢魂，一朝埋玉骨方溫。',16,'全唐诗/poet.song.170000.json','["五十三年墮鬢魂，一朝埋玉骨方溫。"]'),
('d62b284b-1f69-46f4-b8d4-58affd8902fc','夢宗氏子來兄舍寄生九月初七果生姪子','陽伯高','宋','宋诗','song-poetry','','[]','昔年曾夢宗家郎，受生所自言其詳。',160,'全唐诗/poet.song.170000.json','["昔年曾夢宗家郎，受生所自言其詳。", "髼鬆有髮重覆頂，夢裏恍然如在旁。", "大人占之兆惟吉，惟熊惟羆男之祥。", "今朝誕慶果如夢，始生三日逢重陽。", "啼聲已覺是英物，一門四子誠生光。", "小魚嬉戲已成隊，雛雁飛騰終作行。", "曉來搔首搜句喜，奮筆倉惶書弄麞。", "端由乃祖積德厚，詩禮有傳應異常。", "新醅喜醱蒲萄綠，開樽共對籬花黄。", "撳髯一笑共引滿，拜賀箕裘宗派長。"]'),
('ba43f142-2d05-41aa-98eb-5097c26b0831','題妙庭觀玉泉池','趙鎮','宋','宋诗','song-poetry','','[]','一脈泠泠絕點埃，方池幽洞自瀠洄。',64,'全唐诗/poet.song.170000.json','["一脈泠泠絕點埃，方池幽洞自瀠洄。", "源從白石雲邊出，流向青蓮座下迴。", "禹穴鱗游殘雪噴，祗園花墮暗香來。", "可人最是清秋夜，月白沙青寶鏡開。"]'),
('a07c4d3a-6cd2-4697-93c6-89e69fd8629a','臨安還遊金龍洞志感','趙鎮','宋','宋诗','song-poetry','','[]','幾年巖徑違清賞，今日雲蘿躡舊蹤。',64,'全唐诗/poet.song.170000.json','["幾年巖徑違清賞，今日雲蘿躡舊蹤。", "剎閣春陰宜燕雀，天池雷雨起蛟龍。", "崖流玉液空蓮座，風激篔簹送梵鐘。", "洞口不愁迷去路，樽前聊與話從容。"]'),
('71a4fc74-032b-4681-af34-669ef041d0c1','題妙庭觀','李浹','宋','宋诗','song-poetry','','[]','風馭雲車去幾年，空餘故迹鎖蒼烟。',32,'全唐诗/poet.song.170000.json','["風馭雲車去幾年，空餘故迹鎖蒼烟。", "古來信有神仙事，莫漫詩成謝自然。"]'),
('4235aab2-dbf9-41be-a966-6c6e0e540fd7','和晦庵齋居聞磬韵','鄭可學','宋','宋诗','song-poetry','','[]','纖月照幽林，秋氣一何爽。',48,'全唐诗/poet.song.170000.json','["纖月照幽林，秋氣一何爽。", "散步豁煩襟，曠然息羣想。", "忽聞玉磬裏，泠泠送清響。", "頓令塵慮空，頗覺道心長。"]'),
('5f9b2acd-0d34-44b3-90c0-2a3a7e20311c','送龍詞  其一','邵普','宋','宋诗','song-poetry','','[]','四山回環兮古龍湫，山木陰翳兮枝相樛。',36,'全唐诗/poet.song.170000.json','["四山回環兮古龍湫，山木陰翳兮枝相樛。", "轟雷掣電兮耀靈虬，膏澤霶霈兮歲有秋。"]'),
('3943b1ad-5942-407c-87dd-ff0a0e3175fa','送龍詞  其二','邵普','宋','宋诗','song-poetry','','[]','奠桂酒兮椒槳，雜肴蔬兮薦堂皇。',34,'全唐诗/poet.song.170000.json','["奠桂酒兮椒槳，雜肴蔬兮薦堂皇。", "願龍垂休兮時厥雨暘，豐年之報兮不敢忘。"]'),
('c51a7723-3bba-4ab3-8ae5-4c1795357d83','故侍讀黄公挽詩','權安節','宋','宋诗','song-poetry','','[]','西南人物早推先，入踐華途譽望全。',64,'全唐诗/poet.song.170000.json','["西南人物早推先，入踐華途譽望全。", "朱邸談經忠貫日，黄扉批敕力回天。", "敬王素學真無負，憂國沉疴竟莫痊。", "初政遽辜求助意，忍觀遺事照青編。"]'),
('16fd9a8d-325d-4b63-9cdc-d28e3e4138a5','獻沈詹事','潘矩','宋','宋诗','song-poetry','','[]','昔年單騎向筠州，覓得歌姬共遠游。',64,'全唐诗/poet.song.170000.json','["昔年單騎向筠州，覓得歌姬共遠游。", "去日正宜供夜直，歸來渾未識春愁。", "禪人尚有香囊愧，道士猶懷炭婦羞。", "鐵石心腸延壽藥，不風流處却風流。"]'),
('516ef0e4-c1d3-4819-8e36-1341bbaa9a29','深靜堂','李處端','宋','宋诗','song-poetry','','[]','渡水穿雲特地來，虛堂深靜絕塵埃。',64,'全唐诗/poet.song.170000.json','["渡水穿雲特地來，虛堂深靜絕塵埃。", "泉流舍下蒲萄色，山作人間翡翠堆。", "解籜娟娟新竹長，弄香細細雜花開。", "重惟勝餞難爲詠，况我初無錦繡才。"]'),
('ec61d7bc-290f-4e3c-859a-978ed01016f1','慶元三年以職事至零陵訪澹巖','俞徵','宋','宋诗','song-poetry','','[]','傳聞此地稀，來爲細搜奇。',84,'全唐诗/poet.song.170000.json','["傳聞此地稀，來爲細搜奇。", "眩眼珠泉滴，擡頭玉乳垂。", "虛明天廣大，重疊石參差。", "坐久衣襟潤，聲翻語笑隨。", "幽深多怪巧，高下複逶迤。", "歷覽仙君蹟，難酬太史詩。", "自然千古意，形詠愧蕪詞。"]'),
('5b47bb94-b5be-427b-9cdf-0a72481355fe','丹臺井','陳奕','宋','宋诗','song-poetry','','[]','東城有觀號丹臺，石甃淵然天所開。',32,'全唐诗/poet.song.170000.json','["東城有觀號丹臺，石甃淵然天所開。", "回客題詩今不見，空令屐齒印蒼苔。"]'),
('6010a44f-ce35-4abd-a1c6-8678662ace14','題集福院','徐柟','宋','宋诗','song-poetry','','[]','松谿竹塢密藏村，行盡杉陰始到門。',64,'全唐诗/poet.song.170000.json','["松谿竹塢密藏村，行盡杉陰始到門。", "一鳥不啼春有思，千山都綠燒無痕。", "自慚俗吏塵埃久，來伴禪僧語笑溫。", "瓶水鑪香三十載，閲人此地幾朝昏。"]'),
('97c67134-a9ce-45c0-bcd8-31cc1941cd25','刺陳賈','淳熙太學生','宋','宋诗','song-poetry','','[]','周公大聖獨遭謗，元晦真賢亦被譏。',32,'全唐诗/poet.song.170000.json','["周公大聖獨遭謗，元晦真賢亦被譏。", "堪歎古今兩陳賈，如何都把聖賢非。"]'),
('3295b803-ae4d-49c4-89a6-ce48c79954e6','淳熙壬寅沿檄游洞天','馮鋼','宋','宋诗','song-poetry','','[]','洞府深沈別有天，翬飛樓閣聳晴烟。',64,'全唐诗/poet.song.170000.json','["洞府深沈別有天，翬飛樓閣聳晴烟。", "詩傳玉局驚凡目，丹就金爐記昔年。", "翠湧千波橫絕壁，風吹萬籟入飛泉。", "他時待我功成後，卜室青山絕世緣。"]'),
('e6d9b287-42f8-4669-ae97-66b4cdb056f8','紹熙庚戌中秋後三日拜張于湖墓','操某','宋','宋诗','song-poetry','','[]','古冢誰來香一瓣，斷蓬衰草自斜陽。',32,'全唐诗/poet.song.170000.json','["古冢誰來香一瓣，斷蓬衰草自斜陽。", "至今唯有文章骨，埋入幽泉土也香。"]'),
('bbe0d4b0-fb51-47ce-8fd5-1f18a4017ffa','紹熙庚戌中秋後三日拜張于湖墓','董道輔','宋','宋诗','song-poetry','','[]','曉出白下門，瘦馬踏秋色。',120,'全唐诗/poet.song.170000.json','["曉出白下門，瘦馬踏秋色。", "鍾山度蒼翠，慰我遠游客。", "暮投清果寺，花草獻幽寂。", "長廊靜無人，落日照西壁。", "平生張于湖，萬里去一息。", "翩然九州外，汗漫跨鯨脊。", "乾坤能幾時，安用較顔跖。", "文章失津梁，所念斯道厄。", "夜闌耿不寐，搔首聽蕭瑟。", "懷人感西風，翁仲守孤柏。"]'),
('45d3d9dd-f0ba-4b60-a780-d3665430c1a2','褒禪山有于湖所題寶塔二字','李繁昌','宋','宋诗','song-poetry','','[]','路入亂雲堆，僧房四面開。',48,'全唐诗/poet.song.170000.json','["路入亂雲堆，僧房四面開。", "龜泉半泥滓，龍洞已塵埃。", "潄竹渾忘醉，穿花浪費才。", "何人題寶塔，千載仰崔嵬。"]'),
('b98c5659-64ca-4e5a-b2b1-4271c254ba7d','篔簹萬箇黄雀每棲息其上一昔風雨颯至忽聞有殺聲呼童視之乃鼩嚙也故爲之賦黄頭雀','李自中','宋','宋诗','song-poetry','','[]','黄頭雀，觜交交，尾倬倬，突然散去雲路邈。',151,'全唐诗/poet.song.170000.json','["黄頭雀，觜交交，尾倬倬，突然散去雲路邈。", "東村四面禾黍稠，欲下未下驚呼儔。", "牛羊上山鷄犬睡，翩躚蹙步來相求。", "日斜深塹有羅網，投宿青冥依篠蕩。", "沙鳴羊角轉崢嶸，蹴踏虬枝猶倔强。", "誰知簷下息爾軀，夜半瀝血逢精鼩。", "唇焦舌爛救不得，一縷性命才須臾。", "君不見螳螂捕蟬上高樹，企足昂頭忘反顧。", "人生吞噬更可憐，臘月未窮誰悔悟。"]'),
('0dda7c07-d5e3-48af-a6cd-a65ec2c8cb5a','初夏旅况','李自中','宋','宋诗','song-poetry','','[]','南山北山雨濛濛，鎖斷翡翠千萬重。',96,'全唐诗/poet.song.170000.json','["南山北山雨濛濛，鎖斷翡翠千萬重。", "茅簷剝啄鳥未散，練带野水來相衝。", "土階莎草如箭鏃，冷透篔簹清入骨。", "雷公挾斧渡長河，拋擲牟尼三百斛。", "一身蒲柳寄天涯，白雲何處栽胡麻。", "江湖夏潦魚鱉亂，錦袍夜月乘仙槎。"]'),
('c729b2a9-7c78-4c81-be2c-ca3f2e1f5854','麻姑山作','李自中','宋','宋诗','song-poetry','','[]','小小茅簷下，清吟對此君。',48,'全唐诗/poet.song.170000.json','["小小茅簷下，清吟對此君。", "溪深春漲雨，山闊夜藏雲。", "地濕松花冷，天晴樹色分。", "敲門尋道士，鷄犬隔籬聞。"]'),
('3ece6345-42e3-4a9e-baed-d796cd6a1460','送曾景建道州聽讀','李自中','宋','宋诗','song-poetry','','[]','晚節傷弓未足憐，江湖因此累諸賢。',64,'全唐诗/poet.song.170000.json','["晚節傷弓未足憐，江湖因此累諸賢。", "名標宇宙千年在，事屬朝廷萬口傳。", "湘水有情空引些，舂陵無事早歸田。", "多年浪說飛昇讖，不擬如今尚悄然。"]'),
('1c0da437-3d4f-454c-998c-12227d2fab03','題南康縣山寺','李自中','宋','宋诗','song-poetry','','[]','絕無常住只隨緣，石榻焚香向佛前。',64,'全唐诗/poet.song.170000.json','["絕無常住只隨緣，石榻焚香向佛前。", "風折碧梧能幾日，鶴巢白塔已多年。", "無人去剗階邊草，有客來探井底泉。", "休笑空門長寂寂，近時地上也流錢。"]'),
('616a7729-529a-4393-8755-29531673d768','南昌樓贈符子威','李自中','宋','宋诗','song-poetry','','[]','占得南樓第一凉，焚香終日話蒼茫。',32,'全唐诗/poet.song.170000.json','["占得南樓第一凉，焚香終日話蒼茫。", "客來酌酒烹茶外，雜採山花供藥王。"]'),
('fdfde974-dcd3-4b6f-9674-d41909fb2ec3','春曉','李自中','宋','宋诗','song-poetry','','[]','門瞰青山侵草開，苦吟吟上最高臺。',32,'全唐诗/poet.song.170000.json','["門瞰青山侵草開，苦吟吟上最高臺。", "春風誰遣鄰家去，成陣落化吹過來。"]'),
('b8a3332d-67b8-4113-997c-b3e029320fe8','代宴費大參樂語','王子俊','宋','宋诗','song-poetry','','[]','相君曩歲轉洪鈞，手散陽和處處勻。',64,'全唐诗/poet.song.170000.json','["相君曩歲轉洪鈞，手散陽和處處勻。", "衮服肯迂今日駕，錦城便勝去年春。", "珍臺多暇何妨醉，左席猶虛正要人。", "飲罷天邊有消息，催歸一騎走紅塵。"]'),
('aebeffb1-7ffd-4fd0-ae42-d68a10f5415e','代吉席宴都運煥章校書知府親家致語','王子俊','宋','宋诗','song-poetry','','[]','天喚風雷落詔黄，身披雲錦護天章。',64,'全唐诗/poet.song.170000.json','["天喚風雷落詔黄，身披雲錦護天章。", "日隨漢使旌旗暖，路入韓城草木香。", "即上星辰扶北極，先持衣鉢付東廂。", "不知今夕端何夕，且向梅花頓舉觴。"]'),
('a4097f77-0e40-44b8-8c69-a8ad44d29903','代漕使宴賀帥平蠻轉官樂語','王子俊','宋','宋诗','song-poetry','','[]','紫橐仙人雲錦裳，碧油幢下受降羌。',64,'全唐诗/poet.song.170000.json','["紫橐仙人雲錦裳，碧油幢下受降羌。", "三邊外掃烟塵靜，一札中含雨露香。", "天上即歸扶日轂，樽前莫惜醉霞觴。", "主賓情分今如許，飲罷相携入帝鄉。"]'),
('e38fceb3-9019-43f0-94a6-39030e3e2b6c','代趙漕使進秩酢帥燕會樂語','王子俊','宋','宋诗','song-poetry','','[]','星軺夜落錦江邊，萬里來依刺史天。',64,'全唐诗/poet.song.170000.json','["星軺夜落錦江邊，萬里來依刺史天。", "纔了銓衡三考績，便勤督府一金筵。", "綠尊敬酢青田酒，翠袖爭扶紫橐仙。", "飲罷嘉賓歸底處，三槐陰裏望貂蟬。"]'),
('0a7c41bd-c111-411f-a8db-26c3c571d55b','總使生日樂語','王子俊','宋','宋诗','song-poetry','','[]','丹青步武是家傳，夜泛靈槎下九天。',64,'全唐诗/poet.song.170000.json','["丹青步武是家傳，夜泛靈槎下九天。", "纔看收駒霜滿節，旋觀董餉地流錢。", "補天有譜行歸輔，閲世無疆不計年。", "飲罷鋒車趣東去，座中舐鼎亦俱仙。"]'),
('2f2f14f8-6dd1-4743-b942-4943b49d7b24','淳熙內禪頌','王子俊','宋','宋诗','song-poetry','','[]','太初冥冥，孰究孰營。',247,'全唐诗/poet.song.170000.json','["太初冥冥，孰究孰營。", "羲儀圖之，靡麗於成。", "有聖惟勛，疏之瀹之。", "斧其不條，而荒度之。", "匪世不阜，匪穹不佑。", "可燕可守，而勛以不有。", "乃遜於華，與世爲公。", "何以告之，曰允執其中。", "華述厥志，亦以命文命。", "率克念厥紹，以共闡厥盛。", "皇皇惟天，而勛則之。", "絕德與功，紹者克之。", "我瞻我稽，閲世惟千。", "泯泯棼棼，曾莫闖厥藩。", "天將開之，必固培之。", "厥培以豐，古尚克回之。", "豈惟回之，視培淺深。", "軼而躪之，視我斯今。", "粵歲己酉，二月壬戌。", "天仗宵嚴，彤廷曉蹕。", "穆穆壽皇，如天斯臨。", "羣后在位，奉承玉音。", "曰予一人，實倦於勤。", "退處北宮，以篤於親。"]'),
('5c47ab24-3f51-414f-97d2-67782e30bcab','和徐思叔題貧樂圖','王子俊','宋','宋诗','song-poetry','','[]','大兒阻饑頗廢書，小兒忍寒粟生膚。',32,'全唐诗/poet.song.170000.json','["大兒阻饑頗廢書，小兒忍寒粟生膚。", "婦縱有褌無一襦，不敢緣此相庸奴。"]'),
('408c2710-6138-479c-8253-ccb2eaba2280','賀李憲校書生子','王子俊','宋','宋诗','song-poetry','','[]','乃翁學海深無底，材如莫耶淬清水。',160,'全唐诗/poet.song.170000.json','["乃翁學海深無底，材如莫耶淬清水。", "天教乞與玉麒麟，拍手歡呼爲公喜。", "雪峰千丈玉嶙峋，玻璃之江浸秋旻。", "可憐秀氣無著處，都爲此子融精神。", "昨夜使星光耿耿，旁邊却有庚星影。", "起來瑞靄迷綺筵，玉果犀錢試湯餠。", "乃翁著書身爲臞，私稿自有一石渠。", "行看一日誦千紙，不必更讀他人書。", "乃翁勳名已如許，如何免得洪鈞府。", "請更撰成經國譜，付與郎君踵前武。"]'),
('ffcdcb20-a48c-4a38-88a3-e12af84afa08','賀彥澤新得子','王子俊','宋','宋诗','song-poetry','','[]','君不見白居易，五十八歲方得嗣。',126,'全唐诗/poet.song.170000.json','["君不見白居易，五十八歲方得嗣。", "當時立名曰阿崔，香綳綉襦胎髮膩。", "又不見元微之，五十八歲方生兒。", "當時立名曰道保，可望成家得力時。", "西鄰有親曰彥澤，天與明珠堪愛惜。", "今年年方四十三，甲庚少似唐元白。", "葛仙溪前燕子樓，燕子未老人風流。", "一年一度作湯餠，但願年年逢麥秋。"]'),
('26348b60-463f-4ab0-b7e5-cf49e24c4a7c','長風紙平渡','王子俊','宋','宋诗','song-poetry','','[]','剪紙鋪平江，雁飛翬字雙。',24,'全唐诗/poet.song.170000.json','["剪紙鋪平江，雁飛翬字雙。", "秋山青隔岸，誰啟讀書窗。"]'),
('302b68bd-7bcb-42b2-9665-62e79aa9149b','句  其一','王子俊','宋','宋诗','song-poetry','','[]','沙鷗背人去。',6,'全唐诗/poet.song.170000.json','["沙鷗背人去。"]'),
('fcfd4b43-0fce-4e30-8e95-4fecc5e748be','句  其二','王子俊','宋','宋诗','song-poetry','','[]','數椽月屋愛巖阿。',8,'全唐诗/poet.song.170000.json','["數椽月屋愛巖阿。"]'),
('f4c1fc15-07d1-46fa-9ade-961e53c5ea3c','句  其三','王子俊','宋','宋诗','song-poetry','','[]','雲林好處欲留脚。',8,'全唐诗/poet.song.170000.json','["雲林好處欲留脚。"]'),
('fa6c4f7d-44f3-482f-b644-57066c0c3853','句  其四','王子俊','宋','宋诗','song-poetry','','[]','安排流水落巖前。',8,'全唐诗/poet.song.170000.json','["安排流水落巖前。"]'),
('6b76924c-1c46-4f88-ac59-5546ed10354f','句  其五','王子俊','宋','宋诗','song-poetry','','[]','病客欲眠渾不寐。',8,'全唐诗/poet.song.170000.json','["病客欲眠渾不寐。"]'),
('654db53d-3fd3-4b8f-90d2-4daf688a5dc5','句  其六','王子俊','宋','宋诗','song-poetry','','[]','再見山城石井邊。',8,'全唐诗/poet.song.170000.json','["再見山城石井邊。"]'),
('b1cf5b33-5c28-47ac-a94d-ca4338ea1dc9','句  其七','王子俊','宋','宋诗','song-poetry','','[]','並舍者誰清可喜，各家之竹翠相交。',16,'全唐诗/poet.song.170000.json','["並舍者誰清可喜，各家之竹翠相交。"]'),
('a80994f2-9589-4810-8ffa-d6468afbe8bc','句  其八','王子俊','宋','宋诗','song-poetry','','[]','歸去來兮覺今是，不知我者謂何求。',16,'全唐诗/poet.song.170000.json','["歸去來兮覺今是，不知我者謂何求。"]'),
('f4a23895-d68a-4e7e-999f-dbb520484018','壬寅仲秋二十有五日哭東萊先生之墓  其一','徐暄','宋','宋诗','song-poetry','','[]','缺月疎星夜己闌，風凄露重逼人寒。',32,'全唐诗/poet.song.170000.json','["缺月疎星夜己闌，風凄露重逼人寒。", "郵亭破曉經行處，不似今朝酷鼻酸。"]'),
('25c297c6-653b-4fc1-b2f6-33c4b42f115f','壬寅仲秋二十有五日哭東萊先生之墓  其二','徐暄','宋','宋诗','song-poetry','','[]','庚子秋中憶請違，先生溫語扣還期。',32,'全唐诗/poet.song.170000.json','["庚子秋中憶請違，先生溫語扣還期。", "去年匍匐雙溪路，迨似當年失母時。"]'),
('5f057c90-dc7f-4241-a323-23e86cec1a34','壬寅仲秋二十有五日哭東萊先生之墓  其三','徐暄','宋','宋诗','song-poetry','','[]','先生墓木已成陰，霽月光風何處尋。',32,'全唐诗/poet.song.170000.json','["先生墓木已成陰，霽月光風何處尋。", "只有遺言常烱烱，誓將白首契初心。"]'),
('c8993d63-12bb-4c44-8706-1f8a0172b085','壬寅仲秋二十有五日哭東萊先生之墓  其四','徐暄','宋','宋诗','song-poetry','','[]','四海瞻依一偉人，丘封嶪嶪木森森。',32,'全唐诗/poet.song.170000.json','["四海瞻依一偉人，丘封嶪嶪木森森。", "仰天慟哭悲風起，舉世中和孰嗣音。"]'),
('6513e296-d72c-4cc5-9a4c-308c3f5af8ea','陸象山先生墓','黄矩','宋','宋诗','song-poetry','','[]','西風匹馬駐郵亭，茅屋鷄鳴尚未醒。',64,'全唐诗/poet.song.170000.json','["西風匹馬駐郵亭，茅屋鷄鳴尚未醒。", "野寺秋聲三徑竹，石橋雲氣一潭星。", "寒欺短褐霜華白，水落平田野蔓青。", "師友家傳今寂寞，欲移文字問山靈。"]'),
('93f266ec-7607-43cb-b7c5-718f844c0789','獻韓平原生日','開禧朝士','宋','宋诗','song-poetry','','[]','本是神仙服日華，而今癯瘁爲王家。',32,'全唐诗/poet.song.170000.json','["本是神仙服日華，而今癯瘁爲王家。", "槐龍影轉朝方退，閒却南園一院花。"]'),
('2e9ea475-5ff8-4c34-9ad9-cc6d0a5dd998','題客邸','宗室某','宋','宋诗','song-poetry','','[]','蹇衛衝風怯曉寒，也隨舉子到長安。',32,'全唐诗/poet.song.170000.json','["蹇衛衝風怯曉寒，也隨舉子到長安。", "路人莫作親王看，姓趙如今不似韓。"]'),
('89eb0741-355f-4ad3-b487-7f35fb7fd056','金陵','曾極','宋','宋诗','song-poetry','','[]','鑿地破除函谷帝，埋金厭勝郢中王。',32,'全唐诗/poet.song.170000.json','["鑿地破除函谷帝，埋金厭勝郢中王。", "興亡總不關君事，五百年前枉斷腸。"]'),
('92744a52-cd51-4ccf-a036-c3a8942264f8','攝山','曾極','宋','宋诗','song-poetry','','[]','一丈唐碑今露立，十尋梵塔已低摧。',32,'全唐诗/poet.song.170000.json','["一丈唐碑今露立，十尋梵塔已低摧。", "層層石佛雲閒出，坐閲齊梁成劫灰。"]'),
('25889a81-4b72-4182-b4f5-f32c5f0ac30b','方山','曾極','宋','宋诗','song-poetry','','[]','人間底事有方壺，劍截青摇界碧虛。',32,'全唐诗/poet.song.170000.json','["人間底事有方壺，劍截青摇界碧虛。", "試上殊庭瞻醉葛，仙雲垂带護儲胥。"]'),
('2940b4a4-9f01-409c-bb51-fb17a545a928','覆舟山','曾極','宋','宋诗','song-poetry','','[]','六代興亡貉一丘，繁華夢逐水東流。',32,'全唐诗/poet.song.170000.json','["六代興亡貉一丘，繁華夢逐水東流。", "操蛇神向山前笑，三百年前幾度舟。"]'),
