('d443f8a6-7ae8-4f7b-94b3-f36baac841f5','文孝廟','曾極','宋','宋诗','song-poetry','','[]','德隠前星民已和，山隈水曲廟何多。',32,'全唐诗/poet.song.170000.json','["德隠前星民已和，山隈水曲廟何多。", "皇孫不得承天統，猶使而翁恨蠟鵝。"]'),
('e915ea7a-e96a-4e8f-9984-85ebac54b7cf','謝玄廟','曾極','宋','宋诗','song-poetry','','[]','兒輩能軍國未危，更令朱序助聲威。',32,'全唐诗/poet.song.170000.json','["兒輩能軍國未危，更令朱序助聲威。", "秦人若也全師集，雲母車盛晉鼎歸。"]'),
('3199b531-fa80-4e8e-a869-b456cea4a1cc','蔣帝廟','曾極','宋','宋诗','song-poetry','','[]','白馬千年繫廟門，爐烟浮動衮龍昏。',32,'全唐诗/poet.song.170000.json','["白馬千年繫廟門，爐烟浮動衮龍昏。", "闔棺謾說榮枯定，青骨猶當履至尊。"]'),
('1c883094-cdda-4a41-816a-c0d27d6116db','吳大帝廟','曾極','宋','宋诗','song-poetry','','[]','曾將一劍定全吳，斗大祠庭泣楚巫。',32,'全唐诗/poet.song.170000.json','["曾將一劍定全吳，斗大祠庭泣楚巫。", "故國神遊應撫掌，蘆花楓葉幾年無。"]'),
('c7d3b344-85bf-4668-ad0a-b96516a22209','晉元帝廟','曾極','宋','宋诗','song-poetry','','[]','茅茨綿蕝寄江東，陵廟回看渫血紅。',32,'全唐诗/poet.song.170000.json','["茅茨綿蕝寄江東，陵廟回看渫血紅。", "右衽危冠纔自保，未能無責敢言功。"]'),
('3b5a8454-36f6-4889-91ed-b2b686e80045','中主像','曾極','宋','宋诗','song-poetry','','[]','乘時草竊豈無人，三主相傳事有因。',32,'全唐诗/poet.song.170000.json','["乘時草竊豈無人，三主相傳事有因。", "畢竟老天憐一念，據敖爲粥活饑民。"]'),
('5631e0f9-1a47-4556-b328-50abebfe75f1','謝公像','曾極','宋','宋诗','song-poetry','','[]','失喜向來因折屐，含悲今日爲聞箏。',32,'全唐诗/poet.song.170000.json','["失喜向來因折屐，含悲今日爲聞箏。", "人間悲喜何時了，携伎東山載酒行。"]'),
('7e7ee8dd-2137-4533-a480-5355d5d0384a','大茅君像','曾極','宋','宋诗','song-poetry','','[]','面如赬玉碧矑寒，散髮垂腰槲葉乾。',32,'全唐诗/poet.song.170000.json','["面如赬玉碧矑寒，散髮垂腰槲葉乾。", "不向大茅峰頂見，時人多作伏羲看。"]'),
('d508ebcf-508e-42a0-9f1b-3293b22a029a','吳大帝陵','曾極','宋','宋诗','song-poetry','','[]','老瞞虎裂橫中州，何物生兒作仲謀。',32,'全唐诗/poet.song.170000.json','["老瞞虎裂橫中州，何物生兒作仲謀。", "四十帝中功第一，壞陵無主使人愁。"]'),
('7a283c45-745c-4f89-a88a-e709fc6b9f60','荆公墓','曾極','宋','宋诗','song-poetry','','[]','誤把清標犯世紛，平生忠業自超羣。',32,'全唐诗/poet.song.170000.json','["誤把清標犯世紛，平生忠業自超羣。", "如何今代麒麟閣，只道詩名合策勳。"]');
